-- Enable required extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS vector;

-- Verify
DO $$
BEGIN
  RAISE NOTICE 'Extensions installed: uuid-ossp, pgcrypto, vector';
END $$;

import { drizzle } from 'drizzle-orm/postgres-js';
import postgres from 'postgres';
import { z } from 'zod';
import * as schema from './schema';

// Environment variable validation with Zod
const envSchema = z.object({
  DATABASE_URL: z.string().url(),
  DB_MAX_CONNECTIONS: z.coerce.number().default(10),
});

const env = envSchema.parse(process.env);

// Connection pool with proper config
const queryClient = postgres(env.DATABASE_URL, {
  max: env.DB_MAX_CONNECTIONS,
});

export const db = drizzle(queryClient, { schema });

// Health check function
export async function checkDbHealth(): Promise<boolean> {
  try {
    await queryClient`SELECT 1`;
    return true;
  } catch (error) {
    console.error('Database health check failed:', error);
    return false;
  }
}

import { eq } from 'drizzle-orm';
import { db } from './client';
import { sessions, users } from './schema';

export interface SessionUserContext {
  sessionId: string;
  userId: string;
  expiresAt: Date;
}

export async function getSessionUserContext(
  sessionId: string | null | undefined,
): Promise<SessionUserContext | null> {
  if (!sessionId) return null;

  const session = await db.query.sessions.findFirst({
    where: eq(sessions.id, sessionId),
  });

  if (!session || session.expiresAt.getTime() <= Date.now()) {
    return null;
  }

  const user = await db.query.users.findFirst({
    where: eq(users.id, session.userId),
  });

  if (!user) return null;

  return {
    sessionId: session.id,
    userId: user.id,
    expiresAt: session.expiresAt,
  };
}

export async function validateSessionUserId(
  sessionId: string | null | undefined,
): Promise<string | null> {
  const context = await getSessionUserContext(sessionId);
  return context?.userId ?? null;
}

export async function verifyUserExists(userId: string | null | undefined): Promise<string | null> {
  if (!userId) return null;

  const user = await db.query.users.findFirst({
    where: eq(users.id, userId),
  });

  return user?.id ?? null;
}

import { timingSafeEqual } from 'node:crypto';
import { validateSessionUserId, verifyUserExists } from './session';

/**
 * Minimal shape every Fastify request already exposes. We do not depend on
 * `fastify` here so this module stays usable from non-route contexts (tests,
 * websocket auth, BullMQ workers, ...).
 */
export interface AuthRequestLike {
  headers: Record<string, string | string[] | undefined>;
  cookies: { sessionId?: string };
}

export interface ResolveAuthOptions {
  /**
   * Optional shared secret expected on the `Authorization: Bearer <token>`
   * header for service-to-service calls. When unset, the internal-token path
   * is disabled and only the cookie session is honored.
   */
  internalServiceToken?: string;
}

function readHeader(
  headers: Record<string, string | string[] | undefined>,
  name: string,
): string | undefined {
  const value = headers[name] ?? headers[name.toLowerCase()];
  if (Array.isArray(value)) return value[0];
  return value;
}

/**
 * Resolve the acting user id for an inbound request, in this priority:
 *
 * 1. `Authorization: Bearer <INTERNAL_SERVICE_TOKEN>` + `X-User-Id: <uuid>`
 *    — internal service-to-service path. The user id is verified against
 *    the users table to defend against forged headers.
 * 2. `Cookie: sessionId=<id>` — the standard browser session path. The
 *    session must exist and not be expired.
 *
 * Returns `null` when no path authenticates the request. Routes should
 * respond with `401` on `null`.
 */
export async function resolveAuthenticatedUserId(
  request: AuthRequestLike,
  options: ResolveAuthOptions = {},
): Promise<string | null> {
  const internalToken = options.internalServiceToken;
  if (internalToken) {
    const auth = readHeader(request.headers, 'authorization');
    if (typeof auth === 'string' && auth.startsWith('Bearer ')) {
      const token = auth.slice('Bearer '.length).trim();
      if (token && constantTimeEquals(token, internalToken)) {
        const headerUserId = readHeader(request.headers, 'x-user-id');
        if (typeof headerUserId === 'string' && headerUserId.length > 0) {
          return verifyUserExists(headerUserId);
        }
      }
    }
  }

  const sessionId = request.cookies?.sessionId;
  if (!sessionId) return null;
  return validateSessionUserId(sessionId);
}

/**
 * Constant-time string comparison to prevent timing-oracle attacks against
 * the internal service token. Strings of differing length are compared
 * against a fixed-length buffer so the early-exit path does not leak length.
 */
function constantTimeEquals(a: string, b: string): boolean {
  const aBuf = Buffer.from(a, 'utf8');
  const bBuf = Buffer.from(b, 'utf8');
  if (aBuf.length !== bBuf.length) {
    // Still perform a comparison of equal-size buffers so the timing path
    // does not branch on length alone.
    timingSafeEqual(aBuf, aBuf);
    return false;
  }
  return timingSafeEqual(aBuf, bBuf);
}

import { defineConfig } from 'drizzle-kit';
import { z } from 'zod';

const envSchema = z.object({
  DATABASE_URL: z.string().url(),
});

const env = envSchema.parse(process.env);

export default defineConfig({
  schema: './src/schema/*',
  out: './src/migrations',
  dialect: 'postgresql',
  dbCredentials: {
    url: env.DATABASE_URL,
  },
  verbose: true,
  strict: true,
});

import { pgTable, timestamp, uuid, varchar } from 'drizzle-orm/pg-core';

export const users = pgTable('users', {
  id: uuid('id').primaryKey().defaultRandom(),
  email: varchar('email', { length: 255 }).notNull().unique(),
  passwordHash: varchar('password_hash', { length: 255 }), // Nullable for OAuth-only users
  name: varchar('name', { length: 255 }),
  createdAt: timestamp('created_at').defaultNow().notNull(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
});

import { pgTable, timestamp, varchar, uuid } from 'drizzle-orm/pg-core';
import { users } from './users';

export const sessions = pgTable('sessions', {
  id: varchar('id', { length: 255 }).primaryKey(), // Usually a secure random string (session token)
  userId: uuid('user_id').notNull().references(() => users.id, { onDelete: 'cascade' }),
  expiresAt: timestamp('expires_at').notNull(),
  createdAt: timestamp('created_at').defaultNow().notNull(),
});

import { pgTable, timestamp, uuid, varchar, primaryKey, text } from 'drizzle-orm/pg-core';
import { users } from './users';

export const oauthAccounts = pgTable('oauth_accounts', {
  providerId: varchar('provider_id', { length: 255 }).notNull(),
  providerUserId: varchar('provider_user_id', { length: 255 }).notNull(),
  userId: uuid('user_id').notNull().references(() => users.id, { onDelete: 'cascade' }),
  accessToken: text('access_token'),
  refreshToken: text('refresh_token'),
  createdAt: timestamp('created_at').defaultNow().notNull(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
}, (table) => ({
  pk: primaryKey({ columns: [table.providerId, table.providerUserId] }),
}));

import {
  pgTable,
  timestamp,
  uuid,
  varchar,
  text,
  jsonb,
  boolean,
  index,
} from 'drizzle-orm/pg-core';
import { users } from './users';

/**
 * Encrypted credentials for AI providers (BYOK) and integrations.
 * `encryptedKey` is AES-256-GCM ciphertext; `iv` and `authTag` stored separately.
 * Plaintext is never persisted, never logged, never returned to client.
 */
export const providerCredentials = pgTable(
  'provider_credentials',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    provider: varchar('provider', { length: 32 }).notNull(), // openai|anthropic|google|mock
    label: varchar('label', { length: 80 }),
    encryptedKey: text('encrypted_key').notNull(), // base64
    iv: varchar('iv', { length: 64 }).notNull(), // base64
    authTag: varchar('auth_tag', { length: 64 }).notNull(), // base64
    keyVersion: varchar('key_version', { length: 16 }).default('v1').notNull(),
    lastUsedAt: timestamp('last_used_at'),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    revokedAt: timestamp('revoked_at'),
    metadata: jsonb('metadata').$type<Record<string, unknown>>(),
  },
  (t) => ({
    userIdx: index('provider_credentials_user_idx').on(t.userId),
    activeIdx: index('provider_credentials_active_idx').on(t.userId, t.provider, t.revokedAt),
  }),
);

export const userPreferences = pgTable('user_preferences', {
  userId: uuid('user_id')
    .primaryKey()
    .references(() => users.id, { onDelete: 'cascade' }),
  defaultProvider: varchar('default_provider', { length: 32 }),
  defaultModel: varchar('default_model', { length: 120 }),
  theme: varchar('theme', { length: 16 }).default('system').notNull(),
  terminalRiskLevel: varchar('terminal_risk_level', { length: 16 }).default('normal').notNull(),
  bio: text('bio'),
  rules: text('rules'), // user "rules" injected into system prompt
  notificationPrefs: jsonb('notification_prefs').$type<{
    inApp?: boolean;
    emailMock?: boolean;
    webhookUrl?: string | null;
  }>(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
});

export const personas = pgTable(
  'personas',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    slug: varchar('slug', { length: 80 }).notNull(),
    name: varchar('name', { length: 120 }).notNull(),
    systemPrompt: text('system_prompt').notNull(),
    icon: varchar('icon', { length: 80 }),
    isDefault: boolean('is_default').default(false).notNull(),
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),
  },
  (t) => ({
    userSlugIdx: index('personas_user_slug_idx').on(t.userId, t.slug),
  }),
);

import { pgTable, timestamp, uuid, varchar, jsonb } from 'drizzle-orm/pg-core';
import { users } from './users';

export const auditLogs = pgTable('audit_logs', {
  id: uuid('id').primaryKey().defaultRandom(),
  userId: uuid('user_id').references(() => users.id, { onDelete: 'set null' }),
  action: varchar('action', { length: 255 }).notNull(),
  details: jsonb('details'),
  ipAddress: varchar('ip_address', { length: 45 }),
  userAgent: varchar('user_agent', { length: 255 }),
  createdAt: timestamp('created_at').defaultNow().notNull(),
});

export * from './users';
export * from './sessions';
export * from './oauth_accounts';
export * from './audit_logs';
export * from './workspaces';
