});

import { z } from 'zod';
import {
  assertEncryptionKey,
  isUnsafeEnvValue,
  makeDevelopmentSecret,
  resolveExternalValue,
  resolveSecret,
} from '@pcp/shared';

const rawEnv = {
  ...process.env,
  COOKIE_SECRET: process.env.COOKIE_SECRET ?? process.env.SESSION_SECRET,
  GOOGLE_CALLBACK_URL: process.env.GOOGLE_CALLBACK_URL ?? process.env.GOOGLE_REDIRECT_URI,
  FRONTEND_URL: process.env.FRONTEND_URL ?? process.env.APP_URL,
};

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
  PORT: z.coerce.number().int().positive().default(3001),
  COOKIE_SECRET: z.string().optional(),
  ENCRYPTION_KEY: z.string().optional(),
  GOOGLE_CLIENT_ID: z.string().optional(),
  GOOGLE_CLIENT_SECRET: z.string().optional(),
  GOOGLE_CALLBACK_URL: z.string().url().default('http://localhost:3001/auth/oauth/google/callback'),
  FRONTEND_URL: z.string().url().default('http://localhost:3000'),
  ADMIN_EMAIL: z.string().email().optional(),
});

const parsed = envSchema.parse(rawEnv);
const ctx = { isProduction: parsed.NODE_ENV === 'production' };

export const env = {
  NODE_ENV: parsed.NODE_ENV,
  PORT: parsed.PORT,
  COOKIE_SECRET: resolveSecret(ctx, 'COOKIE_SECRET', parsed.COOKIE_SECRET, 32),
  ENCRYPTION_KEY: resolveEncryptionKey(parsed.ENCRYPTION_KEY),
  GOOGLE_CLIENT_ID: resolveExternalValue(ctx, 'GOOGLE_CLIENT_ID', parsed.GOOGLE_CLIENT_ID),
  GOOGLE_CLIENT_SECRET: resolveExternalValue(ctx, 'GOOGLE_CLIENT_SECRET', parsed.GOOGLE_CLIENT_SECRET),
  GOOGLE_CALLBACK_URL: parsed.GOOGLE_CALLBACK_URL,
  FRONTEND_URL: parsed.FRONTEND_URL,
  ADMIN_EMAIL: parsed.ADMIN_EMAIL?.trim().toLowerCase(),
};

function resolveEncryptionKey(value: string | undefined): string {
  const resolved = value?.trim() || makeDevelopmentSecret(32, 'ENCRYPTION_KEY');
  if (ctx.isProduction && (!value?.trim() || isUnsafeEnvValue(resolved))) {
    throw new Error('ENCRYPTION_KEY must be set to a non-default value in production');
  }
  assertEncryptionKey('ENCRYPTION_KEY', resolved, ctx);
  return resolved;
}

import Fastify from 'fastify';
import { serializerCompiler, validatorCompiler } from 'fastify-type-provider-zod';
import cookie from '@fastify/cookie';
import cors from '@fastify/cors';
import rateLimit from '@fastify/rate-limit';
import {
  createApiErrorHandler,
  createCorsOptions,
  createCorrelationIdGenerator,
  registerObservability,
} from '@pcp/shared';
import { setupAuthRoutes } from './routes';
import { env } from './env';

const server = Fastify({
  genReqId: createCorrelationIdGenerator(),
  logger: {
    transport:
      env.NODE_ENV === 'development'
        ? {
            target: 'pino-pretty',
            options: {
              translateTime: 'HH:MM:ss Z',
              ignore: 'pid,hostname',
            },
          }
        : undefined,
  },
});

// Add schema validator and serializer
server.setValidatorCompiler(validatorCompiler);
server.setSerializerCompiler(serializerCompiler);

// Shared API error envelope: prevents 5xx leaks and standardizes the response shape.
server.setErrorHandler(createApiErrorHandler());
registerObservability(server, { serviceName: 'auth' });

server.addHook('onRequest', (request, reply, done) => {
  reply.header('x-correlation-id', request.id);
  done();
});

// Register plugins
server.register(cors, {
  ...createCorsOptions(env.NODE_ENV),
});

server.register(rateLimit, {
  max: 100,
  timeWindow: '1 minute',
});

server.register(cookie, {
  secret: env.COOKIE_SECRET,
  hook: 'onRequest',
});

// Health check
server.get('/health', async () => {
  return { status: 'ok', service: 'auth' };
});

// Register routes
server.register(setupAuthRoutes, { prefix: '/auth' });

const start = async () => {
  try {
    await server.listen({ port: env.PORT, host: '0.0.0.0' });
    server.log.info(`Auth service running on port ${env.PORT}`);
  } catch (err) {
    server.log.error(err);
    process.exit(1);
  }
};

start();

import crypto from 'crypto';
import { env } from './env';

const ALGORITHM = 'aes-256-gcm';

// Key must be exactly 32 bytes (256 bits) for aes-256-gcm.
const ENCRYPTION_KEY = Buffer.from(env.ENCRYPTION_KEY, 'utf8');

if (ENCRYPTION_KEY.length !== 32) {
  throw new Error('ENCRYPTION_KEY must be exactly 32 bytes long');
}

export function encrypt(text: string): { encrypted: string; iv: string; authTag: string } {
  const iv = crypto.randomBytes(12); // 96 bits is recommended for GCM
  const cipher = crypto.createCipheriv(ALGORITHM, ENCRYPTION_KEY, iv);

  let encrypted = cipher.update(text, 'utf8', 'base64');
  encrypted += cipher.final('base64');

  const authTag = cipher.getAuthTag();

  return {
    encrypted,
    iv: iv.toString('base64'),
    authTag: authTag.toString('base64'),
  };
}

export function decrypt(encrypted: string, ivBase64: string, authTagBase64: string): string {
  const iv = Buffer.from(ivBase64, 'base64');
  const authTag = Buffer.from(authTagBase64, 'base64');

  const decipher = crypto.createDecipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  decipher.setAuthTag(authTag);

  let decrypted = decipher.update(encrypted, 'base64', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

export function encryptOAuthToken(token: string): string {
  const { encrypted, iv, authTag } = encrypt(token);
  return `enc:v1:${iv}:${authTag}:${encrypted}`;
}

export function decryptOAuthToken(token: string): string {
  const [prefix, version, iv, authTag, encrypted] = token.split(':');

  if (prefix !== 'enc' || version !== 'v1' || !iv || !authTag || !encrypted) {
    throw new Error('Invalid encrypted OAuth token format');
  }

  return decrypt(encrypted, iv, authTag);
}

import { db } from '@pcp/db/src/client';
import { users, sessions, oauthAccounts, auditLogs } from '@pcp/db/src/schema';
import { eq, and } from 'drizzle-orm';
import * as argon2 from 'argon2';
import crypto from 'crypto';
import { encryptOAuthToken } from './encryption';

export type SanitizedUser = {
  id: string;
  email: string;
  name: string | null;
};

type AuditDetails = Record<string, unknown> | null;
type UserRecord = typeof users.$inferSelect;

export class AuthService {
  constructor(
    private logger: {
      info: (obj: object, msg?: string) => void;
      error: (obj: object, msg?: string) => void;
    },
  ) {}

  private async logAudit(
    action: string,
    userId: string | null,
    details: AuditDetails,
    ipAddress?: string,
    userAgent?: string,
  ) {
    try {
      await db.insert(auditLogs).values({
        action,
        userId,
        details,
        ipAddress: ipAddress || null,
        userAgent: userAgent || null,
      });
    } catch (error) {
      this.logger.error({ error, action, userId }, 'Failed to write audit log');
    }
  }

  async register(
    email: string,
    password: string,
    name?: string,
    ipAddress?: string,
    userAgent?: string,
  ) {
    this.logger.info({}, 'Registering new user');
    const existingUser = await db.query.users.findFirst({
      where: eq(users.email, email),
    });

    if (existingUser) {
      throw new Error('Email already registered');
    }

    const passwordHash = await argon2.hash(password);

    const [newUser] = await db
      .insert(users)
      .values({
        email,
        passwordHash,
        name: name || null,
      })
      .returning();

    if (!newUser) {
      throw new Error('Failed to create user');
    }

    const session = await this.createSession(newUser.id);
    await this.logAudit('auth.register', newUser.id, null, ipAddress, userAgent);
    return { user: this.sanitizeUser(newUser), session };
  }

  async login(email: string, password: string, ipAddress?: string, userAgent?: string) {
    this.logger.info({}, 'User login attempt');
    const user = await db.query.users.findFirst({
      where: eq(users.email, email),
    });

    if (!user || !user.passwordHash) {
      await this.logAudit(
        'auth.login_failed',
        user?.id || null,
        { reason: 'Invalid credentials' },
        ipAddress,
        userAgent,
      );
      throw new Error('Invalid credentials');
    }

    const isValid = await argon2.verify(user.passwordHash, password);
    if (!isValid) {
      await this.logAudit(
        'auth.login_failed',
        user.id,
        { reason: 'Invalid credentials' },
        ipAddress,
        userAgent,
      );
      throw new Error('Invalid credentials');
    }

    const session = await this.createSession(user.id);
    await this.logAudit('auth.login', user.id, null, ipAddress, userAgent);
    return { user: this.sanitizeUser(user), session };
  }

  async handleOAuthLogin(
    data: {
      providerId: string;
      providerUserId: string;
      email: string;
      name: string;
      accessToken: string;
      refreshToken?: string;
    },
    ipAddress?: string,
    userAgent?: string,
  ) {
    let user = await db.query.users.findFirst({
      where: eq(users.email, data.email),
    });

    if (!user) {
      const [newUser] = await db
        .insert(users)
        .values({
          email: data.email,
          name: data.name,
        })
        .returning();
      if (!newUser) throw new Error('Failed to create user');
      user = newUser;
      await this.logAudit(
        'auth.register_oauth',
        user.id,
        { provider: data.providerId },
        ipAddress,
        userAgent,
      );
    }

    if (!user) throw new Error('User not found');

    const encryptedAccessToken = encryptOAuthToken(data.accessToken);
    const encryptedRefreshToken = data.refreshToken ? encryptOAuthToken(data.refreshToken) : undefined;

    const existingOauth = await db.query.oauthAccounts.findFirst({
      where: and(
        eq(oauthAccounts.providerId, data.providerId),
        eq(oauthAccounts.providerUserId, data.providerUserId),
      ),
    });

    if (existingOauth) {
      await db
        .update(oauthAccounts)
        .set({
          accessToken: encryptedAccessToken,
          refreshToken: encryptedRefreshToken || existingOauth.refreshToken,
          updatedAt: new Date(),
        })
        .where(
          and(
            eq(oauthAccounts.providerId, data.providerId),
            eq(oauthAccounts.providerUserId, data.providerUserId),
          ),
        );
    } else {
      await db.insert(oauthAccounts).values({
        providerId: data.providerId,
        providerUserId: data.providerUserId,
        userId: user.id,
        accessToken: encryptedAccessToken,
        refreshToken: encryptedRefreshToken,
      });
    }

    const session = await this.createSession(user.id);
    await this.logAudit(
      'auth.login_oauth',
      user.id,
      { provider: data.providerId },
      ipAddress,
      userAgent,
    );

    return { user: this.sanitizeUser(user), session };
  }

  async validateSession(sessionId: string) {
    const session = await db.query.sessions.findFirst({
      where: eq(sessions.id, sessionId),
    });

    if (!session) return null;

    if (session.expiresAt.getTime() < Date.now()) {
      await this.logout(sessionId);
      return null;
    }

    // Refresh session expiration time if less than 15 days left
    const fifteenDays = 1000 * 60 * 60 * 24 * 15;
    if (session.expiresAt.getTime() - Date.now() < fifteenDays) {
      const newExpiresAt = new Date(Date.now() + 1000 * 60 * 60 * 24 * 30);
      await db.update(sessions).set({ expiresAt: newExpiresAt }).where(eq(sessions.id, sessionId));
    }

    const user = await db.query.users.findFirst({
      where: eq(users.id, session.userId),
    });

    return user ? this.sanitizeUser(user) : null;
  }

  private sanitizeUser(user: UserRecord): SanitizedUser {
    return {
      id: user.id,
      email: user.email,
      name: user.name,
    };
  }

  async refreshSession(oldSessionId: string, ipAddress?: string, userAgent?: string) {
    const session = await db.query.sessions.findFirst({
      where: eq(sessions.id, oldSessionId),
    });

    if (!session || session.expiresAt.getTime() < Date.now()) {
      if (session) await this.logout(oldSessionId);
      return null;
    }

    const newSession = await this.createSession(session.userId);
    await this.logout(oldSessionId);
    await this.logAudit('auth.session_refresh', session.userId, null, ipAddress, userAgent);

    return newSession;
  }

  async logout(sessionId: string, ipAddress?: string, userAgent?: string) {
    const session = await db.query.sessions.findFirst({
      where: eq(sessions.id, sessionId),
    });

    if (session) {
      await this.logAudit('auth.logout', session.userId, null, ipAddress, userAgent);
      await db.delete(sessions).where(eq(sessions.id, sessionId));
    }
  }

  private async createSession(userId: string) {
    const sessionId = crypto.randomBytes(32).toString('hex');
    const expiresAt = new Date(Date.now() + 1000 * 60 * 60 * 24 * 30); // 30 days

    const [session] = await db
      .insert(sessions)
      .values({
        id: sessionId,
        userId,
        expiresAt,
      })
      .returning();

    if (!session) {
      throw new Error('Failed to create session');
    }

    return session;
  }
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import oauthPlugin from '@fastify/oauth2';
import { registerSchema, loginSchema, authResponseSchema, sendApiError } from '@pcp/shared';
import { z } from 'zod';
import { AuthService } from './service';
import { setupProfileRoutes } from './routes/profile';
import { setupAdminRoutes } from './routes/admin';
import { env } from './env';

export const googleUserInfoSchema = z.object({
  id: z.string(),
  email: z.string().email(),
  name: z.string(),
  verified_email: z.literal(true),
});

export async function setupAuthRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const authService = new AuthService(fastify.log);

  // Register Profile and Admin Routes
  await setupProfileRoutes(fastify);
  await setupAdminRoutes(fastify);

  // Register Google OAuth2
  server.register(oauthPlugin, {
    name: 'googleOAuth2',
    credentials: {
      client: {
        id: env.GOOGLE_CLIENT_ID,
        secret: env.GOOGLE_CLIENT_SECRET,
      },
      auth: oauthPlugin.GOOGLE_CONFIGURATION,
    },
    startRedirectPath: '/oauth/google/start',
    callbackUri: env.GOOGLE_CALLBACK_URL,
    scope: ['profile', 'email'],
  });

  server.post(
    '/register',
    {
      config: {
        rateLimit: {
          max: 5,
          timeWindow: '1 minute',
        },
      },
      schema: {
        body: registerSchema,
        response: {
          201: authResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const { email, password, name } = request.body;
      const { user, session } = await authService.register(
        email,
        password,
        name,
        request.ip,
        request.headers['user-agent'],
      );

      reply.setCookie('sessionId', session.id, {
        path: '/',
        httpOnly: true,
        sameSite: 'lax',
        secure: env.NODE_ENV === 'production',
        maxAge: 30 * 24 * 60 * 60, // 30 days
      });

      return reply.code(201).send({ user });
    },
  );

  server.post(
    '/login',
    {
      config: {
        rateLimit: {
          max: 5,
          timeWindow: '1 minute',
        },
      },
      schema: {
        body: loginSchema,
        response: {
          200: authResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const { email, password } = request.body;
      const { user, session } = await authService.login(
        email,
        password,
        request.ip,
        request.headers['user-agent'],
      );

      reply.setCookie('sessionId', session.id, {
        path: '/',
        httpOnly: true,
        sameSite: 'lax',
        secure: env.NODE_ENV === 'production',
        maxAge: 30 * 24 * 60 * 60, // 30 days
      });

      return { user };
    },
  );

  server.get(
    '/me',
    {
      schema: {
        response: {
          200: authResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const sessionId = request.cookies.sessionId;
      if (!sessionId) {
        return sendApiError(reply, 401, 'UNAUTHORIZED');
      }

      const user = await authService.validateSession(sessionId);
      if (!user) {
        return sendApiError(reply, 401, 'UNAUTHORIZED', 'Invalid session');
      }

      return { user };
    },
  );

  server.post('/refresh', async (request, reply) => {
    const sessionId = request.cookies.sessionId;
    if (!sessionId) {
      return sendApiError(reply, 401, 'UNAUTHORIZED');
    }

    const newSession = await authService.refreshSession(
      sessionId,
      request.ip,
      request.headers['user-agent'],
    );

    if (!newSession) {
      reply.clearCookie('sessionId', { path: '/' });
      return sendApiError(reply, 401, 'UNAUTHORIZED', 'Invalid or expired session');
    }

    reply.setCookie('sessionId', newSession.id, {
      path: '/',
      httpOnly: true,
      sameSite: 'lax',
      secure: env.NODE_ENV === 'production',
      maxAge: 30 * 24 * 60 * 60, // 30 days
    });

    return { success: true };
  });

  server.post('/logout', async (request, reply) => {
    const sessionId = request.cookies.sessionId;
    if (sessionId) {
      await authService.logout(sessionId, request.ip, request.headers['user-agent']);
    }

    reply.clearCookie('sessionId', { path: '/' });
    return { success: true };
  });

  // Google OAuth callback
  server.get('/oauth/google/callback', async function (request, reply) {
    // @ts-ignore
    const { token } = await this.googleOAuth2.getAccessTokenFromAuthorizationCodeFlow(request);

    const userInfoResponse = await fetch('https://www.googleapis.com/oauth2/v2/userinfo', {
      headers: { Authorization: `Bearer ${token.access_token}` },
    });

    if (!userInfoResponse.ok) {
      throw new Error('Failed to fetch user info from Google');
    }

    const userInfo = googleUserInfoSchema.parse(await userInfoResponse.json());

    const { session } = await authService.handleOAuthLogin(
      {
        providerId: 'google',
        providerUserId: userInfo.id,
        email: userInfo.email,
        name: userInfo.name,
        accessToken: token.access_token,
        refreshToken: token.refresh_token,
      },
      request.ip,
      request.headers['user-agent'],
    );

    reply.setCookie('sessionId', session.id, {
      path: '/',
      httpOnly: true,
      sameSite: 'lax',
      secure: env.NODE_ENV === 'production',
      maxAge: 30 * 24 * 60 * 60,
    });

    return reply.redirect(`${env.FRONTEND_URL}/dashboard`);
  });
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { db } from '@pcp/db/src/client';
import { userPreferences, providerCredentials, auditLogs } from '@pcp/db/src/schema';
import { eq, and, isNull, desc } from 'drizzle-orm';
import {
  userPreferencesSchema,
  updateUserPreferencesSchema,
  providerCredentialResponseSchema,
  createProviderCredentialSchema,
  auditLogSchema,
  sendApiError,
} from '@pcp/shared';
import { encrypt } from '../encryption';
import { AuthService } from '../service';

type ProviderCredentialRow = typeof providerCredentials.$inferSelect;

export function maskProviderKey(provider: string, key: string): string {
  const suffix = key.slice(-4);
  return `${provider}-****${suffix}`;
}

export function toProviderCredentialResponse(credential: ProviderCredentialRow) {
  const keySuffix =
    credential.metadata &&
    typeof credential.metadata === 'object' &&
    typeof credential.metadata.keySuffix === 'string'
      ? credential.metadata.keySuffix
      : '';

  return {
    id: credential.id,
    provider: credential.provider,
    label: credential.label,
    maskedKey: keySuffix
      ? `${credential.provider}-****${keySuffix}`
      : `${credential.provider}-****`,
    lastUsedAt: credential.lastUsedAt,
    createdAt: credential.createdAt,
  };
}

export async function setupProfileRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const authService = new AuthService(fastify.log);

  async function getUserId(request: any, reply: any) {
    const sessionId = request.cookies.sessionId;
    if (!sessionId) {
      sendApiError(reply, 401, 'UNAUTHORIZED');
      return null;
    }
    const user = await authService.validateSession(sessionId);
    if (!user) {
      sendApiError(reply, 401, 'UNAUTHORIZED');
      return null;
    }
    return user.id;
  }

  // User Preferences
  server.get(
    '/user/preferences',
    {
      schema: {
        response: {
          200: userPreferencesSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      let prefs = await db.query.userPreferences.findFirst({
        where: eq(userPreferences.userId, userId),
      });

      if (!prefs) {
        // Create default preferences
        const [newPrefs] = await db.insert(userPreferences).values({ userId }).returning();
        prefs = newPrefs;
      }

      return reply.code(200).send(prefs);
    },
  );

  server.patch(
    '/user/preferences',
    {
      schema: {
        body: updateUserPreferencesSchema,
        response: {
          200: userPreferencesSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      // Ensure preferences exist
      const existing = await db.query.userPreferences.findFirst({
        where: eq(userPreferences.userId, userId),
      });

      if (!existing) {
        await db.insert(userPreferences).values({ userId });
      }

      const [updated] = await db
        .update(userPreferences)
        .set({ ...request.body, updatedAt: new Date() })
        .where(eq(userPreferences.userId, userId))
        .returning();

      // Log action
      await db.insert(auditLogs).values({
        userId,
        action: 'UPDATE_PREFERENCES',
        ipAddress: request.ip,
        userAgent: request.headers['user-agent'] as string,
      });

      return reply.code(200).send(updated);
    },
  );

  // Provider Credentials
  server.get(
    '/user/providers',
    {
      schema: {
        response: {
          200: z.array(providerCredentialResponseSchema),
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      const providers = await db.query.providerCredentials.findMany({
        where: and(eq(providerCredentials.userId, userId), isNull(providerCredentials.revokedAt)),
      });

      return reply.code(200).send(providers.map(toProviderCredentialResponse));
    },
  );

  server.post(
    '/user/providers',
    {
      schema: {
        body: createProviderCredentialSchema,
        response: {
          201: providerCredentialResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      const { provider, label, key } = request.body;
      const { encrypted, iv, authTag } = encrypt(key);
      const keySuffix = key.slice(-4);

      const [credential] = await db
        .insert(providerCredentials)
        .values({
          userId,
          provider,
          label,
          encryptedKey: encrypted,
          iv,
          authTag,
          metadata: { keySuffix },
        })
        .returning();

      if (!credential) throw new Error('Failed to save credential');

      await db.insert(auditLogs).values({
        userId,
        action: 'ADD_PROVIDER_CREDENTIAL',
        details: { provider },
        ipAddress: request.ip,
        userAgent: request.headers['user-agent'] as string,
      });

      return reply.code(201).send({
        id: credential.id,
        provider: credential.provider,
        label: credential.label,
        maskedKey: maskProviderKey(credential.provider, key),
        lastUsedAt: credential.lastUsedAt,
        createdAt: credential.createdAt,
      });
    },
  );

  server.delete(
    '/user/providers/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      await db
        .update(providerCredentials)
        .set({ revokedAt: new Date() })
        .where(
          and(
            eq(providerCredentials.id, request.params.id),
            eq(providerCredentials.userId, userId),
          ),
        );

      await db.insert(auditLogs).values({
        userId,
        action: 'REVOKE_PROVIDER_CREDENTIAL',
        details: { credentialId: request.params.id },
        ipAddress: request.ip,
        userAgent: request.headers['user-agent'] as string,
      });

      return reply.code(204).send();
    },
  );

  // List the current user's own audit log entries (most recent first).
  server.get(
    '/user/audit-logs',
    {
      schema: {
        querystring: z.object({
          limit: z.coerce.number().int().min(1).max(500).optional(),
          action: z.string().optional(),
        }),
        response: {
          200: z.array(auditLogSchema),
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request, reply);
      if (!userId) return;

      const { limit, action } = request.query;
      const logs = await db.query.auditLogs.findMany({
        where: action
          ? and(eq(auditLogs.userId, userId), eq(auditLogs.action, action))
          : eq(auditLogs.userId, userId),
        orderBy: [desc(auditLogs.createdAt)],
        limit: limit ?? 100,
      });

      return reply.code(200).send(
        logs.map((log) => ({
          ...log,
          details:
            log.details && typeof log.details === 'object' && !Array.isArray(log.details)
              ? (log.details as Record<string, unknown>)
              : null,
        })),
      );
    },
  );
}

import { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { db } from '@pcp/db/src/client';
import { users, auditLogs } from '@pcp/db/src/schema';
import { desc } from 'drizzle-orm';
import { auditLogSchema, sendApiError } from '@pcp/shared';
import { AuthService, SanitizedUser } from '../service';
import { env } from '../env';

export function isAdminUser(user: SanitizedUser, adminEmail: string | undefined): boolean {
  if (!adminEmail) return false;
  return user.email.toLowerCase() === adminEmail.toLowerCase();
}

function normalizeAuditDetails(details: unknown): Record<string, unknown> | null {
  if (!details || typeof details !== 'object' || Array.isArray(details)) {
    return null;
  }

  return details as Record<string, unknown>;
}

export async function setupAdminRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const authService = new AuthService(fastify.log);

  // Helper to check if user is admin
  async function checkIsAdmin(request: FastifyRequest, reply: FastifyReply) {
    const sessionId = request.cookies.sessionId;
    if (!sessionId) {
      sendApiError(reply, 401, 'UNAUTHORIZED');
      return false;
    }
    const user = await authService.validateSession(sessionId);
    if (!user) {
      sendApiError(reply, 401, 'UNAUTHORIZED');
      return false;
    }

    // MVP admin policy: fail closed unless an explicit admin email is configured.
    if (!isAdminUser(user, env.ADMIN_EMAIL)) {
      sendApiError(reply, 403, 'FORBIDDEN');
      return false;
    }

    return true;
  }

  // List all users
  server.get(
    '/admin/users',
    {
      schema: {
        response: {
          200: z.array(
            z.object({
              id: z.string().uuid(),
              name: z.string().nullable(),
              email: z.string(),
              createdAt: z.date(),
            }),
          ),
        },
      },
    },
    async (request, reply) => {
      if (!(await checkIsAdmin(request, reply))) return;

      const allUsers = await db.query.users.findMany({
        orderBy: [desc(users.createdAt)],
      });

      return reply.code(200).send(allUsers);
    },
  );

  // List audit logs
  server.get(
    '/admin/audit-logs',
    {
      schema: {
        response: {
          200: z.array(auditLogSchema),
        },
      },
    },
    async (request, reply) => {
      if (!(await checkIsAdmin(request, reply))) return;

      const logs = await db.query.auditLogs.findMany({
        orderBy: [desc(auditLogs.createdAt)],
        limit: 100, // Limit to recent 100 for MVP
      });

      return reply.code(200).send(
        logs.map((log) => ({
          ...log,
          details: normalizeAuditDetails(log.details),
        })),
      );
    },
  );

  // Simple health check
  server.get('/admin/health', async (request, reply) => {
    if (!(await checkIsAdmin(request, reply))) return;

    return reply.code(200).send({
      status: 'healthy',
      dbConnected: true,
      uptime: process.uptime(),
    });
  });
}

import { z } from 'zod';
