import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import {
  createWorkspaceSchema,
  fileContentResponseSchema,
  fileMetadataSchema,
  listFilesSchema,
  listWorkspacesSchema,
  moveFileSchema,
