    const [file] = await db
      .insert(workspaceFiles)
      .values({
        workspaceId,
        path: normalizedPath,
        name: data.name,
        mimeType: data.mimeType || null,
        size: data.size.toString(),
        storageKey,
        isDirectory: data.isDirectory ? '1' : '0',
