      throw new WorkspaceError(`Snapshot failed: ${message}`, 500);
    }
  }

  async getSnapshots(workspaceId: string, userId: string): Promise<any[]> {
    return db.query.snapshots.findMany({
      where: and(
        eq(snapshots.workspaceId, workspaceId),
        eq(snapshots.userId, userId),
        isNull(snapshots.deletedAt),
      ),
      orderBy: [desc(snapshots.createdAt)],
    });
  }

  async deleteSnapshot(snapshotId: string, userId: string): Promise<void> {
    const snapshot = await db.query.snapshots.findFirst({
      where: and(eq(snapshots.id, snapshotId), eq(snapshots.userId, userId)),
    });
    if (!snapshot) throw new WorkspaceError('Snapshot not found', 404);

    await db
      .update(snapshots)
      .set({ deletedAt: new Date(), status: 'deleted' })
      .where(
        and(
          eq(snapshots.id, snapshotId),
          eq(snapshots.userId, userId),
          isNull(snapshots.deletedAt),
        ),
      );
  }

  async restoreSnapshot(snapshotId: string, userId: string): Promise<{ restoredFiles: number }> {
    const snapshot = await db.query.snapshots.findFirst({
      where: and(eq(snapshots.id, snapshotId), eq(snapshots.userId, userId)),
    });
    if (!snapshot) throw new WorkspaceError('Snapshot not found', 404);
    if (snapshot.status !== 'ready') {
      throw new WorkspaceError(`Snapshot not restorable (status=${snapshot.status})`, 400);
    }

    // Auto pre-restore snapshot so the user can roll back the rollback.
    try {
      await this.createSnapshot(
        snapshot.workspaceId,
        userId,
        `pre-restore ${new Date().toISOString()}`,
        `Automatic snapshot taken before restoring ${snapshot.name}`,
        'auto-pre-restore',
      );
    } catch (err) {
      this.logger.warn({ err, snapshotId }, 'Auto pre-restore snapshot failed; aborting restore');
      throw new WorkspaceError('Failed to create pre-restore snapshot', 500);
    }

    await db
      .update(snapshots)
      .set({ status: 'restoring' })
      .where(
        and(
          eq(snapshots.id, snapshotId),
          eq(snapshots.userId, userId),
          isNull(snapshots.deletedAt),
        ),
      );

    try {
      const buffer = await this.storage.getBuffer(snapshot.storageKey);
      const json = gunzipSync(buffer).toString('utf8');
      const archive = JSON.parse(json) as SnapshotArchive;

      if (archive.version !== SNAPSHOT_FORMAT_VERSION) {
        throw new Error(`Unsupported snapshot format version ${archive.version}`);
      }

      const restoredCount = await this.applySnapshotArchive(snapshot.workspaceId, userId, archive);

      await db
        .update(snapshots)
        .set({ status: 'ready' })
        .where(
          and(
            eq(snapshots.id, snapshotId),
            eq(snapshots.userId, userId),
            isNull(snapshots.deletedAt),
          ),
        );

      return { restoredFiles: restoredCount };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Restore failed';
      this.logger.error({ err, snapshotId }, 'Failed to restore snapshot');
      await db
        .update(snapshots)
        .set({ status: 'failed', error: message })
        .where(
          and(
            eq(snapshots.id, snapshotId),
            eq(snapshots.userId, userId),
            isNull(snapshots.deletedAt),
          ),
        );
      throw new WorkspaceError(`Restore failed: ${message}`, 500);
    }
  }

  private async buildSnapshotArchive(workspaceId: string): Promise<SnapshotArchive> {
    const rows = await db.query.workspaceFiles.findMany({
      where: and(eq(workspaceFiles.workspaceId, workspaceId), isNull(workspaceFiles.deletedAt)),
    });

    const files: SnapshotArchive['files'] = [];
    for (const row of rows) {
      const isDirectory = row.isDirectory === '1';
      let contentBase64: string | null = null;

      if (!isDirectory && row.storageKey) {
        try {
          const text = await this.storage.getText(row.storageKey);
          contentBase64 = Buffer.from(text, 'utf8').toString('base64');
        } catch (err) {
          this.logger.warn({ err, path: row.path }, 'Failed to read file during snapshot');
          contentBase64 = '';
        }
      }

      files.push({
        path: row.path,
        name: row.name,
        parentPath: row.parentPath,
        isDirectory,
        mimeType: row.mimeType,
        size: Number(row.size || 0),
        contentBase64,
      });
    }

    return {
      version: SNAPSHOT_FORMAT_VERSION,
      workspaceId,
      createdAt: new Date().toISOString(),
      files,
    };
  }

  private async applySnapshotArchive(
    workspaceId: string,
    userId: string,
    archive: SnapshotArchive,
  ): Promise<number> {
    // Soft-delete current files so existing storageKeys remain readable for any
    // in-flight requests; the new snapshot uses fresh keys.
    await db
      .update(workspaceFiles)
      .set({ deletedAt: new Date() })
      .where(and(eq(workspaceFiles.workspaceId, workspaceId), isNull(workspaceFiles.deletedAt)));

    let totalSize = 0;
    let restored = 0;

    for (const entry of archive.files) {
      const normalizedPath = this.normalizeFilePath(entry.path);
      let storageKey = '';

      if (!entry.isDirectory) {
        storageKey = this.getStorageKey(userId, workspaceId, normalizedPath);
        const text = entry.contentBase64
          ? Buffer.from(entry.contentBase64, 'base64').toString('utf8')
          : '';
        await this.storage.putText(storageKey, text, entry.mimeType ?? 'text/plain');
        totalSize += entry.size;
      }

      await db.insert(workspaceFiles).values({
        workspaceId,
        path: normalizedPath,
        name: entry.name,
        mimeType: entry.mimeType,
        size: entry.size.toString(),
        storageKey,
        isDirectory: entry.isDirectory ? '1' : '0',
        parentPath: entry.parentPath,
      });
      restored += 1;
    }

    await db
      .update(workspaces)
      .set({ storageUsed: totalSize, updatedAt: new Date() })
      .where(and(eq(workspaces.id, workspaceId), eq(workspaces.userId, userId)));

    return restored;
  }
}

interface SnapshotArchive {
  version: number;
  workspaceId: string;
  createdAt: string;
  files: Array<{
    path: string;
    name: string;
    parentPath: string | null;
    isDirectory: boolean;
    mimeType: string | null;
    size: number;
    contentBase64: string | null;
  }>;
}

import { FastifyInstance, FastifyRequest } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { promises as fs } from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { pipeline } from 'node:stream/promises';
import { createWriteStream } from 'node:fs';
import {
  datasetResponseSchema,
  queryDatasetSchema,
  queryResultSchema,
  apiErrorCodeFromStatus,
  sendApiError,
} from '@pcp/shared';
import { DatasetsService } from '../datasets/service';
import { env } from '../env';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';

const SOURCE_TYPE_BY_EXT: Record<string, 'csv' | 'json' | 'parquet'> = {
  '.csv': 'csv',
  '.tsv': 'csv',
  '.json': 'json',
  '.ndjson': 'json',
  '.jsonl': 'json',
  '.parquet': 'parquet',
};

function toResponse(row: any) {
  return {
    id: row.id,
    name: row.name,
    tableName: row.tableName,
    sourceType: row.sourceType,
    sourceFilename: row.sourceFilename ?? null,
    columns: Array.isArray(row.columns) ? row.columns : [],
    rowCount: Number(row.rowCount ?? 0),
    sizeBytes: Number(row.sizeBytes ?? 0),
    version: Number(row.version ?? 1),
    createdAt: row.createdAt instanceof Date ? row.createdAt.toISOString() : row.createdAt,
    updatedAt: row.updatedAt instanceof Date ? row.updatedAt.toISOString() : row.updatedAt,
  };
}

export async function setupDatasetsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const datasetsService = new DatasetsService(fastify.log);

  async function authUser(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  server.get(
    '/datasets',
    {
      schema: {
        response: {
          200: z.object({ datasets: z.array(datasetResponseSchema) }),
        },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await datasetsService.list(userId);
      return { datasets: rows.map(toResponse) };
    },
  );

  server.delete(
    '/datasets/:id',
    {
      schema: { params: z.object({ id: z.string().uuid() }) },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await datasetsService.remove(userId, request.params.id);
        return { success: true };
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Internal error',
        );
      }
    },
  );

  server.post(
    '/datasets/:id/query',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const ds = await datasetsService.get(userId, request.params.id);
      if (!ds) return sendApiError(reply, 404, 'NOT_FOUND', 'Dataset not found');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.post(
    '/datasets/query',
    {
      schema: {
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.get(
    '/datasets/:id/preview',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        querystring: z.object({ limit: z.coerce.number().int().min(1).max(500).optional() }),
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.preview(userId, request.params.id, request.query.limit);
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Preview failed',
        );
      }
    },
  );

  // Multipart upload + import. Field name for the file part is "file"; an optional
  // text field "name" overrides the dataset display name.
  server.post('/datasets/import', async (request, reply) => {
    const userId = await authUser(request);
    if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

    if (!request.isMultipart()) {
      return sendApiError(reply, 400, 'BAD_REQUEST', 'Expected multipart/form-data');
    }

    let displayName: string | undefined;
    let savedPath: string | undefined;
    let originalFilename: string | undefined;
    let sourceType: 'csv' | 'json' | 'parquet' | undefined;

    try {
      const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'cloudmind-ds-'));
      const parts = request.parts();
      for await (const part of parts) {
        if (part.type === 'field' && part.fieldname === 'name') {
          displayName = String(part.value);
        } else if (part.type === 'file') {
          originalFilename = part.filename;
          const ext = path.extname(part.filename).toLowerCase();
          const detected = SOURCE_TYPE_BY_EXT[ext];
          if (!detected) {
            await part.file.resume();
            return sendApiError(
              reply,
              400,
              'BAD_REQUEST',
              `Unsupported file type "${ext}". Use .csv, .tsv, .json, .ndjson, or .parquet.`,
            );
          }
          sourceType = detected;
          savedPath = path.join(tmpDir, `upload${ext}`);
          await pipeline(part.file, createWriteStream(savedPath));
        }
      }

      if (!savedPath || !sourceType || !originalFilename) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'No file provided');
      }

      const finalName =
        (displayName?.trim() || path.basename(originalFilename, path.extname(originalFilename))) ||
        'dataset';

      const inserted = await datasetsService.importFile({
        userId,
        name: finalName,
        filePath: savedPath,
        sourceFilename: originalFilename,
        sourceType,
      });
      return reply.code(201).send(toResponse(inserted));
    } catch (err: any) {
      const status = err?.statusCode ?? 500;
      if (status === 500) fastify.log.error({ err }, 'dataset import failed');
      return sendApiError(
        reply,
        status,
        apiErrorCodeFromStatus(status),
        err?.message ?? 'Import failed',
      );
    } finally {
      if (savedPath) {
        await fs.rm(path.dirname(savedPath), { recursive: true, force: true }).catch(() => {});
      }
    }
  });
}

import * as path from 'node:path';
import { promises as fs } from 'node:fs';
import { db } from '@pcp/db/src/client';
import { datasets } from '@pcp/db/src/schema';
import { and, asc, eq, isNull } from 'drizzle-orm';
import { DuckDb, sanitizeTableName, type DuckDbColumn } from './driver';
import { env } from '../env';

export interface ImportOptions {
  userId: string;
  name: string;
  filePath: string; // local path to the uploaded file
  sourceFilename: string;
  sourceType: 'csv' | 'json' | 'parquet';
}

export interface QueryOptions {
  userId: string;
  sql: string;
  rowLimit?: number;
}

const DEFAULT_ROW_LIMIT = 1000;
const MAX_ROW_LIMIT = 10000;
const FILE_READING_FUNCTION_PATTERN =
  /\b(?:read_(?:csv|csv_auto|json|json_auto|ndjson|parquet|text)|parquet_scan|glob|sniff_csv)\s*\(/i;

export class DatasetsService {
  private dataDir: string;

  constructor(
    private logger?: {
      info: (...a: any[]) => void;
      warn: (...a: any[]) => void;
      error: (...a: any[]) => void;
    },
  ) {
    this.dataDir = path.resolve(env.DATASETS_DATA_DIR);
  }

  private dbPathFor(userId: string): string {
    return path.join(this.dataDir, `${userId}.duckdb`);
  }

  async list(userId: string) {
    return db
      .select()
      .from(datasets)
      .where(and(eq(datasets.userId, userId), isNull(datasets.deletedAt)))
      .orderBy(asc(datasets.name));
  }

  async get(userId: string, id: string) {
    const rows = await db
      .select()
      .from(datasets)
      .where(and(eq(datasets.id, id), eq(datasets.userId, userId), isNull(datasets.deletedAt)))
      .limit(1);
    return rows[0] ?? null;
  }

  /** Import a local file (CSV/JSON/Parquet) into the user's DuckDB and register the dataset. */
  async importFile(opts: ImportOptions) {
    const { userId, name, filePath, sourceFilename, sourceType } = opts;

    const stat = await fs.stat(filePath);
    const tableName = await this.uniqueTableName(userId, name);

    const duck = new DuckDb(this.dbPathFor(userId));
    const conn = await duck.connect();
    try {
      const reader = this.readerExpression(sourceType, filePath);
      // Atomic replace via CREATE OR REPLACE.
      await conn.run(`CREATE OR REPLACE TABLE "${tableName}" AS SELECT * FROM ${reader}`);
      const desc = await conn.all(`DESCRIBE "${tableName}"`);
      const cols = desc.rows.map((r) => ({
        name: String(r[0]),
        type: String(r[1] ?? 'UNKNOWN'),
      }));
      const countRes = await conn.all(`SELECT count(*) FROM "${tableName}"`);
      const rowCount = Number(countRes.rows[0]?.[0] ?? 0);

      const inserted = await db
        .insert(datasets)
        .values({
          userId,
          name,
          tableName,
          sourceType,
          sourceFilename,
          columns: cols,
          rowCount,
          sizeBytes: stat.size,
        })
        .returning();
      return inserted[0]!;
    } finally {
      await conn.close().catch(() => {});
    }
  }

  /** Run a read-only SQL query, scoped to the user's DuckDB file. */
  async query(opts: QueryOptions) {
    const { userId, sql } = opts;
    const limit = Math.min(Math.max(opts.rowLimit ?? DEFAULT_ROW_LIMIT, 1), MAX_ROW_LIMIT);
    this.assertReadOnly(sql);

    const duck = new DuckDb(this.dbPathFor(userId));
    const conn = await duck.connect();
    const start = Date.now();
    try {
      // Wrap user SQL in a CTE to enforce a hard row cap regardless of LIMIT clauses.
      const wrapped = `SELECT * FROM (${sql.trim().replace(/;\s*$/, '')}) _q LIMIT ${limit + 1}`;
      const result = await conn.all(wrapped);
      const truncated = result.rows.length > limit;
      const rows = truncated ? result.rows.slice(0, limit) : result.rows;
      return {
        columns: result.columns satisfies DuckDbColumn[],
        rows,
        rowCount: rows.length,
        truncated,
        durationMs: Date.now() - start,
      };
    } finally {
      await conn.close().catch(() => {});
    }
  }

  async preview(userId: string, id: string, limit = 50) {
    const ds = await this.get(userId, id);
    if (!ds) throw Object.assign(new Error('Dataset not found'), { statusCode: 404 });
    return this.query({ userId, sql: `SELECT * FROM "${ds.tableName}"`, rowLimit: limit });
  }

  async remove(userId: string, id: string) {
    const ds = await this.get(userId, id);
    if (!ds) throw Object.assign(new Error('Dataset not found'), { statusCode: 404 });

    const duck = new DuckDb(this.dbPathFor(userId));
    const conn = await duck.connect();
    try {
      await conn.run(`DROP TABLE IF EXISTS "${ds.tableName}"`);
    } catch (err) {
      this.logger?.warn?.({ err, tableName: ds.tableName }, 'failed to drop duckdb table');
    } finally {
      await conn.close().catch(() => {});
    }
    await db
      .update(datasets)
      .set({ deletedAt: new Date() })
      .where(and(eq(datasets.id, id), eq(datasets.userId, userId), isNull(datasets.deletedAt)));
    return { success: true };
  }

  private readerExpression(sourceType: string, filePath: string): string {
    const escaped = filePath.replace(/'/g, "''");
    switch (sourceType) {
      case 'csv':
        return `read_csv_auto('${escaped}', sample_size=-1, header=true)`;
      case 'json':
        return `read_json_auto('${escaped}')`;
      case 'parquet':
        return `read_parquet('${escaped}')`;
      default:
        throw Object.assign(new Error(`Unsupported source type: ${sourceType}`), {
          statusCode: 400,
        });
    }
  }

  private async uniqueTableName(userId: string, name: string): Promise<string> {
    const base = sanitizeTableName(name);
    const existing = await db
      .select({ tableName: datasets.tableName })
      .from(datasets)
      .where(and(eq(datasets.userId, userId), isNull(datasets.deletedAt)));
    const taken = new Set(existing.map((r) => r.tableName));
    if (!taken.has(base)) return base;
    for (let i = 2; i < 1000; i++) {
      const cand = `${base}_${i}`;
      if (!taken.has(cand)) return cand;
    }
    return `${base}_${Date.now()}`;
  }

  /**
   * Block obvious mutating statements. DuckDB has no real read-only mode in the Node API,
   * so we do a coarse keyword check against the trimmed first token. Multi-statement input
   * is rejected by the trailing-semicolon strip + CTE wrapping in `query()`.
   */
  private assertReadOnly(sql: string) {
    const cleaned = sql
      .replace(/--[^\n]*/g, '')
      .replace(/\/\*[\s\S]*?\*\//g, '')
      .trim()
      .toLowerCase();
    if (!cleaned) throw Object.assign(new Error('Empty SQL'), { statusCode: 400 });
    if (/;\s*\S/.test(cleaned.replace(/;\s*$/, ''))) {
      throw Object.assign(new Error('Multiple statements are not allowed'), { statusCode: 400 });
    }
    if (FILE_READING_FUNCTION_PATTERN.test(cleaned)) {
      throw Object.assign(new Error('File-reading SQL functions are not allowed'), {
        statusCode: 400,
      });
    }
    const banned = [
      'insert ',
      'update ',
      'delete ',
      'drop ',
      'truncate ',
      'alter ',
      'create ',
      'attach ',
      'detach ',
      'copy ',
      'export ',
      'pragma ',
      'install ',
      'load ',
    ];
    for (const k of banned) {
      if (cleaned.startsWith(k) || cleaned.includes(` ${k}`)) {
        throw Object.assign(new Error(`Statement type "${k.trim()}" is not allowed`), {
          statusCode: 400,
        });
      }
    }
  }
}

import { promises as fs } from 'node:fs';
import * as path from 'node:path';

/**
 * Lazy DuckDB driver. We dynamically import @duckdb/node-api so the workspace-service
 * still boots and `tsc` succeeds when the native binary is not installed (the routes
 * surface a 503 with an install hint instead of crashing the service).
 */

export type DuckDbColumn = { name: string; type: string };

export interface DuckDbConnection {
  run(sql: string, params?: unknown[]): Promise<void>;
  all(sql: string, params?: unknown[]): Promise<{ columns: DuckDbColumn[]; rows: unknown[][] }>;
  close(): Promise<void>;
}

let driverModule: any | null = null;
let driverError: string | null = null;

async function loadDriver(): Promise<any> {
  if (driverModule) return driverModule;
  if (driverError) throw new Error(driverError);
  try {
    // Indirect specifier prevents TS from resolving the module at build time so the
    // service compiles even when the optional native dependency isn't installed.
    const specifier = '@duckdb/node-api';
    const mod = await (Function('s', 'return import(s)') as (s: string) => Promise<any>)(specifier);
    driverModule = mod;
    return mod;
  } catch (err) {
    driverError = `DuckDB native binding not available. Install with "pnpm --filter @pcp/workspace-service add @duckdb/node-api". Original error: ${(err as Error).message}`;
    throw new Error(driverError);
  }
}

export function isDuckDbAvailable(): boolean {
  return driverError === null;
}

export class DuckDb {
  private dbPath: string;

  constructor(dbPath: string) {
    this.dbPath = dbPath;
  }

  async connect(): Promise<DuckDbConnection> {
    await fs.mkdir(path.dirname(this.dbPath), { recursive: true });
    const mod = await loadDriver();
    const instance = await mod.DuckDBInstance.create(this.dbPath);
    const conn = await instance.connect();

    return {
      async run(sql: string, params: unknown[] = []) {
        if (params.length === 0) {
          await conn.run(sql);
        } else {
          const prepared = await conn.prepare(sql);
          for (let i = 0; i < params.length; i++) {
            prepared.bind(i + 1, params[i]);
          }
          await prepared.run();
        }
      },
      async all(sql: string, params: unknown[] = []) {
        const reader = params.length === 0 ? await conn.runAndReadAll(sql) : await runPrepared(conn, sql, params);
        const cols = reader.columnNames();
        const types = reader.columnTypes().map((t: any) => String(t?.toString?.() ?? t));
        const rows = reader.getRowsJson();
        const columns: DuckDbColumn[] = cols.map((name: string, i: number) => ({
          name,
          type: types[i] ?? 'UNKNOWN',
        }));
        return { columns, rows: rows as unknown[][] };
      },
      async close() {
        await conn.disconnectSync?.();
        await instance.disconnectSync?.();
      },
    };
  }
}

async function runPrepared(conn: any, sql: string, params: unknown[]) {
  const prepared = await conn.prepare(sql);
  for (let i = 0; i < params.length; i++) {
    prepared.bind(i + 1, params[i]);
  }
  return prepared.runAndReadAll();
}

/** Sanitize a name so it is a safe DuckDB identifier (letters/digits/underscore, 1-120). */
export function sanitizeTableName(input: string): string {
  const base = input
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 100);
  if (!base) return `t_${Date.now()}`;
  // DuckDB identifiers can't start with a digit unsafely without quoting; prefix.
  return /^[a-z]/.test(base) ? base : `t_${base}`;
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { createSnapshotSchema, snapshotResponseSchema, sendApiError } from '@pcp/shared';
import { WorkspaceService } from '../service';
import { db } from '@pcp/db/src/client';
import { auditLogs } from '@pcp/db/src/schema';

async function emitAudit(
  fastify: FastifyInstance,
  userId: string | null,
  action: string,
  details: Record<string, unknown>,
): Promise<void> {
  try {
    await db.insert(auditLogs).values({ userId, action, details });
  } catch (e) {
    fastify.log.warn({ action, err: e }, 'audit_log emit failed');
  }
}

export async function setupSnapshotRoutes(
  fastify: FastifyInstance,
  workspaceService: WorkspaceService,
) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();

  server.post(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: createSnapshotSchema.omit({ workspaceId: true }),
        response: {
          201: snapshotResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshot = await workspaceService.createSnapshot(
        request.params.id,
        userId,
        request.body.name,
        request.body.description,
      );

      return reply.code(201).send(snapshot);
    },
  );

  server.get(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        response: {
          200: z.object({
            snapshots: z.array(snapshotResponseSchema),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshots = await workspaceService.getSnapshots(request.params.id, userId);
      return { snapshots };
    },
  );

  server.post(
    '/snapshots/:id/restore',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const result = await workspaceService.restoreSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_RESTORE', { snapshotId: request.params.id });
      return { success: true, ...result };
    },
  );

  server.delete(
    '/snapshots/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await workspaceService.deleteSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_DELETE', { snapshotId: request.params.id });
      return { success: true };
    },
  );
}

import { z } from 'zod';
import { resolveProductionValue, resolveSecret } from '@pcp/shared';

const rawEnv = {
  ...process.env,
  COOKIE_SECRET: process.env.COOKIE_SECRET ?? process.env.SESSION_SECRET,
};

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
  PORT: z.coerce.number().int().positive().default(3003),
  DATABASE_URL: z.string().url().optional(),
  COOKIE_SECRET: z.string().optional(),
  INTERNAL_SERVICE_TOKEN: z.string().optional(),
  WORKSPACE_HOST_ROOT: z.string().default('/var/lib/pcp/workspaces'),
  WORKSPACE_SERVICE_URL: z.string().url().default('http://localhost:3002'),
  RUNTIME_SECCOMP_PROFILE: z.string().optional(),
  RUNTIME_APPARMOR_PROFILE: z.string().optional(),
  RUNTIME_TERMINAL_ENABLED: z
    .string()
    .optional()
    .transform((value) => (value === undefined ? undefined : value === '1' || value === 'true')),
});

const parsed = envSchema.parse(rawEnv);
const ctx = { isProduction: parsed.NODE_ENV === 'production' };

export const env = {
  NODE_ENV: parsed.NODE_ENV,
  PORT: parsed.PORT,
  DATABASE_URL: resolveProductionValue(ctx, 'DATABASE_URL', parsed.DATABASE_URL),
  COOKIE_SECRET: resolveSecret(ctx, 'COOKIE_SECRET', parsed.COOKIE_SECRET, 32),
  INTERNAL_SERVICE_TOKEN: resolveSecret(
    ctx,
    'INTERNAL_SERVICE_TOKEN',
    parsed.INTERNAL_SERVICE_TOKEN,
    32,
  ),
  WORKSPACE_HOST_ROOT: parsed.WORKSPACE_HOST_ROOT,
  WORKSPACE_SERVICE_URL: parsed.WORKSPACE_SERVICE_URL,
  RUNTIME_SECCOMP_PROFILE: parsed.RUNTIME_SECCOMP_PROFILE,
  RUNTIME_APPARMOR_PROFILE: parsed.RUNTIME_APPARMOR_PROFILE,
  RUNTIME_TERMINAL_ENABLED:
    parsed.RUNTIME_TERMINAL_ENABLED ?? parsed.NODE_ENV !== 'production',
};

import Fastify from 'fastify';
import { serializerCompiler, validatorCompiler } from 'fastify-type-provider-zod';
import cookie from '@fastify/cookie';
import cors from '@fastify/cors';
import rateLimit from '@fastify/rate-limit';
import websocket from '@fastify/websocket';
import {
  createApiErrorHandler,
  createCorsOptions,
  createCorrelationIdGenerator,
  registerObservability,
} from '@pcp/shared';
import { setupRuntimeRoutes } from './routes';
import { env } from './env';

const server = Fastify({
  genReqId: createCorrelationIdGenerator(),
  logger: {
    transport:
      env.NODE_ENV === 'development'
        ? {
            target: 'pino-pretty',
            options: {
              translateTime: 'HH:MM:ss Z',
              ignore: 'pid,hostname',
            },
          }
        : undefined,
  },
});

server.setValidatorCompiler(validatorCompiler);
server.setSerializerCompiler(serializerCompiler);

server.setErrorHandler(createApiErrorHandler());
registerObservability(server, { serviceName: 'runtime' });

server.addHook('onRequest', (request, reply, done) => {
  reply.header('x-correlation-id', request.id);
  done();
});

server.register(cors, {
  ...createCorsOptions(env.NODE_ENV),
});

server.register(rateLimit, { max: 100, timeWindow: '1 minute' });

server.register(cookie, {
  secret: env.COOKIE_SECRET,
  hook: 'onRequest',
});

server.register(websocket);

server.get('/health', async () => {
  return { status: 'ok', service: 'runtime' };
});

server.register(setupRuntimeRoutes, { prefix: '/api' });

const start = async () => {
  try {
    await server.listen({ port: env.PORT, host: '0.0.0.0' });
    server.log.info(`Runtime service running on port ${env.PORT}`);
  } catch (err) {
    server.log.error(err);
    process.exit(1);
  }
};

start();

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { createRuntimeSchema, execCommandSchema, runtimeResponseSchema, sendApiError } from '@pcp/shared';
import { RuntimeService } from './service';
import { z } from 'zod';
import { env } from './env';
import type { FastifyRequest } from 'fastify';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';

type RuntimeTerminalParams = {
  id: string;
};

export async function setupRuntimeRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const runtimeService = new RuntimeService(fastify.log);

  async function getAuthenticatedUserId(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  server.post(
    '/runtimes',
    {
      schema: {
        body: createRuntimeSchema,
        response: {
          201: runtimeResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { workspaceId, image, options } = request.body;
      const runtime = await runtimeService.createRuntime(userId, workspaceId, image, options);
      return reply.code(201).send(runtime);
    }
  );

  server.post(
    '/runtimes/:id/start',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await runtimeService.startRuntime(request.params.id, userId);
      return { success: true };
    }
  );

  server.post(
    '/runtimes/:id/stop',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await runtimeService.stopRuntime(request.params.id, userId);
      return { success: true };
    }
  );

  server.post(
    '/runtimes/:id/exec',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: execCommandSchema,
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const result = await runtimeService.execCommand(request.params.id, userId, request.body.command);
      return result;
    }
  );

  server.delete(
    '/runtimes/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await runtimeService.deleteRuntime(request.params.id, userId);
      return { success: true };
    }
  );

  // Find-or-create a running runtime for a workspace.
  server.post(
    '/runtimes/ensure',
    {
      schema: {
        body: z.object({
          workspaceId: z.string().uuid(),
          image: z.string().default('node:20-alpine'),
          options: z
            .object({
              cpu: z.number().optional(),
              memory: z.number().optional(),
              env: z.record(z.string()).optional(),
            })
            .optional(),
        }),
        response: {
          200: runtimeResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { workspaceId, image, options } = request.body;
      const runtime = await runtimeService.ensureRuntimeForWorkspace(
        userId,
        workspaceId,
        image,
        options ?? {},
      );
      return runtime;
    },
  );

  // WebSocket Terminal
  server.get(
    '/runtimes/:id/terminal',
    { websocket: true },
    async (connection, request) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) {
        connection.socket.send(JSON.stringify({ error: 'Unauthorized' }));
        connection.socket.close();
        return;
      }

      const { id } = request.params as RuntimeTerminalParams;
      try {
        const stream = await runtimeService.attachTerminal(id, userId);
        
        // Pipe stream to socket
        stream.on('data', (data) => {
          connection.socket.send(data.toString());
        });

        connection.socket.on('message', (message: Buffer) => {
          stream.write(message.toString());
        });

        connection.socket.on('close', () => {
          stream.end();
        });

        stream.on('end', () => {
          connection.socket.close();
        });

        stream.on('error', (err) => {
          request.log.error(err, 'Terminal stream error');
          connection.socket.close();
        });
      } catch (err) {
        request.log.error(err, 'Failed to attach terminal');
        connection.socket.send(JSON.stringify({ error: 'Failed to attach terminal' }));
        connection.socket.close();
      }
    }
  );
}

import { db } from '@pcp/db/src/client';
import { runtimes, runtimeLogs, runtimeEvents, workspaces } from '@pcp/db/src/schema';
import {
  validateSessionUserId,
  verifyUserExists as verifySharedUserExists,
} from '@pcp/db/src/session';
import { eq, and, isNull, desc, ne } from 'drizzle-orm';
import { mkdir, writeFile, readFile, readdir, stat } from 'node:fs/promises';
import { join, relative, resolve, dirname, sep } from 'node:path';
import { DockerProvider } from './provider/docker';
import { RuntimeProvider } from './provider/types';
import { env } from './env';
import { WorkspaceClient } from './workspaceClient';
import {
  assertRuntimeCommandAllowed,
  assertRuntimeImageAllowed,
  RUNTIME_COMMAND_POLICY,
} from './policy';

const SYNC_IGNORE_DIRS = new Set(['node_modules', '.git', '.cache', 'dist', '.next', '.venv']);
const SYNC_BACK_MAX_BYTES = 512 * 1024;

export class RuntimeService {
  private provider: RuntimeProvider;
  private workspaceClient: WorkspaceClient;

  constructor(private logger: any) {
    this.provider = new DockerProvider();
    this.workspaceClient = new WorkspaceClient();
    this.logger.info('RuntimeService initialized');
  }

  async validateUserFromCookie(sessionId: string): Promise<string | null> {
    return validateSessionUserId(sessionId);
  }

  async verifyUserExists(userId: string): Promise<string | null> {
    if (!userId) return null;
    return verifySharedUserExists(userId);
  }

  private async resolveWorkspaceHostPath(userId: string, workspaceId: string): Promise<string> {
    const root = env.WORKSPACE_HOST_ROOT;
    const dir = join(root, userId, workspaceId);
    try {
      await mkdir(dir, { recursive: true });
    } catch (err) {
      this.logger.warn({ err, dir }, 'Failed to ensure workspace host directory');
    }
    return dir;
  }

  async createRuntime(userId: string, workspaceId: string, image: string, options: any) {
    await this.assertWorkspaceOwned(workspaceId, userId);
    assertRuntimeImageAllowed(image);

    const [runtime] = await db
      .insert(runtimes)
      .values({
        userId,
        workspaceId,
        image,
        options,
        status: 'pending',
      })
      .returning();

    if (!runtime) throw new Error('Failed to create runtime record');

    const hostWorkspacePath = await this.resolveWorkspaceHostPath(userId, workspaceId);

    let containerId: string;
    try {
      containerId = await this.provider.create(image, {
        ...options,
        workspacePath: hostWorkspacePath,
        labels: {
          ...(options?.labels ?? {}),
          'pcp.service': 'runtime',
          'pcp.userId': userId,
          'pcp.workspaceId': workspaceId,
          'pcp.runtimeId': runtime.id,
        },
      });
    } catch (err) {
      // Trace 13 (#13m): a Docker provisioning failure used to leave the
      // runtime row pinned at status='pending' forever, requiring manual
      // database cleanup. Mark the row failed and emit an event so listings,
      // health probes, and the operator UI can move on.
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(
        { err, runtimeId: runtime.id, userId, workspaceId, image },
        'Docker provisioning failed; marking runtime failed',
      );
      await db
        .update(runtimes)
        .set({ status: 'failed', updatedAt: new Date() })
        .where(and(eq(runtimes.id, runtime.id), eq(runtimes.userId, userId)));
      await db.insert(runtimeEvents).values({
        runtimeId: runtime.id,
        type: 'failed',
        payload: { stage: 'create', error: message },
      });
      throw err;
    }

    await db
      .update(runtimes)
      .set({ containerId })
      .where(and(eq(runtimes.id, runtime.id), eq(runtimes.userId, userId)));

    await db.insert(runtimeEvents).values({
      runtimeId: runtime.id,
      type: 'create',
      payload: { containerId, options },
    });

    return { ...runtime, containerId };
  }

  private async assertWorkspaceOwned(workspaceId: string, userId: string) {
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });

    if (!workspace) {
      throw new Error('Workspace not found');
    }
  }

  async startRuntime(runtimeId: string, userId: string) {
    const runtime = await this.getRuntime(runtimeId, userId);
    if (!runtime || !runtime.containerId) throw new Error('Runtime or container not found');

    await this.provider.start(runtime.containerId);

    await db
      .update(runtimes)
      .set({ status: 'running', lastStartedAt: new Date() })
      .where(and(eq(runtimes.id, runtimeId), eq(runtimes.userId, userId)));

    await db.insert(runtimeEvents).values({
      runtimeId,
      type: 'start',
    });
  }

  async stopRuntime(runtimeId: string, userId: string) {
    const runtime = await this.getRuntime(runtimeId, userId);
    if (!runtime || !runtime.containerId) throw new Error('Runtime or container not found');

    await this.provider.stop(runtime.containerId);

    await db
      .update(runtimes)
      .set({ status: 'stopped', lastStoppedAt: new Date() })
      .where(and(eq(runtimes.id, runtimeId), eq(runtimes.userId, userId)));

    await db.insert(runtimeEvents).values({
      runtimeId,
      type: 'stop',
    });
  }

  async execCommand(runtimeId: string, userId: string, command: string[]) {
    const runtime = await this.getRuntime(runtimeId, userId);
    if (!runtime || !runtime.containerId || runtime.status !== 'running') {
      throw new Error('Runtime not running or container not found');
    }

    assertRuntimeCommandAllowed(command);

    // Sync workspace files into the host-mounted directory so the container sees
    // the latest content. Failures here are logged but non-fatal.
    const hostPath = await this.resolveWorkspaceHostPath(userId, runtime.workspaceId);
    await this.materializeWorkspace(userId, runtime.workspaceId, hostPath);

    const result = await this.provider.exec(runtime.containerId, command, {
      timeoutMs: RUNTIME_COMMAND_POLICY.timeoutMs,
    });

    // After exec, push any small text files back to the workspace so that
    // outputs (e.g. generated build artifacts under the workspace root) become
    // visible to the agent's read_file tool. Best-effort; failures are logged.
    await this.syncBackWorkspace(userId, runtime.workspaceId, hostPath);

    await db.insert(runtimeLogs).values({
      runtimeId,
      stream: 'stdout',
      content: result.stdout,
    });

    if (result.stderr) {
      await db.insert(runtimeLogs).values({
        runtimeId,
        stream: 'stderr',
        content: result.stderr,
      });
    }

    await db.insert(runtimeEvents).values({
      runtimeId,
      type: 'exec',
      payload: { command, exitCode: result.exitCode },
    });

    return result;
  }

  async attachTerminal(runtimeId: string, userId: string) {
    if (!env.RUNTIME_TERMINAL_ENABLED) {
      throw Object.assign(new Error('Runtime terminal is disabled'), { statusCode: 403 });
    }

    const runtime = await this.getRuntime(runtimeId, userId);
    if (!runtime || !runtime.containerId || runtime.status !== 'running') {
      throw new Error('Runtime not running or container not found');
    }

    return this.provider.attach(runtime.containerId);
  }

  async deleteRuntime(runtimeId: string, userId: string) {
    const runtime = await this.getRuntime(runtimeId, userId);
    if (!runtime || !runtime.containerId) throw new Error('Runtime or container not found');

    await this.provider.destroy(runtime.containerId);
    await db.delete(runtimes).where(and(eq(runtimes.id, runtimeId), eq(runtimes.userId, userId)));
  }

  private async getRuntime(runtimeId: string, userId: string) {
    return db.query.runtimes.findFirst({
      where: and(eq(runtimes.id, runtimeId), eq(runtimes.userId, userId)),
    });
  }

  async findActiveRuntimeForWorkspace(workspaceId: string, userId: string) {
    await this.assertWorkspaceOwned(workspaceId, userId);
    return db.query.runtimes.findFirst({
      where: and(
        eq(runtimes.userId, userId),
        eq(runtimes.workspaceId, workspaceId),
        ne(runtimes.status, 'destroyed'),
      ),
      orderBy: [desc(runtimes.createdAt)],
    });
  }

  /**
   * Find or create a running runtime for the given workspace.
   * Used by the agent service to ensure run_command has an execution target.
   */
  async ensureRuntimeForWorkspace(
    userId: string,
    workspaceId: string,
    image: string,
    options: any = {},
  ) {
    const existing = await this.findActiveRuntimeForWorkspace(workspaceId, userId);
    if (existing) {
      if (existing.status !== 'running') {
        try {
          await this.startRuntime(existing.id, userId);
        } catch (err) {
          this.logger.warn(
            { err, runtimeId: existing.id },
            'Failed to restart existing runtime; creating new one',
          );
          // Fall through to create new
        }
      }
      const refreshed = await this.getRuntime(existing.id, userId);
      if (refreshed && refreshed.status === 'running') return refreshed;
    }

    const created = await this.createRuntime(userId, workspaceId, image, options);
    await this.startRuntime(created.id, userId);
    const hostPath = await this.resolveWorkspaceHostPath(userId, workspaceId);
    await this.materializeWorkspace(userId, workspaceId, hostPath);
    return (await this.getRuntime(created.id, userId))!;
  }

  /**
   * Fetches the workspace sync manifest and writes every file/directory into
   * `hostPath`. Used to keep the container's `/workspace` mount aligned with
   * the canonical S3-backed workspace state. Best-effort: errors are logged
   * but do not prevent the exec from running (the container will simply see
   * stale or missing files).
   */
  async materializeWorkspace(userId: string, workspaceId: string, hostPath: string): Promise<void> {
    let manifest: Awaited<ReturnType<WorkspaceClient['getSyncManifest']>>;
    try {
      manifest = await this.workspaceClient.getSyncManifest(userId, workspaceId);
    } catch (err) {
      this.logger.warn({ err, workspaceId }, 'Failed to fetch workspace sync manifest');
      return;
    }

    const rootResolved = resolve(hostPath);

    // Sort so directories are created before nested files.
    const entries = [...manifest.files].sort((a, b) => a.path.length - b.path.length);

    for (const entry of entries) {
      const safeRel = entry.path.replace(/^\/+/, '');
      const target = resolve(hostPath, safeRel);
      // Defense in depth: refuse paths that escape the host root.
      if (target !== rootResolved && !target.startsWith(rootResolved + sep)) {
        this.logger.warn({ path: entry.path }, 'Skipping unsafe path during materialize');
        continue;
      }
      try {
        if (entry.isDirectory) {
          await mkdir(target, { recursive: true });
        } else {
          await mkdir(dirname(target), { recursive: true });
          const buf = entry.contentBase64
            ? Buffer.from(entry.contentBase64, 'base64')
            : Buffer.alloc(0);
          await writeFile(target, buf);
        }
      } catch (err) {
        this.logger.warn({ err, path: entry.path }, 'Failed to materialize workspace entry');
      }
    }
  }

  /**
   * After an exec, scan the host-mounted workspace directory and push small
   * text files whose content has changed (or that are new) back to the
   * canonical workspace storage. Skips heavyweight directories such as
   * `node_modules` and `.git` to avoid unbounded uploads. Best-effort.
   */
  async syncBackWorkspace(userId: string, workspaceId: string, hostPath: string): Promise<void> {
    let manifest: Awaited<ReturnType<WorkspaceClient['getSyncManifest']>>;
    try {
      manifest = await this.workspaceClient.getSyncManifest(userId, workspaceId);
    } catch (err) {
      this.logger.warn({ err, workspaceId }, 'Failed to fetch manifest for sync-back');
      return;
    }

    const known = new Map<string, { size: number; contentBase64: string | null }>();
    for (const entry of manifest.files) {
      if (!entry.isDirectory) {
        known.set(entry.path, { size: entry.size, contentBase64: entry.contentBase64 });
      }
    }

    const rootResolved = resolve(hostPath);
    const walked: string[] = [];
    try {
      await this.walkHostDir(rootResolved, rootResolved, walked);
    } catch (err) {
      this.logger.warn({ err, hostPath }, 'Failed to walk host workspace dir for sync-back');
      return;
    }

    for (const absPath of walked) {
      let st;
      try {
        st = await stat(absPath);
      } catch {
        continue;
      }
      if (!st.isFile()) continue;
      if (st.size > SYNC_BACK_MAX_BYTES) continue;

      const rel = '/' + relative(rootResolved, absPath).split(sep).join('/');
      const previous = known.get(rel);

      let buf: Buffer;
      try {
        buf = await readFile(absPath);
      } catch (err) {
        this.logger.warn({ err, path: rel }, 'Failed to read host file for sync-back');
        continue;
      }

      // Skip files that look binary (contain NUL bytes) and aren't already tracked.
      if (buf.includes(0) && !previous) continue;

      const base64 = buf.toString('base64');
      if (previous && previous.contentBase64 === base64) continue;

      try {
        await this.workspaceClient.writeFile(userId, workspaceId, rel, buf.toString('utf8'));
      } catch (err) {
        this.logger.warn({ err, path: rel }, 'Failed to sync file back to workspace');
      }
    }
  }

  private async walkHostDir(root: string, current: string, out: string[]): Promise<void> {
    let entries;
    try {
      entries = await readdir(current, { withFileTypes: true });
    } catch {
      return;
    }
    for (const entry of entries) {
      if (SYNC_IGNORE_DIRS.has(entry.name)) continue;
      const abs = join(current, entry.name);
      // Defense in depth: never escape root.
      if (!abs.startsWith(root)) continue;
      if (entry.isDirectory()) {
        await this.walkHostDir(root, abs, out);
      } else if (entry.isFile()) {
        out.push(abs);
      }
    }
  }
}

export const RUNTIME_IMAGE_ALLOWLIST = ['node:20-alpine'] as const;

type DockerSecurityProfileConfig = {
  seccompProfile?: string;
  appArmorProfile?: string;
};

const DOCKER_NO_NEW_PRIVILEGES = 'no-new-privileges:true';
const SECCOMP_PROFILE_PATTERN = /^\/?[A-Za-z0-9][A-Za-z0-9_./:-]*$/;
const APPARMOR_PROFILE_PATTERN = /^[A-Za-z0-9][A-Za-z0-9_.:-]*$/;

const BLOCKED_COMMANDS = [
  {
    category: 'destructive root deletion',
    pattern: /rm\s+-rf\s+\//,
  },
  {
    category: 'privilege escalation',
    pattern: /(?:^|\s)sudo\b/,
  },
  {
    category: 'fork bomb',
    pattern: /:\(\)\{\s*:\|:&\s*\};:/,
  },
] as const;

const MAX_COMMAND_ARGS = 64;
const MAX_COMMAND_ARG_LENGTH = 4096;

export const RUNTIME_COMMAND_POLICY = {
  timeoutMs: 60_000,
  network: 'disabled',
  blockedCategories: BLOCKED_COMMANDS.map((rule) => rule.category),
} as const;

export function assertRuntimeImageAllowed(image: string): void {
  if (!RUNTIME_IMAGE_ALLOWLIST.includes(image as (typeof RUNTIME_IMAGE_ALLOWLIST)[number])) {
    throw new Error('Runtime image is not allowed');
  }
}

export function assertRuntimeCommandAllowed(command: string[]): void {
  if (command.length === 0 || command.length > MAX_COMMAND_ARGS) {
    throw new Error('Command blocked by security policy');
  }

  if (command.some((arg) => arg.length === 0 || arg.length > MAX_COMMAND_ARG_LENGTH || /\0/.test(arg))) {
    throw new Error('Command blocked by security policy');
  }

  const commandStr = command.join(' ');
  if (BLOCKED_COMMANDS.some((rule) => rule.pattern.test(commandStr))) {
    throw new Error('Command blocked by security policy');
  }
}

export function buildRuntimeSecurityOptions(config: DockerSecurityProfileConfig = {}): string[] {
  const securityOptions = [DOCKER_NO_NEW_PRIVILEGES];
  const seccompProfile = normalizeProfileValue(
    config.seccompProfile,
    'RUNTIME_SECCOMP_PROFILE',
    SECCOMP_PROFILE_PATTERN,
  );
  const appArmorProfile = normalizeProfileValue(
    config.appArmorProfile,
    'RUNTIME_APPARMOR_PROFILE',
    APPARMOR_PROFILE_PATTERN,
  );

  if (seccompProfile) securityOptions.push(`seccomp=${seccompProfile}`);
  if (appArmorProfile) securityOptions.push(`apparmor=${appArmorProfile}`);
  return securityOptions;
}

function normalizeProfileValue(
  value: string | undefined,
  envName: string,
  pattern: RegExp,
): string | undefined {
  const trimmed = value?.trim();
  if (!trimmed) return undefined;
  if (trimmed === 'unconfined') {
    throw new Error(`${envName} must not disable confinement`);
  }
  if (trimmed.includes('..') || !pattern.test(trimmed)) {
    throw new Error(`${envName} contains invalid characters`);
  }
  return trimmed;
}

export interface RuntimeOptions {
  cpu?: number;
  memory?: number;
  env?: Record<string, string>;
  workspacePath: string;
  labels?: Record<string, string>;
}

export interface ExecResult {
  exitCode: number;
  stdout: string;
  stderr: string;
}

export interface RuntimeExecOptions {
  timeoutMs?: number;
}

export class RuntimeExecTimeoutError extends Error {
  statusCode = 408;

  constructor(timeoutMs: number) {
    super(`Command execution timed out after ${Math.round(timeoutMs / 1000)} seconds`);
    this.name = 'RuntimeExecTimeoutError';
  }
}

export interface RuntimeProvider {
  create(image: string, options: RuntimeOptions): Promise<string>;
  start(id: string): Promise<void>;
  stop(id: string): Promise<void>;
  destroy(id: string): Promise<void>;
  exec(id: string, command: string[], options?: RuntimeExecOptions): Promise<ExecResult>;
  attach(id: string): Promise<NodeJS.ReadWriteStream>;
  getStatus(id: string): Promise<string>;
}

import { env } from './env';

export interface SyncManifestEntry {
  path: string;
  isDirectory: boolean;
  size: number;
  mimeType: string | null;
  contentBase64: string | null;
}

export interface SyncManifest {
  files: SyncManifestEntry[];
}

export class WorkspaceClientError extends Error {
  constructor(
    message: string,
    public statusCode: number,
  ) {
    super(message);
    this.name = 'WorkspaceClientError';
  }
}

/**
 * Minimal HTTP client for the workspace service. Authenticates with the shared
 * INTERNAL_SERVICE_TOKEN + acting user id.
 */
export class WorkspaceClient {
  private readonly baseUrl: string;

  constructor(baseUrl?: string) {
    this.baseUrl = (baseUrl ?? env.WORKSPACE_SERVICE_URL).replace(/\/+$/, '');
  }

  async getSyncManifest(
    userId: string,
    workspaceId: string,
    opts: { maxInlineBytes?: number } = {},
  ): Promise<SyncManifest> {
    const url = new URL(`${this.baseUrl}/workspaces/${workspaceId}/sync/manifest`);
    if (opts.maxInlineBytes != null) {
      url.searchParams.set('maxInlineBytes', String(opts.maxInlineBytes));
    }
    const res = await fetch(url, {
      method: 'GET',
      headers: {
        Authorization: `Bearer ${env.INTERNAL_SERVICE_TOKEN}`,
        'X-User-Id': userId,
      },
    });
    if (!res.ok) {
      const text = await res.text().catch(() => '');
      throw new WorkspaceClientError(
        `workspace ${res.status}: ${text || res.statusText}`,
        res.status,
      );
    }
    return (await res.json()) as SyncManifest;
  }

  async writeFile(
    userId: string,
    workspaceId: string,
    filePath: string,
    content: string,
    mimeType = 'text/plain',
  ): Promise<{ bytesWritten: number; path: string }> {
    const res = await fetch(`${this.baseUrl}/workspaces/${workspaceId}/files/write`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${env.INTERNAL_SERVICE_TOKEN}`,
        'X-User-Id': userId,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ path: filePath, content, mimeType }),
    });
    if (!res.ok) {
      const text = await res.text().catch(() => '');
      throw new WorkspaceClientError(
        `workspace ${res.status}: ${text || res.statusText}`,
        res.status,
      );
    }
    return (await res.json()) as { bytesWritten: number; path: string };
  }
}

import Docker from 'dockerode';
import { Writable } from 'node:stream';
import {
  RuntimeExecOptions,
  RuntimeExecTimeoutError,
  RuntimeProvider,
  RuntimeOptions,
  ExecResult,
} from './types';
import { env } from '../env';
import { buildRuntimeSecurityOptions } from '../policy';

const DEFAULT_CPU = 1;
const MAX_CPU = 4;
const DEFAULT_MEMORY_MB = 512;
const MAX_MEMORY_MB = 4096;
const ENV_NAME_PATTERN = /^[A-Za-z_][A-Za-z0-9_]*$/;

export class DockerProvider implements RuntimeProvider {
  private docker: Docker;

  constructor() {
    this.docker = new Docker();
  }

  async create(image: string, options: RuntimeOptions): Promise<string> {
    const memoryMb = clampLimit(options.memory, DEFAULT_MEMORY_MB, MAX_MEMORY_MB);
    const cpu = clampLimit(options.cpu, DEFAULT_CPU, MAX_CPU);

    const container = await this.docker.createContainer({
      Image: image,
      User: '1000:1000',
      Labels: options.labels,
      HostConfig: {
        Binds: [`${options.workspacePath}:/workspace`],
        Memory: memoryMb * 1024 * 1024,
        MemorySwap: memoryMb * 1024 * 1024,
        // Docker expects NanoCpus as an integer; round to preserve the requested
        // CPU allocation despite floating-point imprecision in `cpu * 1e9`.
        NanoCpus: Math.round(cpu * 1e9),
        NetworkMode: 'none', // Default security: no network
        ReadonlyRootfs: true,
        Privileged: false,
        Init: true,
        OomKillDisable: false,
        CapDrop: ['ALL'],
        PidsLimit: 100,
        SecurityOpt: buildRuntimeSecurityOptions({
          seccompProfile: env.RUNTIME_SECCOMP_PROFILE,
          appArmorProfile: env.RUNTIME_APPARMOR_PROFILE,
        }),
        Tmpfs: {
          '/tmp': 'rw,noexec,nosuid,size=100m',
        },
        Ulimits: [{ Name: 'nofile', Soft: 1024, Hard: 1024 }],
      },
      Env: toSafeEnv(options.env),
      WorkingDir: '/workspace',
      Tty: true,
      Cmd: ['/bin/sh'],
    });

    return container.id;
  }

  async start(id: string): Promise<void> {
    const container = this.docker.getContainer(id);
    await container.start();
  }

  async stop(id: string): Promise<void> {
    const container = this.docker.getContainer(id);
    await container.stop();
  }

  async destroy(id: string): Promise<void> {
    const container = this.docker.getContainer(id);
    try {
      await container.stop();
    } catch (e) {}
    await container.remove();
  }

  async exec(id: string, command: string[], options: RuntimeExecOptions = {}): Promise<ExecResult> {
    const container = this.docker.getContainer(id);
    const exec = await container.exec({
      Cmd: command,
      User: '1000:1000',
      WorkingDir: '/workspace',
      AttachStdout: true,
      AttachStderr: true,
    });

    const stream = await exec.start({});

    return new Promise((resolve, reject) => {
      let stdout = '';
      let stderr = '';
      let settled = false;

      const timeout = options.timeoutMs
        ? setTimeout(() => {
            if (settled) return;
            settled = true;
            stream.destroy?.();
            container.kill().catch(() => undefined);
            reject(new RuntimeExecTimeoutError(options.timeoutMs ?? 0));
          }, options.timeoutMs)
        : undefined;

      const finish = (callback: () => void) => {
        if (settled) return;
        settled = true;
        if (timeout) clearTimeout(timeout);
        callback();
      };

      const stdoutSink = new Writable({
        write(chunk, _encoding, callback) {
          stdout += chunk.toString();
          callback();
        },
      });

      const stderrSink = new Writable({
        write(chunk, _encoding, callback) {
          stderr += chunk.toString();
          callback();
        },
      });

      container.modem.demuxStream(
        stream,
        stdoutSink,
        stderrSink,
      );

      stream.on('end', async () => {
        finish(async () => {
          try {
            const status = await exec.inspect();
            resolve({
              exitCode: status.ExitCode || 0,
              stdout,
              stderr,
            });
          } catch (err) {
            reject(err);
          }
        });
      });

      stream.on('error', (err) => {
        finish(() => reject(err));
      });
    });
  }

  async attach(id: string): Promise<NodeJS.ReadWriteStream> {
    const container = this.docker.getContainer(id);
    const exec = await container.exec({
      Cmd: ['/bin/sh'],
      User: '1000:1000',
      WorkingDir: '/workspace',
      AttachStdin: true,
      AttachStdout: true,
      AttachStderr: true,
      Tty: true,
    });
    const stream = await exec.start({
      stdin: true,
      Tty: true,
    });
    return stream;
  }

  async getStatus(id: string): Promise<string> {
    const container = this.docker.getContainer(id);
    const data = await container.inspect();
    return data.State.Status;
  }
}

function clampLimit(value: number | undefined, defaultValue: number, max: number): number {
  if (value === undefined || !Number.isFinite(value) || value <= 0) {
    return defaultValue;
  }

  return Math.min(value, max);
}

function toSafeEnv(env: Record<string, string> | undefined): string[] {
  return Object.entries(env || {})
    .filter(([key]) => ENV_NAME_PATTERN.test(key))
    .map(([key, value]) => `${key}=${value}`);
}

