import { z } from 'zod';
import { ToolDefinition } from '../llm/types';
import { WorkspaceClient } from '../clients/workspace';
import { RuntimeClient } from '../clients/runtime';
import { MemoryClient } from '../clients/memory';

export interface ToolContext {
  userId: string;
  workspaceId: string;
  taskId: string;
  /** Optional logger for tools to emit warnings/errors. */
  logger?: { info: (...args: any[]) => void; warn: (...args: any[]) => void; error: (...args: any[]) => void };
  /** Shared HTTP clients injected by the orchestrator. */
  clients: {
    workspace: WorkspaceClient;
    runtime: RuntimeClient;
    memory: MemoryClient;
  };
  /** Cached runtime id for the current task to avoid repeated `ensure` calls. */
  runtimeId?: string;
}

export interface Tool<TInput = any, TOutput = any> {
  name: string;
  description: string;
  schema: z.ZodType<TInput>;
  requiresApproval: boolean;
  execute(input: TInput, context: ToolContext): Promise<TOutput>;
  getDefinition(): ToolDefinition;
}

export class ToolRegistry {
  private tools: Map<string, Tool> = new Map();

  register(tool: Tool) {
    this.tools.set(tool.name, tool);
  }

  get(name: string): Tool | undefined {
    return this.tools.get(name);
  }

  getAllDefinitions(): ToolDefinition[] {
    return Array.from(this.tools.values()).map((t) => t.getDefinition());
  }

  /**
   * Validate and execute a tool. Throws if the tool requires approval — callers must use
   * `executeApproved` after the user has approved the call.
   */
  async execute(name: string, inputStr: string, context: ToolContext): Promise<any> {
    const tool = this.get(name);
    if (!tool) throw new Error(`Tool not found: ${name}`);

    const input = JSON.parse(inputStr);
    const validatedInput = tool.schema.parse(input);

    if (tool.requiresApproval) {
      throw new Error(`Tool requires approval: ${name}`);
    }

    return await tool.execute(validatedInput, context);
  }

  /**
   * Execute a tool whose approval has already been granted by the user.
   * Skips the requiresApproval check but still validates input against the schema.
   */
  async executeApproved(name: string, inputStr: string, context: ToolContext): Promise<any> {
    const tool = this.get(name);
    if (!tool) throw new Error(`Tool not found: ${name}`);

    const input = JSON.parse(inputStr);
    const validatedInput = tool.schema.parse(input);

    return await tool.execute(validatedInput, context);
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';

const MAX_OUTPUT_BYTES = 32 * 1024;

export const RUN_COMMAND_POLICY = {
  approvalRequired: true,
  timeoutMs: 60_000,
  network: 'disabled',
  outputLimitBytes: MAX_OUTPUT_BYTES,
  blockedCategories: ['destructive root deletion', 'privilege escalation', 'fork bomb'],
} as const;

function trim(value: string): string {
  if (value.length <= MAX_OUTPUT_BYTES) return value;
  return `${value.slice(0, MAX_OUTPUT_BYTES)}\n[truncated: ${value.length - MAX_OUTPUT_BYTES} more bytes]`;
}

function formatPolicyDescription(): string {
  return [
    'Approval required',
    `${RUN_COMMAND_POLICY.timeoutMs / 1000}s timeout`,
    `network ${RUN_COMMAND_POLICY.network}`,
    `output truncated to ${RUN_COMMAND_POLICY.outputLimitBytes / 1024}KB`,
    `blocked: ${RUN_COMMAND_POLICY.blockedCategories.join(', ')}`,
  ].join('; ');
}

export class RunCommandTool implements Tool<{ command: string }, string> {
  name = 'run_command';
  description = `Run a shell command inside the workspace runtime container (sh -c). ${formatPolicyDescription()}.`;
  requiresApproval = true;
  schema = z.object({
    command: z.string().min(1).describe('Shell command to run, e.g. "node -v"'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          command: { type: 'string', description: 'Shell command to run' },
        },
        required: ['command'],
      },
    };
  }

  async execute(input: { command: string }, context: ToolContext): Promise<string> {
    try {
      let runtimeId = context.runtimeId;
      if (!runtimeId) {
        const runtime = await context.clients.runtime.ensureForWorkspace(
          context.userId,
          context.workspaceId,
        );
        runtimeId = runtime.id;
        context.runtimeId = runtimeId;
      }

      const result = await context.clients.runtime.exec(context.userId, runtimeId, [
        '/bin/sh',
        '-c',
        input.command,
      ]);
      const parts: string[] = [];
      parts.push(`exit=${result.exitCode}`);
      if (result.stdout) parts.push(`stdout:\n${trim(result.stdout)}`);
      if (result.stderr) parts.push(`stderr:\n${trim(result.stderr)}`);
      return parts.join('\n\n');
    } catch (err: any) {
      const status = err?.status ?? 'unknown';
      return `Error running command (status=${status}): ${err?.message ?? String(err)}`;
    }
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';

const MAX_BYTES = 64 * 1024;

export class ReadFileTool implements Tool<{ path: string }, string> {
  name = 'read_file';
  description = 'Read a UTF-8 text file from the current workspace and return its contents.';
  requiresApproval = false;
  schema = z.object({
    path: z.string().describe('Path to the file relative to the workspace root, e.g. /src/index.ts'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Path to the file relative to the workspace root' },
        },
        required: ['path'],
      },
    };
  }

  async execute(input: { path: string }, context: ToolContext): Promise<string> {
    try {
      const file = await context.clients.workspace.getFileContent(
        context.userId,
        context.workspaceId,
        input.path,
      );
      const content = file.content ?? '';
      if (content.length > MAX_BYTES) {
        return `${content.slice(0, MAX_BYTES)}\n[truncated: ${content.length - MAX_BYTES} more bytes]`;
      }
      return content;
    } catch (err: any) {
      const status = err?.status ?? 'unknown';
      return `Error reading ${input.path} (status=${status}): ${err?.message ?? String(err)}`;
    }
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';

export class WriteFileTool implements Tool<{ path: string; content: string; mimeType?: string }, string> {
  name = 'write_file';
  description = 'Create or overwrite a UTF-8 text file in the current workspace.';
  requiresApproval = true;
  schema = z.object({
    path: z.string().describe('Path to the file relative to the workspace root'),
    content: z.string().describe('Full text content to write'),
    mimeType: z.string().optional().describe('Optional MIME type, defaults to text/plain'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Path to the file relative to the workspace root' },
          content: { type: 'string', description: 'Full text content to write' },
          mimeType: { type: 'string', description: 'Optional MIME type, defaults to text/plain' },
        },
        required: ['path', 'content'],
      },
    };
  }

  async execute(
    input: { path: string; content: string; mimeType?: string },
    context: ToolContext,
  ): Promise<string> {
    try {
      const result = await context.clients.workspace.writeFile(
        context.userId,
        context.workspaceId,
        input.path,
        input.content,
        input.mimeType ?? 'text/plain',
      );
      return `Wrote ${result.bytesWritten} bytes to ${input.path}`;
    } catch (err: any) {
      const status = err?.status ?? 'unknown';
      return `Error writing ${input.path} (status=${status}): ${err?.message ?? String(err)}`;
    }
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';

export class ListFilesTool implements Tool<{ path: string }, string> {
  name = 'list_files';
  description = 'List immediate children (files and directories) of a directory in the workspace.';
  requiresApproval = false;
  schema = z.object({
    path: z.string().describe('Directory path relative to workspace root, e.g. / or /src'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Directory path relative to workspace root' },
        },
        required: ['path'],
      },
    };
  }

  async execute(input: { path: string }, context: ToolContext): Promise<string> {
    try {
      const files = await context.clients.workspace.listFiles(
        context.userId,
        context.workspaceId,
        input.path,
      );
      if (files.length === 0) {
        return `(empty directory: ${input.path})`;
      }
      const lines = files.map((f) => {
        const marker = f.isDirectory ? 'd' : 'f';
        const size = f.isDirectory ? '-' : `${f.size}b`;
        return `${marker} ${size}\t${f.path}`;
      });
      return `Listing of ${input.path}:\n${lines.join('\n')}`;
    } catch (err: any) {
      const status = err?.status ?? 'unknown';
      return `Error listing ${input.path} (status=${status}): ${err?.message ?? String(err)}`;
    }
  }
}

