async function ensureSession(userId: string, sessionId?: string): Promise<string> {
  if (sessionId) return sessionId;
  const created = await internalRequest<SessionDto>(env.BROWSER_SERVICE_URL, {
    userId,
    method: 'POST',
    path: '/api/browser/sessions',
  });
  return created.id;
}

