      const result = await publishService.startService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );
};

import crypto from 'crypto';
import { env } from './env';

const ALGORITHM = 'aes-256-gcm';
const ENCRYPTION_KEY = Buffer.from(env.ENCRYPTION_KEY, 'utf8');

if (ENCRYPTION_KEY.length !== 32) {
  throw new Error('ENCRYPTION_KEY must be exactly 32 bytes long');
}

const ENC_PREFIX = 'enc:';

/** Returns `enc:<iv>.<authTag>.<ciphertext>` (all base64). */
export function encryptValue(plaintext: string): string {
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  const ct = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()]);
  const tag = cipher.getAuthTag();
  return `${ENC_PREFIX}${iv.toString('base64')}.${tag.toString('base64')}.${ct.toString('base64')}`;
}

/** Decrypts a value produced by `encryptValue`. Plain (non-`enc:` prefixed) input is returned as-is. */
export function decryptValue(stored: string): string {
  if (!stored.startsWith(ENC_PREFIX)) return stored;
  const parts = stored.slice(ENC_PREFIX.length).split('.');
  if (parts.length !== 3) return '';
  const [ivB64, tagB64, ctB64] = parts as [string, string, string];
  try {
    const iv = Buffer.from(ivB64, 'base64');
    const tag = Buffer.from(tagB64, 'base64');
    const ct = Buffer.from(ctB64, 'base64');
    const decipher = crypto.createDecipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
    decipher.setAuthTag(tag);
    return Buffer.concat([decipher.update(ct), decipher.final()]).toString('utf8');
  } catch {
    return '';
  }
}

export function encryptEnvVars(envVars: Record<string, string>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const [k, v] of Object.entries(envVars)) {
    out[k] = v.startsWith(ENC_PREFIX) ? v : encryptValue(v);
  }
  return out;
}

export function decryptEnvVars(envVars: Record<string, string>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const [k, v] of Object.entries(envVars)) {
    out[k] = decryptValue(v);
  }
  return out;
}

/** Replaces every value with a fixed mask for safe client display. */
export function redactEnvVars(envVars: Record<string, string>): Record<string, string> {
  const out: Record<string, string> = {};
  for (const k of Object.keys(envVars)) out[k] = '***';
  return out;
}

import { db } from '@pcp/db/src/client';
import { hostedServices, hostedServiceLogs, workspaces, auditLogs } from '@pcp/db/src/schema';
import { eq, desc, and, isNull } from 'drizzle-orm';
import Docker from 'dockerode';
import { encryptEnvVars, decryptEnvVars, redactEnvVars } from './encryption';
import { env } from './env';
import { buildPublishSecurityOptions, resolvePublishImage } from './policy';

const ENV_NAME_PATTERN = /^[A-Za-z_][A-Za-z0-9_]*$/;
const SLUG_PATTERN = /^[a-z0-9](?:[a-z0-9-]{0,118}[a-z0-9])?$/;

type HostedServiceUpdate = Partial<{
  workspaceId: string;
  name: string;
  slug: string;
  kind: 'static' | 'vite' | 'node';
  rootPath: string;
  startCommand: string;
  envVars: Record<string, string>;
  isPublic: boolean;
  autoRestart: boolean;
  customDomain: string;
}>;

type HostedServiceRow = typeof hostedServices.$inferSelect;

export class PublishService {
  private docker: Docker;

  constructor() {
    this.docker = new Docker({ socketPath: '/var/run/docker.sock' });
  }

  async createService(data: {
    userId: string;
    workspaceId: string;
    name: string;
    slug: string;
    kind: 'static' | 'vite' | 'node';
    rootPath: string;
    startCommand?: string;
    envVars?: Record<string, string>;
    isPublic?: boolean;
    autoRestart?: boolean;
    customDomain?: string;
  }) {
    await this.assertWorkspaceOwned(data.workspaceId, data.userId);

    const rootPath = normalizeRootPath(data.rootPath);
    const slug = normalizeSlug(data.slug);
    const startCommand = normalizeStartCommand(data.startCommand);

    const [service] = await db
      .insert(hostedServices)
      .values({
        userId: data.userId,
        workspaceId: data.workspaceId,
        name: data.name,
        slug,
        kind: data.kind,
        rootPath,
        startCommand,
        envVars: encryptEnvVars(data.envVars || {}),
        isPublic: data.isPublic ?? false,
        autoRestart: data.autoRestart ?? true,
        customDomain: data.customDomain,
        status: 'stopped',
      })
      .returning();

    if (!service) throw new Error('Failed to create hosted service');
    await emitAudit(data.userId, 'HOSTED_SERVICE_CREATE', { serviceId: service.id, slug });
    return sanitize(service);
  }

  async updateService(serviceId: string, userId: string, data: HostedServiceUpdate) {
    const updates = normalizeHostedServiceUpdate(data);
    if (updates.workspaceId) {
      await this.assertWorkspaceOwned(updates.workspaceId, userId);
    }
    if (updates.envVars) {
      updates.envVars = encryptEnvVars(updates.envVars);
    }

    const [service] = await db
      .update(hostedServices)
      .set({ ...updates, updatedAt: new Date() })
      .where(and(eq(hostedServices.id, serviceId), eq(hostedServices.userId, userId)))
      .returning();

    if (!service) throw new Error('Service not found or update failed');
    await emitAudit(userId, 'HOSTED_SERVICE_UPDATE', {
      serviceId,
      fields: Object.keys(updates),
    });
    return sanitize(service);
  }

  async listServices(workspaceId: string, userId: string) {
    const rows = await db.query.hostedServices.findMany({
      where: and(eq(hostedServices.workspaceId, workspaceId), eq(hostedServices.userId, userId)),
      orderBy: [desc(hostedServices.updatedAt)],
    });
    return rows.map(sanitize);
  }

  async startService(serviceId: string, userId: string) {
    const service = await db.query.hostedServices.findFirst({
      where: and(eq(hostedServices.id, serviceId), eq(hostedServices.userId, userId)),
    });

    if (!service) throw new Error('Service not found');
    await this.assertWorkspaceOwned(service.workspaceId, userId);

    // Update status to starting
    await db
      .update(hostedServices)
      .set({ status: 'starting' })
      .where(and(eq(hostedServices.id, service.id), eq(hostedServices.userId, userId)));

    // Start asynchronously to not block the request
    this.runContainer(service).catch(console.error);
    await emitAudit(userId, 'HOSTED_SERVICE_START', { serviceId });

    return { status: 'starting' };
  }

  async stopService(serviceId: string, userId: string) {
    const service = await db.query.hostedServices.findFirst({
      where: and(eq(hostedServices.id, serviceId), eq(hostedServices.userId, userId)),
    });

    if (!service) throw new Error('Service not found');

    if (service.runnerProcessId) {
      try {
        const container = this.docker.getContainer(service.runnerProcessId);
        await container.stop();
        await container.remove();
      } catch (e) {
        console.error(`Failed to stop container ${service.runnerProcessId}`, e);
      }
    }

    await db
      .update(hostedServices)
      .set({ status: 'stopped', runnerProcessId: null })
      .where(and(eq(hostedServices.id, service.id), eq(hostedServices.userId, userId)));

    await emitAudit(userId, 'HOSTED_SERVICE_STOP', { serviceId });
    return { status: 'stopped' };
  }

  private async runContainer(service: HostedServiceRow) {
    try {
      const containerName = `hosted-${service.id}`;
      const workspaceVolume = `/tmp/workspaces/${service.userId}/${service.workspaceId}`;

      // In MVP, we just use node alpine or nginx depending on kind
      let image = resolvePublishImage(service.kind as 'static' | 'vite' | 'node');
      let cmd: string[] = [];

      if (service.kind === 'static') {
        image = resolvePublishImage('static');
      } else if (service.startCommand) {
        cmd = ['sh', '-c', normalizeStartCommand(service.startCommand) || ''];
      } else if (service.kind === 'node') {
        cmd = ['npm', 'start'];
      } else if (service.kind === 'vite') {
        cmd = ['npm', 'run', 'dev', '--', '--host'];
      }

      // We expose it on traefik
      const rootPath = normalizeRootPath(service.rootPath);
      const slug = normalizeSlug(service.slug);
      const containerPort = service.port
        ? service.port.toString()
        : service.kind === 'static'
          ? '8080'
          : '3000';

      const container = await this.docker.createContainer({
        Image: image,
        name: containerName,
        Cmd: cmd.length > 0 ? cmd : undefined,
        User: '1000:1000',
        WorkingDir: rootPath === '/' ? '/workspace' : `/workspace${rootPath}`,
        Labels: {
          'pcp.service': 'publish',
          'pcp.userId': service.userId,
          'pcp.workspaceId': service.workspaceId,
          'pcp.hostedServiceId': service.id,
          'traefik.enable': 'true',
          [`traefik.http.routers.${containerName}.rule`]: `Host(\`${slug}.apps.localhost\`)`,
          [`traefik.http.routers.${containerName}.entrypoints`]: 'web',
          [`traefik.http.services.${containerName}.loadbalancer.server.port`]: containerPort,
        },
        HostConfig: {
          NetworkMode: env.PUBLISH_DOCKER_NETWORK,
          Binds: [`${workspaceVolume}:/workspace:ro`],
          Memory: 512 * 1024 * 1024,
          MemorySwap: 512 * 1024 * 1024,
          NanoCpus: 1_000_000_000,
          ReadonlyRootfs: true,
          Privileged: false,
          Init: true,
          OomKillDisable: false,
          CapDrop: ['ALL'],
          PidsLimit: 100,
          SecurityOpt: buildPublishSecurityOptions({
            seccompProfile: env.PUBLISH_SECCOMP_PROFILE,
            appArmorProfile: env.PUBLISH_APPARMOR_PROFILE,
          }),
          Tmpfs: {
            '/tmp': 'rw,noexec,nosuid,size=100m',
          },
          Ulimits: [{ Name: 'nofile', Soft: 1024, Hard: 1024 }],
        },
        Env: toSafeEnv(decryptEnvVars(service.envVars || {})),
      });

      await container.start();

      await db
        .update(hostedServices)
        .set({
          status: 'running',
          runnerProcessId: container.id,
          publicUrl: `http://${slug}.apps.localhost`,
        })
        .where(and(eq(hostedServices.id, service.id), eq(hostedServices.userId, service.userId)));
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown publish container error';
      await db
        .update(hostedServices)
        .set({
          status: 'crashed',
          crashCount: service.crashCount + 1,
        })
        .where(and(eq(hostedServices.id, service.id), eq(hostedServices.userId, service.userId)));

      await db.insert(hostedServiceLogs).values({
        serviceId: service.id,
        stream: 'stderr',
        line: message,
      });
    }
  }

  async deleteService(serviceId: string, userId: string) {
    await this.stopService(serviceId, userId).catch(() => {});
    await db
      .delete(hostedServices)
      .where(and(eq(hostedServices.id, serviceId), eq(hostedServices.userId, userId)));
    await emitAudit(userId, 'HOSTED_SERVICE_DELETE', { serviceId });
  }

  private async assertWorkspaceOwned(workspaceId: string, userId: string) {
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });

    if (!workspace) {
      throw new Error('Workspace not found');
    }
  }
}

function normalizeHostedServiceUpdate(data: HostedServiceUpdate): HostedServiceUpdate {
  return {
    ...data,
    slug: data.slug === undefined ? undefined : normalizeSlug(data.slug),
    rootPath: data.rootPath === undefined ? undefined : normalizeRootPath(data.rootPath),
    startCommand:
      data.startCommand === undefined ? undefined : normalizeStartCommand(data.startCommand),
  };
}

function normalizeSlug(slug: string): string {
  const normalized = slug.trim().toLowerCase();
  if (!SLUG_PATTERN.test(normalized)) {
    throw new Error('Invalid hosted service slug');
  }

  return normalized;
}

function normalizeRootPath(rootPath: string): string {
  const normalized = rootPath.trim().replace(/\\/g, '/');
  if (
    !normalized ||
    normalized.includes('..') ||
    normalized.includes('\0') ||
    normalized.startsWith('~')
  ) {
    throw new Error('Invalid hosted service root path');
  }

  const withLeadingSlash = normalized.startsWith('/') ? normalized : `/${normalized}`;
  return withLeadingSlash.length > 1 ? withLeadingSlash.replace(/\/+$/, '') : '/';
}

function normalizeStartCommand(startCommand: string | null | undefined): string | undefined {
  if (!startCommand) return undefined;
  const normalized = startCommand.trim();
  if (!normalized || /[\r\n\0]/.test(normalized)) {
    throw new Error('Invalid hosted service start command');
  }

  return normalized;
}

function toSafeEnv(env: Record<string, string> | null | undefined): string[] {
  return Object.entries(env || {})
    .filter(([key]) => ENV_NAME_PATTERN.test(key))
    .map(([key, value]) => `${key}=${value}`);
}

/** Replace ciphertext envVars with masked values for client-facing responses. */
function sanitize<T extends { envVars?: Record<string, string> | null }>(service: T): T {
  return { ...service, envVars: redactEnvVars(service.envVars || {}) };
}

async function emitAudit(
  userId: string | null,
  action: string,
  details: Record<string, unknown>,
): Promise<void> {
  try {
    await db.insert(auditLogs).values({ userId, action, details });
  } catch (e) {
    console.error('audit_log emit failed', { action, error: (e as Error).message });
  }
}

type PublishKind = 'static' | 'vite' | 'node';

type DockerSecurityProfileConfig = {
  seccompProfile?: string;
  appArmorProfile?: string;
};

export const PUBLISH_IMAGE_ALLOWLIST = [
  'node:20-alpine',
  'nginxinc/nginx-unprivileged:alpine',
] as const;

const DOCKER_NO_NEW_PRIVILEGES = 'no-new-privileges:true';
const SECCOMP_PROFILE_PATTERN = /^\/?[A-Za-z0-9][A-Za-z0-9_./:-]*$/;
const APPARMOR_PROFILE_PATTERN = /^[A-Za-z0-9][A-Za-z0-9_.:-]*$/;

const PUBLISH_IMAGE_BY_KIND: Record<PublishKind, (typeof PUBLISH_IMAGE_ALLOWLIST)[number]> = {
  node: 'node:20-alpine',
  vite: 'node:20-alpine',
  static: 'nginxinc/nginx-unprivileged:alpine',
};

export function resolvePublishImage(kind: PublishKind): string {
  const image = PUBLISH_IMAGE_BY_KIND[kind];
  assertPublishImageAllowed(image);
  return image;
}

export function assertPublishImageAllowed(image: string): void {
  if (!PUBLISH_IMAGE_ALLOWLIST.includes(image as (typeof PUBLISH_IMAGE_ALLOWLIST)[number])) {
    throw new Error('Publish image is not allowed');
  }
}

export function buildPublishSecurityOptions(config: DockerSecurityProfileConfig = {}): string[] {
  const securityOptions = [DOCKER_NO_NEW_PRIVILEGES];
  const seccompProfile = normalizeProfileValue(
    config.seccompProfile,
    'PUBLISH_SECCOMP_PROFILE',
    SECCOMP_PROFILE_PATTERN,
  );
  const appArmorProfile = normalizeProfileValue(
    config.appArmorProfile,
    'PUBLISH_APPARMOR_PROFILE',
    APPARMOR_PROFILE_PATTERN,
  );

  if (seccompProfile) securityOptions.push(`seccomp=${seccompProfile}`);
  if (appArmorProfile) securityOptions.push(`apparmor=${appArmorProfile}`);
  return securityOptions;
}

function normalizeProfileValue(
  value: string | undefined,
  envName: string,
  pattern: RegExp,
): string | undefined {
  const trimmed = value?.trim();
  if (!trimmed) return undefined;
  if (trimmed === 'unconfined') {
    throw new Error(`${envName} must not disable confinement`);
  }
  if (trimmed.includes('..') || !pattern.test(trimmed)) {
    throw new Error(`${envName} contains invalid characters`);
  }
  return trimmed;
}

import { db } from '@pcp/db/src/client';
import { hostedServices, hostedServiceLogs, notifications } from '@pcp/db/src/schema';
import { and, eq, isNull } from 'drizzle-orm';
import type { FastifyBaseLogger } from 'fastify';
import type { PublishService } from './service';

const HEALTH_TIMEOUT_MS = 5_000;
const CONSECUTIVE_FAIL_THRESHOLD = 3;
// Backoff schedule (seconds): 10s, 30s, 2m, 10m, then capped.
const BACKOFF_SECONDS = [10, 30, 120, 600, 600];
const MAX_RESTART_ATTEMPTS_PER_HOUR = 5;

type ServiceHealthState = {
  consecutiveFailures: number;
  // recent restart attempts (epoch-ms)
  restartHistory: number[];
  // earliest moment we may try restart again
  nextRestartAfter: number;
  inFlight: boolean;
};

const state = new Map<string, ServiceHealthState>();

function getState(serviceId: string): ServiceHealthState {
  let s = state.get(serviceId);
  if (!s) {
    s = {
      consecutiveFailures: 0,
      restartHistory: [],
      nextRestartAfter: 0,
      inFlight: false,
    };
    state.set(serviceId, s);
  }
  return s;
}

async function pingUrl(url: string, signal: AbortSignal): Promise<boolean> {
  try {
    const res = await fetch(url, { method: 'GET', signal, redirect: 'follow' });
    // Treat any 2xx/3xx/4xx as "process is alive"; only network failures and
    // 5xx count as unhealthy.
    if (res.status >= 500) return false;
    return true;
  } catch {
    return false;
  }
}

export interface HealthDaemonOptions {
  intervalMs?: number;
  publishService: PublishService;
  logger: FastifyBaseLogger;
}

export function startHealthDaemon(opts: HealthDaemonOptions) {
  const intervalMs = opts.intervalMs ?? 30_000;
  const log = opts.logger.child({ component: 'health-daemon' });

  log.info({ intervalMs }, 'health daemon starting');

  let stopped = false;
  const tick = async () => {
    if (stopped) return;
    try {
      await runHealthCheck(opts.publishService, log);
    } catch (err) {
      log.error({ err }, 'health daemon tick failed');
    }
  };

  const handle = setInterval(tick, intervalMs);
  // Run immediately so first cycle doesn't wait the full interval.
  void tick();

  return {
    stop: () => {
      stopped = true;
      clearInterval(handle);
    },
  };
}

async function runHealthCheck(publishService: PublishService, log: FastifyBaseLogger) {
  const services = await db.query.hostedServices.findMany({
    where: and(eq(hostedServices.status, 'running'), isNull(hostedServices.deletedAt)),
  });

  await Promise.all(
    services.map((svc) =>
      checkOne(svc, publishService, log).catch((err) => {
        log.error({ err, serviceId: svc.id }, 'health check failed');
      }),
    ),
  );

  // Also progress crashed services that are eligible for auto-restart.
  const crashed = await db.query.hostedServices.findMany({
    where: and(
      eq(hostedServices.status, 'crashed'),
      eq(hostedServices.autoRestart, true),
      isNull(hostedServices.deletedAt),
    ),
  });
  await Promise.all(
    crashed.map((svc) =>
      attemptRestart(svc, publishService, log).catch((err) => {
        log.error({ err, serviceId: svc.id }, 'restart attempt failed');
      }),
    ),
  );
}

async function checkOne(
  svc: typeof hostedServices.$inferSelect,
  publishService: PublishService,
  log: FastifyBaseLogger,
) {
  if (!svc.publicUrl) return;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), HEALTH_TIMEOUT_MS);
  let ok = false;
  try {
    ok = await pingUrl(svc.publicUrl, controller.signal);
  } finally {
    clearTimeout(timer);
  }

  await db
    .update(hostedServices)
    .set({ lastHealthAt: new Date(), lastHealthOk: ok })
    .where(eq(hostedServices.id, svc.id));

  const s = getState(svc.id);
  if (ok) {
    s.consecutiveFailures = 0;
    return;
  }

  s.consecutiveFailures += 1;
  log.warn(
    { serviceId: svc.id, consecutiveFailures: s.consecutiveFailures },
    'service health check failed',
  );

  if (s.consecutiveFailures >= CONSECUTIVE_FAIL_THRESHOLD) {
    await markCrashed(svc, 'health check failed 3 times in a row');
    s.consecutiveFailures = 0;
    if (svc.autoRestart) {
      await attemptRestart({ ...svc, status: 'crashed' }, publishService, log);
    }
  }
}

async function markCrashed(svc: typeof hostedServices.$inferSelect, reason: string) {
  await db
    .update(hostedServices)
    .set({ status: 'crashed', crashCount: svc.crashCount + 1, lastHealthOk: false })
    .where(eq(hostedServices.id, svc.id));

  await db.insert(hostedServiceLogs).values({
    serviceId: svc.id,
    stream: 'system',
    line: `Service marked crashed: ${reason}`,
  });

  await db.insert(notifications).values({
    userId: svc.userId,
    kind: 'hosted_service_crashed',
    title: `Service ${svc.name} crashed`,
    body: reason,
    severity: 'error',
    link: `/hosting`,
    payload: { serviceId: svc.id },
  });
}

async function attemptRestart(
  svc: typeof hostedServices.$inferSelect,
  publishService: PublishService,
  log: FastifyBaseLogger,
) {
  const s = getState(svc.id);
  const now = Date.now();

  if (s.inFlight) return;
  if (now < s.nextRestartAfter) return;

  // Prune restart history older than 1h.
  s.restartHistory = s.restartHistory.filter((t) => now - t < 60 * 60 * 1000);
  if (s.restartHistory.length >= MAX_RESTART_ATTEMPTS_PER_HOUR) {
    log.warn(
      { serviceId: svc.id, attempts: s.restartHistory.length },
      'auto-restart cap reached for the hour; skipping',
    );
    // Push the next attempt out 10m so we don't spam this branch.
    s.nextRestartAfter = now + 10 * 60 * 1000;
    return;
  }

  s.inFlight = true;
  s.restartHistory.push(now);
  const attemptIndex = Math.min(s.restartHistory.length - 1, BACKOFF_SECONDS.length - 1);
  const backoffSec = BACKOFF_SECONDS[attemptIndex] ?? BACKOFF_SECONDS[BACKOFF_SECONDS.length - 1]!;
  s.nextRestartAfter = now + backoffSec * 1000;

  try {
    log.info(
      { serviceId: svc.id, attempt: s.restartHistory.length, backoffSec },
      'auto-restarting crashed service',
    );
    await publishService.startService(svc.id, svc.userId);
    await db.insert(hostedServiceLogs).values({
      serviceId: svc.id,
      stream: 'system',
      line: `Auto-restart attempt #${s.restartHistory.length} dispatched (next backoff ${backoffSec}s)`,
    });
  } catch (err) {
    log.error({ err, serviceId: svc.id }, 'auto-restart failed');
    await db.insert(hostedServiceLogs).values({
      serviceId: svc.id,
      stream: 'stderr',
      line: `Auto-restart failed: ${err instanceof Error ? err.message : String(err)}`,
    });
  } finally {
    s.inFlight = false;
  }
}

// Exposed for tests.
export const __test__ = { state, BACKOFF_SECONDS, CONSECUTIVE_FAIL_THRESHOLD };

import { z } from 'zod';
import { resolveProductionValue, resolveSecret } from '@pcp/shared';

const rawEnv = {
  ...process.env,
  COOKIE_SECRET: process.env.COOKIE_SECRET ?? process.env.SESSION_SECRET,
};

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
  PORT: z.coerce.number().int().positive().default(3007),
  DATABASE_URL: z.string().url().optional(),
  COOKIE_SECRET: z.string().optional(),
  INTERNAL_SERVICE_TOKEN: z.string().optional(),
  AUTH_BYPASS: z
    .union([z.literal('1'), z.literal('true'), z.literal('0'), z.literal('false'), z.literal('')])
    .optional(),
  BROWSER_PROFILE_DIR: z.string().default('./data/browser-profiles'),
  BROWSER_SESSION_TIMEOUT_MS: z.coerce
    .number()
    .int()
    .positive()
    .default(15 * 60 * 1000),
  BROWSER_MAX_SESSIONS_PER_USER: z.coerce.number().int().positive().default(3),
});

const parsed = envSchema.parse(rawEnv);
const ctx = { isProduction: parsed.NODE_ENV === 'production' };
const authBypass = parsed.AUTH_BYPASS === '1' || parsed.AUTH_BYPASS === 'true';
if (ctx.isProduction && authBypass) {
  throw new Error('AUTH_BYPASS must not be enabled when NODE_ENV=production');
}

export const env = {
  NODE_ENV: parsed.NODE_ENV,
  PORT: parsed.PORT,
  DATABASE_URL: resolveProductionValue(ctx, 'DATABASE_URL', parsed.DATABASE_URL),
  COOKIE_SECRET: resolveSecret(ctx, 'COOKIE_SECRET', parsed.COOKIE_SECRET, 32),
  INTERNAL_SERVICE_TOKEN: resolveSecret(
    ctx,
    'INTERNAL_SERVICE_TOKEN',
    parsed.INTERNAL_SERVICE_TOKEN,
    32,
  ),
  AUTH_BYPASS: !ctx.isProduction && authBypass,
  BROWSER_PROFILE_DIR: parsed.BROWSER_PROFILE_DIR,
  BROWSER_SESSION_TIMEOUT_MS: parsed.BROWSER_SESSION_TIMEOUT_MS,
  BROWSER_MAX_SESSIONS_PER_USER: parsed.BROWSER_MAX_SESSIONS_PER_USER,
};

import Fastify from 'fastify';
import { serializerCompiler, validatorCompiler } from 'fastify-type-provider-zod';
import cookie from '@fastify/cookie';
import cors from '@fastify/cors';
import rateLimit from '@fastify/rate-limit';
import {
  createApiErrorHandler,
  createCorsOptions,
  createCorrelationIdGenerator,
  registerObservability,
} from '@pcp/shared';
import { setupBrowserRoutes } from './routes';
import { env } from './env';

const server = Fastify({
  genReqId: createCorrelationIdGenerator(),
  logger: {
    transport:
      env.NODE_ENV === 'development'
        ? {
            target: 'pino-pretty',
            options: {
              translateTime: 'HH:MM:ss Z',
              ignore: 'pid,hostname',
            },
          }
        : undefined,
  },
});

server.setValidatorCompiler(validatorCompiler);
server.setSerializerCompiler(serializerCompiler);

server.setErrorHandler(createApiErrorHandler());
registerObservability(server, { serviceName: 'browser' });

server.addHook('onRequest', (request, reply, done) => {
  reply.header('x-correlation-id', request.id);
  done();
});

