'use client';

import { useEffect, useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { FolderPlus } from 'lucide-react';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import FileTree from '@/components/workspace/file-tree';
import WorkspaceEditor from '@/components/workspace/editor';
import { workspaceApi } from '@/lib/api';
import { useWorkspaceStore } from '@/store/workspace';

type WorkspaceSummary = { id: string; name: string };
type WorkspacesResponse = { workspaces: WorkspaceSummary[] };

export default function FilesPage() {
  const { currentWorkspaceId, setCurrentWorkspaceId } = useWorkspaceStore();

  const { data, isLoading } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaces = useMemo(() => data?.workspaces ?? [], [data]);

  // Auto-select first workspace
  useEffect(() => {
    if (!currentWorkspaceId && workspaces.length > 0 && workspaces[0]) {
      setCurrentWorkspaceId(workspaces[0].id);
    }
  }, [currentWorkspaceId, workspaces, setCurrentWorkspaceId]);

  if (isLoading) {
    return (
      <div className="p-6">
        <LoadingSkeleton lines={6} />
      </div>
    );
  }

  if (workspaces.length === 0) {
    return (
      <EmptyState
        icon={<FolderPlus className="h-6 w-6" />}
        title="No workspace found"
        description="Create a workspace to start managing your files."
      />
    );
  }

  return (
    <div className="flex h-full">
      {/* File Tree Sidebar */}
      <div className="hidden w-64 shrink-0 border-r border-border bg-card lg:block">
        {currentWorkspaceId && <FileTree workspaceId={currentWorkspaceId} />}
      </div>

      {/* Editor / Preview Area */}
      <div className="min-w-0 flex-1">
        {currentWorkspaceId ? (
          <WorkspaceEditor />
        ) : (
          <EmptyState
            icon={<FolderPlus className="h-6 w-6" />}
            title="Select a workspace"
            description="Choose a workspace from the sidebar to browse files."
          />
        )}
      </div>
    </div>
  );
}

import { WorkspaceShell } from '@/components/workspace/workspace-shell';

export default async function WorkspacePage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  return <WorkspaceShell workspaceId={id} />;
}

'use client';

import { useEffect } from 'react';
import dynamic from 'next/dynamic';
import { ResizableHandle, ResizablePanel, ResizablePanelGroup } from '@/components/ui/resizable';
import { useWorkspaceStore } from '@/store/workspace';

const FileTree = dynamic(() => import('@/components/workspace/file-tree'), { ssr: false });
const Editor = dynamic(() => import('@/components/workspace/editor'), { ssr: false });
const Terminal = dynamic(() => import('@/components/workspace/terminal'), { ssr: false });
const Chat = dynamic(() => import('@/components/workspace/chat'), { ssr: false });

export function WorkspaceShell({ workspaceId }: { workspaceId: string }) {
  const { setCurrentWorkspaceId, setSelectedFile, setSelectedItem, setOpenFiles } = useWorkspaceStore();

  useEffect(() => {
    setCurrentWorkspaceId(workspaceId);
    setSelectedFile(null);
    setSelectedItem(null);
    setOpenFiles([]);

    return () => {
      setCurrentWorkspaceId(null);
    };
  }, [setCurrentWorkspaceId, setOpenFiles, setSelectedFile, setSelectedItem, workspaceId]);

  return (
    <div className="flex h-full w-full flex-col bg-[#1e1e1e] text-[#cccccc]">
      <div className="flex h-10 items-center justify-between border-b border-[#333333] bg-[#252526] px-4 text-sm shadow-sm">
        <div className="flex items-center space-x-4">
          <span className="font-semibold text-[#cccccc]">Workspace: {workspaceId}</span>
        </div>
      </div>

      <div className="flex-1 overflow-hidden">
        <ResizablePanelGroup orientation="horizontal">
          <ResizablePanel defaultSize={22} minSize={14} maxSize={34} className="bg-[#252526]">
            <FileTree workspaceId={workspaceId} />
          </ResizablePanel>

          <ResizableHandle className="bg-[#333333] hover:bg-[#007acc] active:bg-[#007acc]" />

          <ResizablePanel defaultSize={58}>
            <ResizablePanelGroup orientation="vertical">
              <ResizablePanel defaultSize={70} minSize={30}>
                <div className="h-full bg-[#1e1e1e]">
                  <Editor />
                </div>
              </ResizablePanel>

              <ResizableHandle className="bg-[#333333] hover:bg-[#007acc] active:bg-[#007acc]" />

              <ResizablePanel defaultSize={30} minSize={10}>
                <div className="h-full bg-[#1e1e1e]">
                  <Terminal workspaceId={workspaceId} />
                </div>
              </ResizablePanel>
            </ResizablePanelGroup>
          </ResizablePanel>

          <ResizableHandle className="bg-[#333333] hover:bg-[#007acc] active:bg-[#007acc]" />

          <ResizablePanel defaultSize={20} minSize={15} maxSize={35} className="bg-[#252526]">
            <Chat workspaceId={workspaceId} />
          </ResizablePanel>
        </ResizablePanelGroup>
      </div>
    </div>
  );
}

'use client';

import { useMemo, useState, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { ChevronDown, ChevronRight, File as FileIcon, Folder, FolderOpen, Pencil, Trash, Download } from 'lucide-react';
import { toast } from 'sonner';
import { workspaceApi, toastApiError} from '@/lib/api';
import { formatBytes, formatDate } from '@/lib/format';
import { cn } from '@/lib/utils';
import { useWorkspaceStore, WorkspaceFileMetadata } from '@/store/workspace';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from '@/components/ui/context-menu';

type FilesResponse = {
  files: WorkspaceFileMetadata[];
};

export default function FileTree({ workspaceId }: { workspaceId: string }) {
  const { selectedItem } = useWorkspaceStore();
  const queryClient = useQueryClient();
  const [isDragging, setIsDragging] = useState(false);

  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('path', `/${file.name}`);

      await workspaceApi.post(`/workspaces/${workspaceId}/upload`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('File uploaded successfully');
    },
    onError: (err) => {
      toastApiError(err, 'Failed to upload file');
    },
  });

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        Array.from(e.dataTransfer.files).forEach((file) => {
          uploadMutation.mutate(file);
        });
      }
    },
    [uploadMutation]
  );

  return (
    <div 
      className={cn(
        "flex h-full flex-col text-sm transition-colors",
        isDragging && "bg-primary/5 ring-1 ring-inset ring-primary"
      )}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <div className="flex h-10 items-center px-4 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
        Explorer
      </div>
      <div className="min-h-0 flex-1 overflow-auto py-1">
        {isDragging && (
          <div className="absolute inset-0 z-10 flex items-center justify-center bg-background/50 backdrop-blur-sm">
            <div className="rounded-xl border border-primary/20 bg-card p-4 text-center shadow-lg">
              <Download className="mx-auto mb-2 h-6 w-6 text-primary" />
              <p className="text-sm font-medium">Drop files to upload</p>
            </div>
          </div>
        )}
        <TreeBranch workspaceId={workspaceId} path="/" level={0} />
      </div>
      <div className="border-t border-border bg-card p-3">
        <p className="mb-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">Details</p>
        {selectedItem ? (
          <dl className="space-y-1.5 text-xs">
            <div>
              <dt className="text-muted-foreground">Name</dt>
              <dd className="truncate text-foreground">{selectedItem.name}</dd>
            </div>
            <div>
              <dt className="text-muted-foreground">Path</dt>
              <dd className="truncate text-foreground">{selectedItem.path}</dd>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <dt className="text-muted-foreground">Type</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? 'Folder' : selectedItem.mimeType || 'File'}</dd>
              </div>
              <div>
                <dt className="text-muted-foreground">Size</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? '-' : formatBytes(selectedItem.size)}</dd>
              </div>
            </div>
            <div>
              <dt className="text-muted-foreground">Updated</dt>
              <dd className="text-foreground">{formatDate(selectedItem.updatedAt)}</dd>
            </div>
          </dl>
        ) : (
          <p className="text-xs text-muted-foreground">Select a file or folder to inspect.</p>
        )}
      </div>
    </div>
  );
}

function TreeBranch({ workspaceId, path, level }: { workspaceId: string; path: string; level: number }) {
  const [expandedPaths, setExpandedPaths] = useState<Set<string>>(new Set());
  const { selectedItem, setSelectedFile, addOpenFile, setSelectedItem, removeOpenFile } = useWorkspaceStore();
  const queryClient = useQueryClient();

  const { data, isLoading, isError } = useQuery({
    queryKey: ['workspace-files', workspaceId, path],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces/' + workspaceId + '/files', { params: { path } });
      return res.data as FilesResponse;
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (filePath: string) => {
      await workspaceApi.delete(`/workspaces/${workspaceId}/files${filePath}`);
    },
    onSuccess: (_, filePath) => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('Deleted successfully');
      removeOpenFile(filePath);
      if (selectedItem?.path === filePath) {
        setSelectedItem(null);
      }
    },
    onError: (err) => {
      toastApiError(err, 'Failed to delete file');
    },
  });

  const files = useMemo(() => {
    return [...(data?.files ?? [])].sort((a, b) => {
      if (a.isDirectory !== b.isDirectory) return a.isDirectory ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  }, [data?.files]);

  const toggleDirectory = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setExpandedPaths((current) => {
      const next = new Set(current);
      if (next.has(file.path)) {
        next.delete(file.path);
      } else {
        next.add(file.path);
      }
      return next;
    });
  };

  const openFile = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setSelectedFile(file.path);
    addOpenFile(file.path);
  };

  if (isLoading) {
    return <div className={cn('py-1 pr-2 text-xs text-muted-foreground', indentClass(level))}>Loading...</div>;
  }

  if (isError) {
    return <div className={cn('py-1 pr-2 text-xs text-destructive', indentClass(level))}>Could not load files.</div>;
  }

  if (files.length === 0 && level === 0) {
    return <div className="px-4 py-2 text-xs text-muted-foreground">No files in this workspace.</div>;
  }

  return (
    <ul className="space-y-0.5 px-1.5">
      {files.map((file) => {
        const isExpanded = expandedPaths.has(file.path);
        const isSelected = selectedItem?.path === file.path;

        return (
          <ContextMenu key={file.path}>
            <ContextMenuTrigger>
              <li>
                <button
                  type="button"
                  className={cn(
                    'flex h-7 w-full items-center rounded-md pr-2 text-left text-sm transition-colors',
                    isSelected
                      ? 'bg-primary/10 text-primary'
                      : 'text-foreground/80 hover:bg-muted',
                    indentClass(level)
                  )}
                  onClick={() => (file.isDirectory ? toggleDirectory(file) : openFile(file))}
                >
                  {file.isDirectory ? (
                    <>
                      {isExpanded ? (
                        <ChevronDown className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      ) : (
                        <ChevronRight className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      )}
                      {isExpanded ? (
                        <FolderOpen className="mr-1.5 h-4 w-4 text-blue-500" />
                      ) : (
                        <Folder className="mr-1.5 h-4 w-4 text-blue-500" />
                      )}
                    </>
                  ) : (
                    <FileIcon className="ml-5 mr-1.5 h-4 w-4 text-muted-foreground" />
                  )}
                  <span className="truncate">{file.name}</span>
                </button>
                {file.isDirectory && isExpanded && <TreeBranch workspaceId={workspaceId} path={file.path} level={level + 1} />}
              </li>
            </ContextMenuTrigger>
            <ContextMenuContent className="w-48">
              {!file.isDirectory && (
                <ContextMenuItem onClick={() => openFile(file)}>
                  <Pencil className="mr-2 h-4 w-4" /> Edit
                </ContextMenuItem>
              )}
              {/* Note: Rename and move functionality to be fully implemented via modals */}
              <ContextMenuItem disabled>
                <Pencil className="mr-2 h-4 w-4" /> Rename
              </ContextMenuItem>
              <ContextMenuSeparator />
              <ContextMenuItem
                className="text-destructive focus:bg-destructive focus:text-destructive-foreground"
                onClick={() => {
                  if (confirm(`Are you sure you want to delete ${file.name}?`)) {
                    deleteMutation.mutate(file.path);
                  }
                }}
              >
                <Trash className="mr-2 h-4 w-4" /> Delete
              </ContextMenuItem>
            </ContextMenuContent>
          </ContextMenu>
        );
      })}
    </ul>
  );
}

function indentClass(level: number) {
  const classes = ['pl-2', 'pl-5', 'pl-8', 'pl-11', 'pl-14', 'pl-16'];
  return classes[Math.min(level, classes.length - 1)];
}

'use client';

import Editor from '@monaco-editor/react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { AlertCircle, FileText, Save, X } from 'lucide-react';
import { toast } from 'sonner';
import { useTheme } from 'next-themes';
import { Button } from '@/components/ui/button';
import { workspaceApi, toastApiError} from '@/lib/api';
import { formatBytes } from '@/lib/format';
import { useWorkspaceStore } from '@/store/workspace';
import { cn } from '@/lib/utils';
import { useEffect, useState, useCallback } from 'react';

type FileContentResponse = {
  path: string;
  name: string;
  mimeType: string | null;
  size: number;
  content: string;
  updatedAt: string;
};

type DraftContent = {
  path: string;
  content: string;
};

export default function WorkspaceEditor() {
  const {
    currentWorkspaceId,
    selectedFile,
    selectedItem,
    openFiles,
    setSelectedFile,
    removeOpenFile,
  } = useWorkspaceStore();
  const { resolvedTheme } = useTheme();
  const [draftContent, setDraftContent] = useState<DraftContent | null>(null);

  const {
    data: fileContent,
    isLoading,
    isError,
    error,
  } = useQuery({
    queryKey: ['file-content', currentWorkspaceId, selectedFile],
    queryFn: async () => {
      const res = await workspaceApi.get(`/workspaces/${currentWorkspaceId}/files/content`, {
        params: { path: selectedFile },
      });
      return res.data as FileContentResponse;
    },
    enabled: Boolean(selectedFile && currentWorkspaceId),
    retry: false,
  });

  const editedContent = draftContent?.path === selectedFile ? draftContent.content : null;

  const saveMutation = useMutation({
    mutationFn: async () => {
      if (!currentWorkspaceId || !selectedFile || editedContent === null) return;
      await workspaceApi.put(`/workspaces/${currentWorkspaceId}/files/content`, {
        path: selectedFile,
        content: editedContent,
      });
    },
    onSuccess: () => {
      toast.success('File saved');
      setDraftContent(null);
    },
    onError: (err) => {
      toastApiError(err, 'Failed to save file');
    },
  });

  // Ctrl+S save handler
  const handleSave = useCallback(() => {
    if (editedContent !== null) saveMutation.mutate();
  }, [editedContent, saveMutation]);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        handleSave();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [handleSave]);

  const hasChanges = editedContent !== null;

  const getLanguage = (path: string) => {
    if (path.endsWith('.ts') || path.endsWith('.tsx')) return 'typescript';
    if (path.endsWith('.js') || path.endsWith('.jsx')) return 'javascript';
    if (path.endsWith('.json')) return 'json';
    if (path.endsWith('.md')) return 'markdown';
    if (path.endsWith('.css')) return 'css';
    if (path.endsWith('.html')) return 'html';
    if (path.endsWith('.yaml') || path.endsWith('.yml')) return 'yaml';
    if (path.endsWith('.py')) return 'python';
    if (path.endsWith('.go')) return 'go';
    if (path.endsWith('.rs')) return 'rust';
    if (path.endsWith('.sh') || path.endsWith('.bash')) return 'shell';
    if (path.endsWith('.sql')) return 'sql';
    if (path.endsWith('.xml')) return 'xml';
    return 'plaintext';
  };

  return (
    <div className="flex h-full flex-col bg-background">
      {/* Tab Bar */}
      {openFiles.length > 0 && (
        <div className="flex h-9 items-end overflow-x-auto border-b border-border bg-card">
          {openFiles.map((file) => (
            <div
              key={file}
              className={cn(
                'group flex h-full min-w-[120px] max-w-[200px] cursor-pointer items-center justify-between border-r border-border px-3 text-xs transition-colors',
                selectedFile === file
                  ? 'bg-background text-foreground'
                  : 'bg-muted/30 text-muted-foreground hover:bg-muted/60',
              )}
              onClick={() => setSelectedFile(file)}
            >
              <span className="truncate">{file.split('/').pop()}</span>
              <button
                type="button"
                aria-label={`Close ${file}`}
                className={cn(
                  'ml-2 flex h-5 w-5 items-center justify-center rounded-sm hover:bg-muted',
                  selectedFile === file ? 'opacity-100' : 'opacity-0 group-hover:opacity-100',
                )}
                onClick={(e) => {
                  e.stopPropagation();
                  removeOpenFile(file);
                }}
              >
                <X className="h-3 w-3" />
              </button>
            </div>
          ))}
          {/* Save indicator */}
          {hasChanges && (
            <Button
              size="xs"
              variant="ghost"
              className="mx-2 text-primary"
              onClick={handleSave}
              disabled={saveMutation.isPending}
            >
              <Save className="mr-1 h-3 w-3" />
              {saveMutation.isPending ? 'Saving...' : 'Save'}
            </Button>
          )}
        </div>
      )}

      {/* Editor */}
      <div className="relative flex-1">
        {!selectedFile ? (
          <div className="flex h-full items-center justify-center">
            <div className="max-w-sm text-center">
              <FileText className="mx-auto mb-3 h-8 w-8 text-muted-foreground" />
              <p className="text-sm font-medium text-foreground">Select a file</p>
              <p className="mt-1 text-xs text-muted-foreground">Use the explorer to open files.</p>
            </div>
          </div>
        ) : isLoading ? (
          <div className="flex h-full items-center justify-center text-muted-foreground">
            Loading...
          </div>
        ) : isError ? (
          <PreviewError
            title={selectedItem?.name || selectedFile}
            detail={getPreviewError(error)}
            size={selectedItem?.size}
            mimeType={selectedItem?.mimeType}
          />
        ) : (
          <Editor
            height="100%"
            theme={resolvedTheme === 'dark' ? 'vs-dark' : 'vs'}
            path={selectedFile}
            defaultLanguage={getLanguage(selectedFile)}
            value={editedContent ?? fileContent?.content ?? ''}
            onChange={(value) => {
              if (!selectedFile) return;
              setDraftContent(value === undefined ? null : { path: selectedFile, content: value });
            }}
            options={{
              minimap: { enabled: true },
              fontSize: 13,
              wordWrap: 'on',
              lineNumbers: 'on',
              folding: true,
              readOnly: false,
              scrollBeyondLastLine: false,
              automaticLayout: true,
              padding: { top: 8 },
            }}
          />
        )}
      </div>
    </div>
  );
}

function PreviewError({
  title,
  detail,
  size,
  mimeType,
}: {
  title: string;
  detail: string;
  size?: number;
  mimeType?: string | null;
}) {
  return (
    <div className="flex h-full items-center justify-center p-8">
      <div className="max-w-md rounded-xl border border-border bg-card p-6">
        <AlertCircle className="mb-3 h-6 w-6 text-amber-500" />
        <h2 className="font-semibold text-foreground">{title}</h2>
        <p className="mt-2 text-sm text-muted-foreground">{detail}</p>
        <dl className="mt-4 grid grid-cols-2 gap-3 text-xs">
          <div>
            <dt className="text-muted-foreground">Type</dt>
            <dd className="mt-1 text-foreground">{mimeType || 'Unknown'}</dd>
          </div>
          <div>
            <dt className="text-muted-foreground">Size</dt>
            <dd className="mt-1 text-foreground">{size === undefined ? '-' : formatBytes(size)}</dd>
          </div>
        </dl>
      </div>
    </div>
  );
}

function getPreviewError(error: unknown) {
  if (typeof error === 'object' && error && 'response' in error) {
    const response = (error as { response?: { data?: { error?: string; message?: string } } })
      .response;
    return response?.data?.error || response?.data?.message || 'This file cannot be previewed.';
  }

  return 'This file cannot be previewed.';
}

'use client';

import { useState } from 'react';
import { Plus, TerminalSquare, AlertTriangle, Loader2 } from 'lucide-react';
import { useMutation } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { runtimeApi, toastApiError} from '@/lib/api';
import { useTerminal } from '@/hooks/use-terminal';

function TerminalTab({ runtimeId, isActive, onBlocked }: { runtimeId: string; isActive: boolean; onBlocked: (cmd: string) => void }) {
  const { terminalRef, connectionState } = useTerminal({ runtimeId, onCommandBlocked: onBlocked });

  const badgeStyle =
    connectionState === 'connected'
      ? 'bg-emerald-500/20 text-emerald-300'
      : connectionState === 'connecting'
        ? 'bg-zinc-500/20 text-zinc-300'
        : connectionState === 'reconnecting'
          ? 'bg-amber-500/20 text-amber-300'
          : 'bg-red-500/20 text-red-300';

  return (
    <div className={`flex-1 p-2 bg-[#1e1e1e] relative ${isActive ? 'block' : 'hidden'}`}>
      <div
        className={`absolute top-2 right-3 z-10 rounded-full px-2 py-0.5 text-[10px] font-medium uppercase tracking-wide ${badgeStyle}`}
        role="status"
        aria-live="polite"
      >
        {connectionState}
      </div>
      {connectionState !== 'connected' && (
        <div className="absolute inset-0 flex items-center justify-center bg-[#1e1e1e]/80 z-10">
          <Loader2 className="animate-spin text-zinc-400 mr-2" />
          <span className="text-zinc-400">
            {connectionState === 'reconnecting' ? 'Reconnecting…' : 'Connecting…'}
          </span>
        </div>
      )}
      <div className="h-full w-full" ref={terminalRef} />
    </div>
  );
}

export default function WorkspaceTerminal({ workspaceId }: { workspaceId: string }) {
  const [tabs, setTabs] = useState<{ id: string; name: string }[]>([]);
  const [activeTabId, setActiveTabId] = useState<string | null>(null);
  const [blockedCommand, setBlockedCommand] = useState<string | null>(null);

  const createRuntimeMutation = useMutation({
    mutationFn: async () => {
      const res = await runtimeApi.post('/runtimes', {
        workspaceId,
        image: 'ubuntu:latest', // Default image
        options: {},
      });
      const runtime = res.data;
      // Start it automatically
      await runtimeApi.post(`/runtimes/${runtime.id}/start`);
      return runtime.id;
    },
    onSuccess: (runtimeId) => {
      const newTab = { id: runtimeId, name: `bash-${tabs.length + 1}` };
      setTabs((prev) => [...prev, newTab]);
      setActiveTabId(runtimeId);
    },
    onError: (error) => {
      toastApiError(error, 'Failed to start terminal');
    },
  });

  const handleBlocked = (cmd: string) => {
    setBlockedCommand(cmd);
  };

  return (
    <div className="flex h-full w-full flex-col relative">
      <div className="flex h-10 items-center bg-[#252526] border-b border-[#333333]">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTabId(tab.id)}
              className={`flex items-center px-4 h-full border-r border-[#333333] text-xs transition-colors ${
                activeTabId === tab.id ? 'bg-[#1e1e1e] text-blue-400 border-t-2 border-t-blue-500' : 'text-zinc-400 hover:bg-[#2d2d2d]'
              }`}
            >
              <TerminalSquare className="mr-2 h-3 w-3" />
              {tab.name}
            </button>
          ))}
        </div>
        <Button
          variant="ghost"
          size="icon"
          className="h-8 w-8 text-zinc-400 hover:text-white mr-2"
          onClick={() => createRuntimeMutation.mutate()}
          disabled={createRuntimeMutation.isPending}
          aria-label="New terminal session"
          title="New terminal session"
        >
          {createRuntimeMutation.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
        </Button>
      </div>

      {tabs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center bg-[#1e1e1e] text-zinc-500">
          <TerminalSquare className="h-12 w-12 mb-4 opacity-50" />
          <p>No active terminal sessions.</p>
          <Button 
            className="mt-4 bg-blue-600 hover:bg-blue-500"
            onClick={() => createRuntimeMutation.mutate()}
            disabled={createRuntimeMutation.isPending}
          >
            {createRuntimeMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            Start Terminal Session
          </Button>
        </div>
      ) : (
        tabs.map((tab) => (
          <TerminalTab 
            key={tab.id} 
            runtimeId={tab.id} 
            isActive={activeTabId === tab.id} 
            onBlocked={handleBlocked}
          />
        ))
      )}

      <AlertDialog open={!!blockedCommand} onOpenChange={() => setBlockedCommand(null)}>
        <AlertDialogContent className="bg-[#2d2d2d] border-[#444] text-zinc-200">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center text-red-400">
              <AlertTriangle className="mr-2 h-5 w-5" />
              Command Blocked
            </AlertDialogTitle>
            <AlertDialogDescription className="text-zinc-400">
              The command you attempted to run violates our security policy and has been blocked.
              <div className="mt-2 p-2 bg-black rounded font-mono text-sm text-red-300">
                {blockedCommand}
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogAction className="bg-blue-600 hover:bg-blue-500 text-white">I Understand</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

'use client';

import { useState, useEffect, useMemo, useRef } from 'react';
import type React from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Send, Bot, Loader2, CheckCircle2, XCircle, Paperclip, X } from 'lucide-react';
import { toast } from 'sonner';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { agentApi, workspaceApi, toastApiError} from '@/lib/api';
import { usePersonaStore } from '@/store/persona';
import { useActiveSkillsStore } from '@/store/skills';

type ToolCall = {
  name: string;
  args: unknown;
};

type Message = {
  id: string;
  taskId: string;
  taskStatus: string;
  conversationId: string;
  role: string;
  content: string;
  toolCalls?: ToolCall[];
  createdAt: string;
};

type Conversation = {
  id: string;
  title: string | null;
};

export default function WorkspaceChat({ workspaceId }: { workspaceId: string }) {
  const [input, setInput] = useState('');
  const [attachments, setAttachments] = useState<{ path: string; name: string }[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const queryClient = useQueryClient();

  // Fetch conversations
  const { data: convosData } = useQuery({
    queryKey: ['agent-conversations'],
    queryFn: async () => {
      const res = await agentApi.get('/agent/conversations');
      return res.data.conversations as Conversation[];
    },
  });

  const activeConversationId = convosData?.[0]?.id;

  // Fetch messages
  const { data: messagesData, isLoading: isLoadingMessages } = useQuery({
    queryKey: ['agent-messages', activeConversationId],
    queryFn: async () => {
      if (!activeConversationId) return { messages: [] };
      const res = await agentApi.get(`/agent/conversations/${activeConversationId}/messages`);
      return res.data as { messages: Message[] };
    },
    enabled: !!activeConversationId,
    refetchInterval: (query) => {
      // Poll if any task is executing or waiting approval
      const isPending = query.state?.data?.messages.some((m: Message) =>
        ['pending', 'executing'].includes(m.taskStatus),
      );
      return isPending ? 2000 : false;
    },
  });

  const messages = useMemo(() => messagesData?.messages ?? [], [messagesData]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMutation = useMutation({
    mutationFn: async (content: string) => {
      const personaId = usePersonaStore.getState().activePersonaId;
      const skillIds = useActiveSkillsStore.getState().activeSkillIds;
      const composed =
        attachments.length > 0
          ? `${content}\n\n${attachments.map((a) => `[Attached: ${a.path}]`).join('\n')}`
          : content;
      await agentApi.post('/agent/tasks', {
        workspaceId,
        input: composed,
        conversationId: activeConversationId,
        personaId: personaId ?? undefined,
        skillIds: skillIds.length > 0 ? skillIds : undefined,
      });
    },
    onSuccess: () => {
      // Invalidate queries so we fetch the new task and poll
      if (!activeConversationId) {
        queryClient.invalidateQueries({ queryKey: ['agent-conversations'] });
      } else {
        queryClient.invalidateQueries({ queryKey: ['agent-messages', activeConversationId] });
      }
      setAttachments([]);
    },
    onError: (error) => {
      toastApiError(error, 'Failed to send message');
    },
  });

  const approvalMutation = useMutation({
    mutationFn: async ({
      taskId,
      decision,
      reason,
    }: {
      taskId: string;
      decision: 'approve' | 'reject';
      reason?: string;
    }) => {
      await agentApi.post(`/agent/tasks/${taskId}/tool-approval`, { decision, reason });
    },
    onSuccess: (_, variables) => {
      toast.success(`Tool call ${variables.decision}d.`);
      queryClient.invalidateQueries({ queryKey: ['agent-messages', activeConversationId] });
    },
    onError: (error) => {
      toastApiError(error, 'Failed to submit approval');
    },
  });

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && attachments.length === 0) || sendMutation.isPending) return;
    sendMutation.mutate(input);
    setInput('');
  };

  const handleFilePick = () => fileInputRef.current?.click();

  const handleFilesSelected = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files ?? []);
    e.target.value = '';
    if (files.length === 0) return;
    if (!workspaceId) {
      toast.error('Open a workspace before attaching files.');
      return;
    }
    setIsUploading(true);
    try {
      for (const file of files) {
        const form = new FormData();
        form.append('file', file);
        form.append('path', `/chat-uploads/${Date.now()}-${file.name}`);
        const res = await workspaceApi.post(`/workspaces/${workspaceId}/upload`, form, {
          headers: { 'Content-Type': 'multipart/form-data' },
        });
        const path = res.data?.path ?? `/chat-uploads/${file.name}`;
        setAttachments((prev) => [...prev, { path, name: file.name }]);
      }
      toast.success(`${files.length} file${files.length > 1 ? 's' : ''} attached.`);
    } catch (err) {
      toastApiError(err, 'Upload failed');
    } finally {
      setIsUploading(false);
    }
  };

  const removeAttachment = (idx: number) => {
    setAttachments((prev) => prev.filter((_, i) => i !== idx));
  };

  return (
    <div className="flex h-full flex-col bg-[#252526]">
      <div className="flex h-10 items-center justify-between border-b border-[#333333] px-4 font-semibold uppercase tracking-wider text-zinc-400">
        <span>Agent Chat</span>
        <Bot className="h-5 w-5 text-blue-400" />
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {isLoadingMessages && !messages.length ? (
          <div className="flex justify-center text-zinc-500 py-4 animate-in fade-in duration-200">
            <Loader2 className="animate-spin h-5 w-5" />
          </div>
        ) : messages.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center text-zinc-500 animate-in fade-in zoom-in-95 duration-300">
            <Bot className="mb-2 h-10 w-10 text-zinc-600" />
            <p>How can I help you today?</p>
          </div>
        ) : null}

        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex flex-col max-w-[85%] animate-in fade-in slide-in-from-bottom-2 duration-300 ${
              msg.role === 'user' ? 'ml-auto items-end' : 'mr-auto items-start'
            }`}
          >
            <div
              className={`rounded-lg px-3 py-2 text-sm whitespace-pre-wrap transition-colors ${
                msg.role === 'user' ? 'bg-blue-600 text-white' : 'bg-[#37373d] text-zinc-200'
              }`}
            >
              {msg.content ||
                (msg.toolCalls?.length ? (
                  ''
                ) : (
                  <span className="italic text-zinc-400">Processing...</span>
                ))}

              {/* Tool Calls Rendering */}
              {msg.toolCalls && msg.toolCalls.length > 0 && (
                <div className="mt-2 space-y-2 border-t border-[#4c4c4c] pt-2">
                  <p className="text-xs font-semibold uppercase text-zinc-400">Tool Calls</p>
                  {msg.toolCalls.map((tc, idx) => (
                    <div
                      key={idx}
                      className="rounded bg-[#2d2d2d] p-2 text-xs font-mono text-blue-300"
                    >
                      <div>{tc.name}</div>
                      <div className="text-zinc-400">{JSON.stringify(tc.args, null, 2)}</div>
                    </div>
                  ))}

                  {/* Approval UI */}
                  {msg.taskStatus === 'waiting_approval' && (
                    <div className="mt-2 flex space-x-2">
                      <Button
                        size="sm"
                        variant="default"
                        className="h-7 text-xs bg-emerald-600 hover:bg-emerald-500"
                        onClick={() =>
                          approvalMutation.mutate({ taskId: msg.taskId, decision: 'approve' })
                        }
                        disabled={approvalMutation.isPending}
                      >
                        <CheckCircle2 className="mr-1 h-3 w-3" /> Approve
                      </Button>
                      <Button
                        size="sm"
                        variant="destructive"
                        className="h-7 text-xs"
                        onClick={() =>
                          approvalMutation.mutate({
                            taskId: msg.taskId,
                            decision: 'reject',
                            reason: 'User rejected manually',
                          })
                        }
                        disabled={approvalMutation.isPending}
                      >
                        <XCircle className="mr-1 h-3 w-3" /> Reject
                      </Button>
                    </div>
                  )}
                </div>
              )}
            </div>
            <div className="mt-1 flex items-center space-x-1 text-[10px] text-zinc-500">
              <span>{msg.role === 'user' ? 'You' : 'Agent'}</span>
              {msg.taskStatus === 'executing' && (
                <Loader2 className="ml-1 h-3 w-3 animate-spin text-blue-400" />
              )}
              {msg.taskStatus === 'failed' && <span className="text-red-400">Failed</span>}
            </div>
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <div className="border-t border-[#333333] p-3">
        {attachments.length > 0 && (
          <div className="mb-2 flex flex-wrap gap-1.5 animate-in fade-in slide-in-from-bottom-1 duration-200">
            {attachments.map((a, idx) => (
              <span
                key={idx}
                className="inline-flex items-center gap-1 rounded-full bg-blue-600/20 px-2 py-1 text-[11px] text-blue-200 border border-blue-500/30"
                title={a.path}
              >
                <Paperclip className="h-3 w-3" />
                <span className="max-w-[160px] truncate">{a.name}</span>
                <button
                  type="button"
                  onClick={() => removeAttachment(idx)}
                  className="ml-0.5 rounded-full p-0.5 hover:bg-blue-500/30 transition-colors"
                  aria-label={`Remove ${a.name}`}
                >
                  <X className="h-3 w-3" />
                </button>
              </span>
            ))}
          </div>
        )}
        <form onSubmit={handleSend} className="flex items-center space-x-2">
          <input
            ref={fileInputRef}
            type="file"
            multiple
            className="hidden"
            onChange={handleFilesSelected}
          />
          <Button
            type="button"
            size="icon"
            variant="ghost"
            onClick={handleFilePick}
            disabled={isUploading || sendMutation.isPending}
            className="h-9 w-9 text-zinc-400 hover:text-zinc-100 hover:bg-[#3c3c3c] transition-colors"
            aria-label="Attach files"
            title="Attach files to message"
          >
            {isUploading ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Paperclip className="h-4 w-4" />
            )}
          </Button>
          <Input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Ask agent to do something..."
            disabled={sendMutation.isPending}
            className="h-9 flex-1 bg-[#3c3c3c] border-none text-zinc-200 placeholder:text-zinc-500 focus-visible:ring-1 focus-visible:ring-blue-500 transition-shadow"
          />
          <Button
            type="submit"
            size="icon"
            className="h-9 w-9 bg-blue-600 hover:bg-blue-500 transition-colors"
            disabled={(!input.trim() && attachments.length === 0) || sendMutation.isPending}
            aria-label={sendMutation.isPending ? 'Sending message' : 'Send message'}
          >
            {sendMutation.isPending ? (
              <Loader2 className="h-4 w-4 animate-spin" />
            ) : (
              <Send className="h-4 w-4" />
            )}
          </Button>
        </form>
      </div>
    </div>
  );
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';
import { ChatComposer } from '@/components/app-shell/chat-composer';
import { DottedBackground } from '@/components/app-shell/dotted-background';
import { StatusToast } from '@/components/app-shell/status-toast';
import { ToolApproval } from '@/components/app-shell/tool-approval-card';
import { agentApi, getApiErrorMessage } from '@/lib/api';

export function ChatHome() {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<
    Array<{ id: string; role: 'user' | 'assistant'; content: string }>
  >([]);
  const [isThinking, setIsThinking] = useState(false);
  const [toolApproval, setToolApproval] = useState<ToolApproval | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const abortRef = useRef<AbortController | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const stopGeneration = useCallback(() => {
    abortRef.current?.abort();
    abortRef.current = null;
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setIsThinking(false);
  }, []);

  const startNewChat = useCallback(() => {
    stopGeneration();
    setMessages([]);
    setInput('');
    setToolApproval(null);
  }, [stopGeneration]);

  const openUpload = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  useEffect(() => {
    const handleNewChat = () => startNewChat();
    const handleUpload = () => openUpload();
    window.addEventListener('app:new-chat', handleNewChat);
    window.addEventListener('app:open-file-upload', handleUpload);
    return () => {
      window.removeEventListener('app:new-chat', handleNewChat);
      window.removeEventListener('app:open-file-upload', handleUpload);
    };
  }, [openUpload, startNewChat]);

  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape' && isThinking) {
        stopGeneration();
      }
    };
    window.addEventListener('keydown', handleEscape);
    return () => window.removeEventListener('keydown', handleEscape);
  }, [isThinking, stopGeneration]);

  useEffect(() => {
    return () => stopGeneration();
  }, [stopGeneration]);

  const submit = async () => {
    const prompt = input.trim();
    if (!prompt || isThinking) return;

    setMessages((current) => [
      ...current,
      { id: crypto.randomUUID(), role: 'user', content: prompt },
    ]);
    setInput('');
    setIsThinking(true);
    setToolApproval(null);

    const needsTool = /\b(file|deploy|publish|terminal|workspace|host)\b/i.test(prompt);
    if (needsTool) {
      setTimeout(() => {
        setToolApproval({
          toolName: prompt.match(/\bdeploy|publish|host\b/i)
            ? 'prepare_deployment'
            : 'workspace_inspector',
          description: 'Review workspace context before taking action.',
        });
      }, 450);
    }

    const assistantId = crypto.randomUUID();
    setMessages((current) => [...current, { id: assistantId, role: 'assistant', content: '' }]);

    const controller = new AbortController();
    abortRef.current = controller;

    try {
      const response = await agentApi.post(
        '/agent/chat',
        { input: prompt },
        { signal: controller.signal },
      );
      const content =
        (response.data as { content?: string }).content ||
        'I did not receive a response from the model.';

      setMessages((current) =>
        current.map((message) => (message.id === assistantId ? { ...message, content } : message)),
      );
    } catch (error) {
      const content = controller.signal.aborted
        ? 'Generation stopped.'
        : getApiErrorMessage(error, 'The MiniMax agent service is not available.');

      setMessages((current) =>
        current.map((message) => (message.id === assistantId ? { ...message, content } : message)),
      );
    } finally {
      if (abortRef.current === controller) {
        abortRef.current = null;
      }
      setIsThinking(false);
    }
  };

  return (
    <div className="relative flex min-h-full flex-col overflow-hidden bg-[linear-gradient(180deg,#1D1E21_0%,#18191C_100%)] px-4 pb-4 pt-8 text-[#F0F0F0] sm:px-8 lg:px-12">
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -left-40 -top-56 h-[900px] w-[900px] rounded-full bg-[radial-gradient(circle,#3FB6E0_0%,transparent_68%)] opacity-[0.10] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -right-48 -top-72 h-[1000px] w-[1000px] rounded-full bg-[radial-gradient(circle,#B85CFF_0%,transparent_68%)] opacity-[0.12] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute bottom-[-280px] left-[22%] h-[560px] w-[820px] rounded-full bg-[radial-gradient(circle,#F5A524_0%,transparent_70%)] opacity-[0.09] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -bottom-52 -left-48 h-[600px] w-[760px] rounded-full bg-[radial-gradient(circle,#7CD992_0%,transparent_70%)] opacity-[0.08] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -left-32 -top-56 h-[1400px] w-96 -rotate-[22deg] rounded-full bg-[linear-gradient(90deg,transparent,#3FB6E0,transparent)] opacity-[0.07] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-32 -top-72 h-[1400px] w-80 rotate-[18deg] rounded-full bg-[linear-gradient(90deg,transparent,#B85CFF,transparent)] opacity-[0.06] blur-3xl"
      />
      <DottedBackground className="opacity-45" />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[13%] top-[10%] h-0.5 w-0.5 rounded-full bg-white shadow-[0_0_14px_4px_rgba(122,184,255,0.65)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[43%] top-[16%] h-1 w-1 rounded-full bg-[#FFE7B3] shadow-[0_0_18px_5px_rgba(245,165,36,0.55)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[22%] top-[11%] h-0.5 w-0.5 rounded-full bg-white shadow-[0_0_14px_4px_rgba(184,92,255,0.55)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[15%] bottom-[18%] h-1 w-1 rounded-full bg-[#FFE7B3] shadow-[0_0_16px_4px_rgba(245,165,36,0.5)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[2%] top-[25%] h-px w-40 rotate-[12deg] bg-gradient-to-r from-transparent to-[#A8E0FF] opacity-45"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[12%] bottom-[28%] h-px w-44 rotate-[14deg] bg-gradient-to-r from-transparent to-[#E0BCFF] opacity-45"
      />
      <input ref={fileInputRef} type="file" multiple className="hidden" aria-label="Upload files" />
      <div className="relative z-10 mx-auto flex w-[calc(100vw-3rem)] min-w-0 max-w-full flex-1 flex-col justify-center pb-20 pt-8 sm:w-full sm:max-w-[700px] lg:justify-start lg:pt-[27vh]">
        <StatusToast isThinking={isThinking} onStop={stopGeneration} />
        {messages.length > 0 && (
          <div className="mb-5 max-h-[32vh] space-y-3 overflow-auto rounded-xl border border-zinc-800 bg-zinc-950/35 p-4">
            {messages.map((message) => (
              <div
                key={message.id}
                className={message.role === 'user' ? 'text-right' : 'text-left'}
              >
                <div
                  className={`inline-block max-w-[84%] rounded-xl px-4 py-2 text-sm leading-6 ${
                    message.role === 'user'
                      ? 'bg-blue-500/15 text-blue-100 ring-1 ring-blue-400/20'
                      : 'bg-zinc-900 text-zinc-200 ring-1 ring-zinc-800'
                  }`}
                >
                  {message.content || '...'}
                </div>
              </div>
            ))}
          </div>
        )}
        <ChatComposer
          value={input}
          onChange={setInput}
          onSubmit={submit}
          onUpload={openUpload}
          isThinking={isThinking}
          toolApproval={toolApproval}
          onApproveTool={() => setToolApproval(null)}
          onRejectTool={() => setToolApproval(null)}
        />
        <div className="mt-5 text-[10px] leading-tight text-[#777C85]">
          <div className="font-extrabold text-[#B1B3B9]">Rewards</div>
          <div>Earn $10 / user</div>
        </div>
      </div>
      <div className="relative z-10 mx-auto flex w-full max-w-[520px] flex-wrap items-center justify-center gap-x-5 gap-y-2 pb-1 text-xs text-[#A8A8A8]/80">
        <span>kafkasder.zo.computer</span>
        <span>kafkasder.zo.space</span>
        <span>kafkasder@zo.computer</span>
      </div>
    </div>
  );
}

