              value={editor.description}
              onChange={(e) => setEditor({ ...editor, description: e.target.value })}
              placeholder="One-line summary"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="sk-trig">
              Triggers (comma-separated keywords; substring match on user input)
            </Label>
            <Input
              id="sk-trig"
              value={editor.triggers}
              onChange={(e) => setEditor({ ...editor, triggers: e.target.value })}
              placeholder="research, summarize, report"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="sk-body">SKILL.md body</Label>
            <textarea
              id="sk-body"
              value={editor.bodyMarkdown}
              onChange={(e) => setEditor({ ...editor, bodyMarkdown: e.target.value })}
              rows={10}
              className="w-full rounded-lg border border-border bg-card p-3 text-sm font-mono"
              placeholder="# Skill instructions...\n\nWhen invoked, the agent should..."
            />
          </div>
          <label className="flex items-center gap-2 text-sm">
            <input
              type="checkbox"
              checked={editor.enabled}
              onChange={(e) => setEditor({ ...editor, enabled: e.target.checked })}
            />
            Enabled
          </label>
          <div className="flex justify-end gap-2">
            <Button size="sm" variant="outline" type="button" onClick={() => setEditor(null)}>
              Cancel
            </Button>
            <Button size="sm" type="submit" disabled={save.isPending}>
              {save.isPending ? 'Saving...' : 'Save'}
            </Button>
          </div>
        </form>
      )}

      <div className="mt-6 space-y-3">
        {isLoading ? (
          <p className="text-sm text-muted-foreground">Loading...</p>
        ) : skills.length === 0 ? (
          <div className="rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">
            No skills yet. Create one to give the agent reusable instructions.
          </div>
        ) : (
          skills.map((s) => (
            <div
              key={s.id}
              className="flex items-start justify-between rounded-xl border border-border bg-card p-4"
            >
              <div className="flex min-w-0 gap-3">
                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                  <Bot className="h-5 w-5 text-primary" />
                </div>
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <h3 className="font-medium text-foreground">{s.name}</h3>
                    <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground">
                      {s.slug}
                    </span>
                    {!s.enabled && (
                      <span className="rounded bg-amber-500/10 px-1.5 py-0.5 text-[10px] font-medium text-amber-600 dark:text-amber-400">
                        Disabled
                      </span>
                    )}
                  </div>
                  {s.description && (
                    <p className="mt-1 text-xs text-muted-foreground">{s.description}</p>
                  )}
                  {s.triggers.length > 0 && (
                    <p className="mt-1 text-[11px] text-muted-foreground">
                      Triggers: {s.triggers.join(', ')}
                    </p>
                  )}
                </div>
              </div>
              <div className="flex gap-1">
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() =>
                    setEditor({
                      id: s.id,
                      slug: s.slug,
                      name: s.name,
                      description: s.description ?? '',
                      bodyMarkdown: s.bodyMarkdown ?? '',
                      triggers: s.triggers.join(', '),
                      enabled: s.enabled,
                    })
                  }
                >
                  <Pencil className="h-3.5 w-3.5" />
                </Button>
                <Button
                  size="sm"
                  variant="ghost"
                  className="text-destructive hover:text-destructive"
                  onClick={() => {
                    if (confirm(`Delete skill "${s.name}"?`)) remove.mutate(s.id);
                  }}
                >
                  <Trash2 className="h-3.5 w-3.5" />
                </Button>
              </div>
            </div>
          ))
        )}
      </div>
      </div>
    </div>
  );
}

'use client';

import { Sparkles, Check, X } from 'lucide-react';
import Link from 'next/link';
import { useQuery } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuLabel,
} from '@/components/ui/dropdown-menu';
import { agentApi } from '@/lib/api';
import { useActiveSkillsStore } from '@/store/skills';

type Skill = {
  id: string;
  slug: string;
  name: string;
  description?: string | null;
  enabled: boolean;
};

export function SkillSelector() {
  const { activeSkillIds, toggleSkill, clear } = useActiveSkillsStore();

  const { data } = useQuery({
    queryKey: ['skills'],
    queryFn: async () => {
      const res = await agentApi.get('/skills');
      return (res.data?.skills ?? []) as Skill[];
    },
    retry: false,
  });

  const skills = (data ?? []).filter((s) => s.enabled);
  const activeCount = activeSkillIds.length;
  const label = activeCount > 0 ? `${activeCount} skill${activeCount > 1 ? 's' : ''}` : 'Skills';

  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        render={(props) => (
          <Button
            {...props}
            type="button"
            variant="outline"
            size="sm"
            title={`Active skills: ${activeCount}`}
            aria-label="Select active skills"
            className="rounded-full border-zinc-700 bg-zinc-900/70 text-zinc-200 hover:bg-zinc-800 dark:border-zinc-700"
          >
            <Sparkles className="mr-1.5 h-4 w-4" />
            <span className="max-w-[140px] truncate text-xs">{label}</span>
          </Button>
        )}
      />
      <DropdownMenuContent align="start" className="w-64">
        <DropdownMenuLabel>Skills (max 5)</DropdownMenuLabel>
        {skills.length === 0 && (
          <div className="px-2 py-3 text-xs text-muted-foreground">
            No enabled skills. Create one in Skills.
          </div>
        )}
        {skills.map((s) => {
          const active = activeSkillIds.includes(s.id);
          return (
            <DropdownMenuItem
              key={s.id}
              onClick={(e) => {
                e.preventDefault();
                toggleSkill(s.id);
              }}
              className="flex items-center justify-between"
            >
              <span className="truncate">{s.name}</span>
              {active && <Check className="h-3.5 w-3.5" />}
            </DropdownMenuItem>
          );
        })}
        {activeCount > 0 && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuItem
              onClick={(e) => {
                e.preventDefault();
                clear();
              }}
              className="text-muted-foreground"
            >
              <X className="mr-1.5 h-3.5 w-3.5" /> Clear selection
            </DropdownMenuItem>
          </>
        )}
        <DropdownMenuSeparator />
        <DropdownMenuItem render={(props) => <Link {...props} href="/skills" />}>
          Manage skills...
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

'use client';

import { Bot, Check } from 'lucide-react';
import Link from 'next/link';
import { useQuery } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuLabel,
} from '@/components/ui/dropdown-menu';
import { agentApi } from '@/lib/api';
import { usePersonaStore } from '@/store/persona';
import { cn } from '@/lib/utils';

type Persona = {
  id: string;
  slug: string;
  name: string;
  icon?: string | null;
  isDefault: boolean;
};

export function PersonaSelector({ compact }: { compact?: boolean }) {
  const { activePersonaId, activePersonaName, setActivePersona } = usePersonaStore();

  const { data } = useQuery({
    queryKey: ['personas'],
    queryFn: async () => {
      const res = await agentApi.get('/personas');
      return (res.data?.personas ?? []) as Persona[];
    },
    retry: false,
  });

  const personas = data ?? [];
  const currentName =
    activePersonaName ||
    personas.find((p) => p.id === activePersonaId)?.name ||
    personas.find((p) => p.isDefault)?.name ||
    'Default';

  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        render={(props) => (
          <Button
            {...props}
            type="button"
            variant="outline"
            size="sm"
            title={`Active persona: ${currentName}`}
            aria-label="Select assistant persona"
            className={cn(
              'rounded-full border-[#66686F] bg-[#202126] text-[#F2F2F2] hover:bg-[#27282E] dark:border-[#66686F]',
              compact && 'h-7 w-7 px-0',
            )}
          >
            <Bot className={cn('h-4 w-4', !compact && 'mr-1.5')} />
            {compact ? null : <span className="max-w-[120px] truncate text-xs">{currentName}</span>}
          </Button>
        )}
      />
      <DropdownMenuContent align="start" className="w-56">
        <DropdownMenuLabel>Persona</DropdownMenuLabel>
        <DropdownMenuItem
          onClick={() => setActivePersona(null, null)}
          className="flex items-center justify-between"
        >
          <span>Default (none)</span>
          {!activePersonaId && <Check className="h-3.5 w-3.5" />}
        </DropdownMenuItem>
        {personas.length > 0 && <DropdownMenuSeparator />}
        {personas.map((p) => (
          <DropdownMenuItem
            key={p.id}
            onClick={() => setActivePersona(p.id, p.name)}
            className="flex items-center justify-between"
          >
            <span className="truncate">{p.name}</span>
            {activePersonaId === p.id && <Check className="h-3.5 w-3.5" />}
          </DropdownMenuItem>
        ))}
        <DropdownMenuSeparator />
        <DropdownMenuItem render={(props) => <Link {...props} href="/personas" />}>
          Manage personas...
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

