'use client';

import { useState } from 'react';
import type React from 'react';
import { useRouter } from 'next/navigation';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Plus } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {workspaceApi , toastApiError} from '@/lib/api';

export type WorkspaceSummary = {
  id: string;
  name: string;
  storageUsed: number;
  storageLimit: number;
  createdAt: string;
  updatedAt: string;
};

type CreateWorkspaceDialogProps = {
  trigger?: React.ReactElement;
  redirectOnCreate?: boolean;
};

export function CreateWorkspaceDialog({ trigger, redirectOnCreate = true }: CreateWorkspaceDialogProps) {
  const [open, setOpen] = useState(false);
  const [name, setName] = useState('My Workspace');
  const router = useRouter();
  const queryClient = useQueryClient();

  const createWorkspace = useMutation({
    mutationFn: async () => {
      const res = await workspaceApi.post('/workspaces', { name: name.trim() });
      return res.data as WorkspaceSummary;
    },
    onSuccess: (workspace) => {
      queryClient.invalidateQueries({ queryKey: ['workspaces'] });
      toast.success('Workspace created.');
      setOpen(false);
      setName('My Workspace');
      if (redirectOnCreate) {
        router.push(`/workspace/${workspace.id}`);
      }
    },
    onError: (error) => {
      toastApiError(error, 'Could not create workspace.');
    },
  });

  const handleSubmit = (event: React.FormEvent) => {
    event.preventDefault();
    if (!name.trim()) return;
    createWorkspace.mutate();
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger
        render={
          trigger || (
            <Button>
              <Plus data-icon="inline-start" />
              New Workspace
            </Button>
          )
        }
      />
      <DialogContent>
        <form onSubmit={handleSubmit} className="space-y-4">
          <DialogHeader>
            <DialogTitle>Create workspace</DialogTitle>
            <DialogDescription>Start with README and sample source files.</DialogDescription>
          </DialogHeader>
          <div className="space-y-2">
            <Label htmlFor="workspace-name">Name</Label>
            <Input
              id="workspace-name"
              value={name}
              onChange={(event) => setName(event.target.value)}
              placeholder="My Workspace"
              autoFocus
            />
          </div>
          <DialogFooter>
            <DialogClose render={<Button type="button" variant="outline" />}>Cancel</DialogClose>
            <Button type="submit" disabled={!name.trim() || createWorkspace.isPending}>
              {createWorkspace.isPending ? 'Creating...' : 'Create'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useRef, useState, useEffect, useCallback } from 'react';
import { Plus, TerminalSquare, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import { cn } from '@/lib/utils';

const BLOCKED_PATTERNS = [
  /^rm\s+-rf\s+\//,
  /^sudo\b/,
  /^shutdown\b/,
  /^reboot\b/,
  /^halt\b/,
  /^mkfs\b/,
  /^dd\s+if=/,
  /:\(\)\{\s*:\|:&\s*\};:/,
  /^chmod\s+-R\s+777\s+\//,
  /^chown\s+-R\b/,
];

type TerminalLine = {
  id: number;
  type: 'input' | 'output' | 'error' | 'blocked';
  text: string;
  timestamp: Date;
};

type TerminalSession = {
  id: string;
  name: string;
  lines: TerminalLine[];
};

let lineIdCounter = 0;

export default function TerminalPage() {
  const [sessions, setSessions] = useState<TerminalSession[]>([
    { id: 'default', name: 'Terminal 1', lines: [] },
  ]);
  const [activeSessionId, setActiveSessionId] = useState('default');
  const [input, setInput] = useState('');
  const [history, setHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [deleteTarget, setDeleteTarget] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  const activeSession = sessions.find((s) => s.id === activeSessionId) || sessions[0];

  useEffect(() => {
    scrollRef.current?.scrollTo(0, scrollRef.current.scrollHeight);
  }, [activeSession?.lines.length]);

  const addLine = useCallback((sessionId: string, type: TerminalLine['type'], text: string) => {
    setSessions((prev) =>
      prev.map((s) =>
        s.id === sessionId
          ? { ...s, lines: [...s.lines, { id: ++lineIdCounter, type, text, timestamp: new Date() }] }
          : s
      )
    );
  }, []);

  const isBlocked = (cmd: string) => BLOCKED_PATTERNS.some((p) => p.test(cmd.trim()));

  const executeCommand = useCallback(
    async (cmd: string) => {
      if (!activeSession) return;
      addLine(activeSession.id, 'input', `$ ${cmd}`);
      setHistory((prev) => [...prev, cmd]);
      setHistoryIndex(-1);

      if (isBlocked(cmd)) {
        addLine(activeSession.id, 'blocked', `⛔ Command blocked: "${cmd}" is not allowed for security reasons.`);
        return;
      }

      // Simulate command execution (real implementation would hit runtime service)
      try {
        addLine(activeSession.id, 'output', `[mock] Command "${cmd}" would execute in workspace sandbox`);
      } catch {
        addLine(activeSession.id, 'error', `Error executing command`);
      }
    },
    [activeSession, addLine]
  );

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cmd = input.trim();
    if (!cmd) return;
    setInput('');
    executeCommand(cmd);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (history.length > 0) {
        const newIndex = historyIndex === -1 ? history.length - 1 : Math.max(0, historyIndex - 1);
        setHistoryIndex(newIndex);
        setInput(history[newIndex] || '');
      }
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (historyIndex >= 0) {
        const newIndex = historyIndex + 1;
        if (newIndex >= history.length) {
          setHistoryIndex(-1);
          setInput('');
        } else {
          setHistoryIndex(newIndex);
          setInput(history[newIndex] || '');
        }
      }
    }
  };

  const addSession = () => {
    const id = `term-${Date.now()}`;
    const name = `Terminal ${sessions.length + 1}`;
    setSessions((prev) => [...prev, { id, name, lines: [] }]);
    setActiveSessionId(id);
  };

  const removeSession = (id: string) => {
    setSessions((prev) => {
      const next = prev.filter((s) => s.id !== id);
      if (next.length === 0) {
        const fallback = { id: 'default', name: 'Terminal 1', lines: [] as TerminalLine[] };
        return [fallback];
      }
      return next;
    });
    if (activeSessionId === id) {
      setActiveSessionId(sessions.find((s) => s.id !== id)?.id || 'default');
    }
  };

  return (
    <div className="flex h-full flex-col bg-background">
      {/* Session Tabs */}
      <div className="flex h-10 items-center gap-0.5 border-b border-border bg-card px-2">
        {sessions.map((s) => (
          <button
            key={s.id}
            type="button"
            onClick={() => setActiveSessionId(s.id)}
            className={cn(
              'group flex h-8 items-center gap-1.5 rounded-md px-3 text-xs font-medium transition-colors',
              activeSessionId === s.id
                ? 'bg-primary/10 text-primary'
                : 'text-muted-foreground hover:bg-muted hover:text-foreground'
            )}
          >
            <TerminalSquare className="h-3 w-3" />
            <span>{s.name}</span>
            {sessions.length > 1 && (
              <button
                type="button"
                title="Close session"
                aria-label={`Close ${s.name}`}
                className="ml-1 rounded p-0.5 opacity-0 hover:bg-muted group-hover:opacity-100"
                onClick={(e) => { e.stopPropagation(); setDeleteTarget(s.id); }}
              >
                <X className="h-3 w-3" />
              </button>
            )}
          </button>
        ))}
        <Button size="icon-xs" variant="ghost" onClick={addSession} title="New terminal" aria-label="New terminal">
          <Plus className="h-3 w-3" />
        </Button>
      </div>

      {/* Terminal Output */}
      <div
        ref={scrollRef}
        className="min-h-0 flex-1 overflow-auto bg-[#0d1117] p-4 font-mono text-sm"
        onClick={() => inputRef.current?.focus()}
      >
        {activeSession && activeSession.lines.length === 0 && (
          <div className="text-zinc-500">
            CloudMind OS Terminal — workspace sandbox
            <br />
            Type a command to get started.
          </div>
        )}
        {activeSession?.lines.map((line) => (
          <div
            key={line.id}
            className={cn(
              'whitespace-pre-wrap py-0.5',
              line.type === 'input' && 'text-emerald-400',
              line.type === 'output' && 'text-zinc-300',
              line.type === 'error' && 'text-red-400',
              line.type === 'blocked' && 'text-amber-400'
            )}
          >
            {line.text}
          </div>
        ))}

        {/* Input */}
        <form onSubmit={handleSubmit} className="mt-1 flex items-center gap-1">
          <span className="text-emerald-400">$</span>
          <input
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            className="flex-1 border-none bg-transparent text-zinc-100 outline-none placeholder:text-zinc-600"
            placeholder="Type a command..."
            autoFocus
            spellCheck={false}
            aria-label="Terminal input"
          />
        </form>
      </div>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={() => setDeleteTarget(null)}
        title="Close terminal session"
        description="This will end the session and clear its history."
        confirmLabel="Close"
        variant="destructive"
        onConfirm={() => {
          if (deleteTarget) removeSession(deleteTarget);
        }}
      />
    </div>
  );
}

'use client';

import Link from 'next/link';
import { useQuery } from '@tanstack/react-query';
import {
  ArrowRight,
  Boxes,
  Camera,
  Clock3,
  Cpu,
  Database,
  Globe,
  Globe2,
  Layers3,
  Server,
  Sparkles,
} from 'lucide-react';
import { agentApi, browserApi, publishApi, workspaceApi } from '@/lib/api';
import { formatBytes, formatDate } from '@/lib/format';

type Workspace = {
  id: string;
  name: string;
  storageUsed: number;
  storageLimit: number;
  updatedAt: string;
};

type WorkspacesResponse = {
  workspaces: Workspace[];
};

type HostedService = {
  id: string;
  name: string;
  status: string;
  url?: string | null;
  updatedAt: string;
};

type BrowserSession = {
  id: string;
  url?: string;
  title?: string;
  createdAt: string;
  lastActiveAt: string;
};

type Automation = {
  id: string;
  name: string;
  schedule: string;
  enabled: boolean;
  lastRunAt: string | null;
};

function StatTile({
  icon: Icon,
  label,
  value,
  href,
  caption,
}: {
  icon: React.ComponentType<{ className?: string }>;
  label: string;
  value: string | number;
  href?: string;
  caption?: string;
}) {
  const inner = (
    <div className="flex items-start gap-4 rounded-xl border border-border bg-card p-4 transition hover:border-foreground/30">
      <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10 text-primary">
        <Icon className="h-5 w-5" />
      </div>
      <div className="min-w-0 flex-1">
        <div className="text-xs uppercase tracking-wide text-muted-foreground">{label}</div>
        <div className="mt-1 text-2xl font-semibold text-foreground">{value}</div>
        {caption ? (
          <div className="mt-1 truncate text-xs text-muted-foreground">{caption}</div>
        ) : null}
      </div>
      {href ? <ArrowRight className="mt-1 h-4 w-4 text-muted-foreground" /> : null}
    </div>
  );
  return href ? <Link href={href}>{inner}</Link> : inner;
}

export default function ComputerPage() {
  const workspacesQuery = useQuery({
    queryKey: ['computer', 'workspaces'],
    queryFn: async () => (await workspaceApi.get('/workspaces')).data as WorkspacesResponse,
    retry: false,
  });

  const servicesQuery = useQuery({
    queryKey: ['computer', 'hosted-services'],
    queryFn: async () => (await publishApi.get('/hosted-services')).data as HostedService[],
    retry: false,
  });

  const browserQuery = useQuery({
    queryKey: ['computer', 'browser-sessions'],
    queryFn: async () => {
      const res = await browserApi.get('/browser/sessions');
      return (res.data?.sessions ?? res.data ?? []) as BrowserSession[];
    },
    retry: false,
  });

  const automationsQuery = useQuery({
    queryKey: ['computer', 'automations'],
    queryFn: async () => {
      const res = await agentApi.get('/automations');
      return (res.data?.automations ?? res.data ?? []) as Automation[];
    },
    retry: false,
  });

  const workspaces = workspacesQuery.data?.workspaces ?? [];
  const services = Array.isArray(servicesQuery.data) ? servicesQuery.data : [];
  const browserSessions = Array.isArray(browserQuery.data) ? browserQuery.data : [];
  const automations = Array.isArray(automationsQuery.data) ? automationsQuery.data : [];

  const runningServices = services.filter((s) => s.status === 'running').length;
  const enabledAutomations = automations.filter((a) => a.enabled).length;
  const totalStorage = workspaces.reduce((sum, w) => sum + (w.storageUsed ?? 0), 0);

  return (
    <div className="flex-1 overflow-auto p-6 lg:p-8">
      <header className="mb-6 flex items-start gap-3">
        <div className="flex h-11 w-11 items-center justify-center rounded-lg bg-primary/10 text-primary">
          <Layers3 className="h-6 w-6" />
        </div>
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Computer</h1>
          <p className="mt-1 max-w-2xl text-sm text-muted-foreground">
            A live snapshot of everything currently running for you: workspaces, hosted services,
            cloud browser sessions, and scheduled automations.
          </p>
        </div>
      </header>

      <section className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">
        <StatTile
          icon={Server}
          label="Workspaces"
          value={workspaces.length}
          href="/workspaces"
          caption={
            workspaces.length > 0
              ? `${formatBytes(totalStorage)} used across all workspaces`
              : 'No workspaces yet'
          }
        />
        <StatTile
          icon={Globe2}
          label="Hosted services"
          value={`${runningServices}/${services.length}`}
          href="/hosting"
          caption={
            services.length > 0
              ? `${runningServices} running, ${services.length - runningServices} stopped`
              : 'Nothing deployed'
          }
        />
        <StatTile
          icon={Globe}
          label="Browser sessions"
          value={browserSessions.length}
          href="/browser"
          caption={
            browserSessions[0]?.url
              ? (() => {
                  try {
                    return `Latest: ${new URL(browserSessions[0]!.url!).hostname}`;
                  } catch {
                    return 'Active';
                  }
                })()
              : 'No active sessions'
          }
        />
        <StatTile
          icon={Clock3}
          label="Automations"
          value={`${enabledAutomations}/${automations.length}`}
          href="/automations"
          caption={
            automations.length > 0
              ? `${enabledAutomations} enabled, ${automations.length - enabledAutomations} paused`
              : 'No automations yet'
          }
        />
      </section>

      <section className="mt-8 grid gap-4 lg:grid-cols-2">
        <div className="rounded-xl border border-border bg-card">
          <div className="flex items-center justify-between border-b border-border px-4 py-3">
            <div className="flex items-center gap-2">
              <Globe2 className="h-4 w-4 text-muted-foreground" />
              <h2 className="text-sm font-semibold text-foreground">Hosted services</h2>
            </div>
            <Link
              href="/hosting"
              className="text-xs text-muted-foreground hover:text-foreground"
            >
              Manage →
            </Link>
          </div>
          {servicesQuery.isLoading ? (
            <div className="p-4 text-sm text-muted-foreground">Loading…</div>
          ) : services.length === 0 ? (
            <div className="p-4 text-sm text-muted-foreground">No services deployed yet.</div>
          ) : (
            <ul className="divide-y divide-border">
              {services.slice(0, 5).map((svc) => (
                <li key={svc.id} className="flex items-center justify-between px-4 py-3">
                  <div className="min-w-0">
                    <div className="truncate text-sm font-medium text-foreground">{svc.name}</div>
                    {svc.url ? (
                      <a
                        href={svc.url}
                        target="_blank"
                        rel="noreferrer"
                        className="truncate text-xs text-muted-foreground hover:text-foreground"
                      >
                        {svc.url}
                      </a>
                    ) : null}
                  </div>
                  <span
                    className={`rounded-full px-2 py-0.5 text-xs ${
                      svc.status === 'running'
                        ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400'
                        : 'bg-muted text-muted-foreground'
                    }`}
                  >
                    {svc.status}
                  </span>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="rounded-xl border border-border bg-card">
          <div className="flex items-center justify-between border-b border-border px-4 py-3">
            <div className="flex items-center gap-2">
              <Globe className="h-4 w-4 text-muted-foreground" />
              <h2 className="text-sm font-semibold text-foreground">Browser sessions</h2>
            </div>
            <Link
              href="/browser"
              className="text-xs text-muted-foreground hover:text-foreground"
            >
              Open →
            </Link>
          </div>
          {browserQuery.isLoading ? (
            <div className="p-4 text-sm text-muted-foreground">Loading…</div>
          ) : browserSessions.length === 0 ? (
            <div className="p-4 text-sm text-muted-foreground">No active sessions.</div>
          ) : (
            <ul className="divide-y divide-border">
              {browserSessions.slice(0, 5).map((s) => (
                <li key={s.id} className="px-4 py-3 text-sm">
                  <div className="truncate font-medium text-foreground">
                    {s.title || s.url || s.id}
                  </div>
                  <div className="mt-1 text-xs text-muted-foreground">
                    Last active {formatDate(s.lastActiveAt)}
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="rounded-xl border border-border bg-card">
          <div className="flex items-center justify-between border-b border-border px-4 py-3">
            <div className="flex items-center gap-2">
              <Clock3 className="h-4 w-4 text-muted-foreground" />
              <h2 className="text-sm font-semibold text-foreground">Automations</h2>
            </div>
            <Link
              href="/automations"
              className="text-xs text-muted-foreground hover:text-foreground"
            >
              Manage →
            </Link>
          </div>
          {automationsQuery.isLoading ? (
            <div className="p-4 text-sm text-muted-foreground">Loading…</div>
          ) : automations.length === 0 ? (
            <div className="p-4 text-sm text-muted-foreground">No automations scheduled.</div>
          ) : (
            <ul className="divide-y divide-border">
              {automations.slice(0, 5).map((a) => (
                <li key={a.id} className="flex items-center justify-between px-4 py-3 text-sm">
                  <div className="min-w-0">
                    <div className="truncate font-medium text-foreground">{a.name}</div>
