];

const LINT_FILTERS = ['--filter', 'web', '--filter', '@pcp/db'];
const TEST_FILTERS = [
  '--filter',
  '@pcp/auth-service',
  '--filter',
  '@pcp/workspace-service',
  '--filter',
  '@pcp/runtime-service',
  '--filter',
