interface LoadingSkeletonProps {
  className?: string;
  lines?: number;
  variant?: 'text' | 'card' | 'avatar' | 'button';
}

function SkeletonLine({ className }: { className?: string }) {
  return <div className={cn('h-4 animate-pulse rounded-md bg-muted', className)} />;
}

export function LoadingSkeleton({ className, lines = 3, variant = 'text' }: LoadingSkeletonProps) {
  if (variant === 'card') {
    return (
      <div className={cn('space-y-3 rounded-xl border border-border bg-card p-4', className)}>
        <SkeletonLine className="h-5 w-2/3" />
        <SkeletonLine className="h-4 w-full" />
        <SkeletonLine className="h-4 w-4/5" />
        <SkeletonLine className="h-8 w-24" />
      </div>
    );
  }

  if (variant === 'avatar') {
    return (
      <div className={cn('flex items-center gap-3', className)}>
        <div className="h-10 w-10 shrink-0 animate-pulse rounded-full bg-muted" />
        <div className="flex-1 space-y-2">
          <SkeletonLine className="h-4 w-32" />
          <SkeletonLine className="h-3 w-48" />
        </div>
      </div>
    );
  }

  if (variant === 'button') {
    return <SkeletonLine className={cn('h-8 w-20 rounded-lg', className)} />;
  }

  return (
    <div className={cn('space-y-2', className)}>
      {Array.from({ length: lines }, (_, i) => (
        <SkeletonLine key={i} className={i === lines - 1 ? 'w-3/5' : 'w-full'} />
      ))}
    </div>
  );
}

import { cn } from '@/lib/utils';

const variants = {
  default: 'bg-muted text-muted-foreground',
  success: 'bg-emerald-500/10 text-emerald-500 dark:bg-emerald-500/15',
  warning: 'bg-amber-500/10 text-amber-600 dark:bg-amber-500/15 dark:text-amber-400',
  error: 'bg-destructive/10 text-destructive',
  info: 'bg-blue-500/10 text-blue-600 dark:bg-blue-500/15 dark:text-blue-400',
  running: 'bg-emerald-500/10 text-emerald-500',
  stopped: 'bg-zinc-500/10 text-zinc-500',
  pending: 'bg-amber-500/10 text-amber-500',
} as const;

interface StatusBadgeProps {
  variant?: keyof typeof variants;
  children: React.ReactNode;
  className?: string;
  dot?: boolean;
}

export function StatusBadge({ variant = 'default', children, className, dot = false }: StatusBadgeProps) {
  return (
    <span
      className={cn(
        'inline-flex items-center gap-1.5 rounded-md px-2 py-0.5 text-xs font-medium',
        variants[variant],
        className,
      )}
    >
      {dot && (
        <span className={cn(
          'h-1.5 w-1.5 rounded-full',
          variant === 'running' && 'bg-emerald-500 animate-pulse',
          variant === 'stopped' && 'bg-zinc-500',
          variant === 'error' && 'bg-destructive',
          variant === 'pending' && 'bg-amber-500',
          variant === 'success' && 'bg-emerald-500',
          variant === 'warning' && 'bg-amber-500',
          variant === 'info' && 'bg-blue-500',
          variant === 'default' && 'bg-muted-foreground',
        )} />
      )}
      {children}
    </span>
  );
}

