'use client';

import { useMemo, useRef, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Database, Upload, Trash2, Play, Eye, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import axios from 'axios';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { workspaceApi, apiEndpoints, toastApiError} from '@/lib/api';

type Dataset = {
  id: string;
  name: string;
  tableName: string;
  sourceType: string;
  sourceFilename: string | null;
  columns: Array<{ name: string; type: string }>;
  rowCount: number;
  sizeBytes: number;
  createdAt: string;
};

type QueryResult = {
  columns: Array<{ name: string; type: string }>;
  rows: unknown[][];
  rowCount: number;
  truncated: boolean;
  durationMs: number;
};

const ACCEPT = '.csv,.tsv,.json,.ndjson,.jsonl,.parquet';

export default function DatasetsPage() {
  const qc = useQueryClient();
  const fileRef = useRef<HTMLInputElement>(null);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [sql, setSql] = useState('');
  const [result, setResult] = useState<QueryResult | null>(null);

  const { data, isLoading } = useQuery({
    queryKey: ['datasets'],
    queryFn: async () => {
      const res = await workspaceApi.get('/datasets');
      return (res.data?.datasets ?? []) as Dataset[];
    },
    retry: false,
  });
  const datasets = useMemo(() => data ?? [], [data]);
  const active = useMemo(
    () => datasets.find((d) => d.id === activeId) ?? null,
    [datasets, activeId],
  );

  const importMut = useMutation({
    mutationFn: async (file: File) => {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('name', file.name.replace(/\.[^.]+$/, ''));
      const res = await axios.post(`${apiEndpoints.workspace}/datasets/import`, fd, {
        withCredentials: true,
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      return res.data as Dataset;
    },
    onSuccess: (ds) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      setActiveId(ds.id);
      setSql(`SELECT * FROM "${ds.tableName}" LIMIT 100`);
      toast.success(
        `Imported ${ds.rowCount.toLocaleString()} rows from ${ds.sourceFilename ?? ds.name}.`,
      );
    },
    onError: (e) => toastApiError(e, 'Import failed.'),
  });

  const removeMut = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.delete(`/datasets/${id}`);
    },
    onSuccess: (_, id) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      if (activeId === id) {
        setActiveId(null);
        setResult(null);
      }
      toast.success('Dataset removed.');
    },
    onError: (e) => toastApiError(e, 'Could not remove dataset.'),
  });

  const queryMut = useMutation({
    mutationFn: async (q: string) => {
      const res = await workspaceApi.post(`/datasets/query`, { sql: q, rowLimit: 500 });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Query failed.'),
  });

  const previewMut = useMutation({
    mutationFn: async (id: string) => {
      const res = await workspaceApi.get(`/datasets/${id}/preview`, { params: { limit: 50 } });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Preview failed.'),
  });

  const onPickFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    importMut.mutate(f);
    e.target.value = '';
  };

  return (
    <div className="mx-auto flex max-w-6xl flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Database className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Datasets</h2>
          <p className="text-sm text-muted-foreground">
            Upload CSV, JSON, or Parquet files into your private DuckDB and query them with SQL.
          </p>
        </div>
        <input ref={fileRef} type="file" accept={ACCEPT} onChange={onPickFile} className="hidden" />
        <Button onClick={() => fileRef.current?.click()} disabled={importMut.isPending}>
          {importMut.isPending ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Upload className="mr-1.5 h-3.5 w-3.5" />
          )}
          {importMut.isPending ? 'Importing...' : 'Import file'}
        </Button>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-[260px_1fr]">
        <aside className="rounded-xl border border-border bg-card p-3">
          <h3 className="mb-2 px-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Catalog
          </h3>
          {isLoading ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">Loading...</p>
          ) : datasets.length === 0 ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">
              No datasets yet. Import a file to get started.
            </p>
          ) : (
            <ul className="space-y-1">
              {datasets.map((d) => (
                <li key={d.id}>
                  <button
                    type="button"
                    onClick={() => {
                      setActiveId(d.id);
                      setSql(`SELECT * FROM "${d.tableName}" LIMIT 100`);
                    }}
                    className={`group flex w-full items-start justify-between gap-2 rounded-lg px-2 py-2 text-left text-sm transition-colors hover:bg-muted ${
                      activeId === d.id ? 'bg-muted' : ''
                    }`}
                  >
                    <div className="min-w-0 flex-1">
                      <div className="truncate font-medium text-foreground">{d.name}</div>
                      <div className="truncate text-[11px] text-muted-foreground">
                        {d.tableName} · {d.rowCount.toLocaleString()} rows · {d.columns.length} cols
                      </div>
                    </div>
                    <span
                      role="button"
                      tabIndex={0}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                        }
                      }}
                      className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <main className="space-y-4">
          {active ? (
            <div className="rounded-xl border border-border bg-card p-4">
              <div className="mb-3 flex flex-wrap items-center gap-2">
                <h3 className="font-medium text-foreground">{active.name}</h3>
                <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono uppercase text-muted-foreground">
                  {active.sourceType}
                </span>
                <span className="text-xs text-muted-foreground">
                  table <code className="font-mono">{active.tableName}</code>
                </span>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => previewMut.mutate(active.id)}
                  disabled={previewMut.isPending}
                  className="ml-auto"
                >
                  <Eye className="mr-1.5 h-3.5 w-3.5" />
                  Preview
                </Button>
              </div>

              <div className="mb-2">
                <Label className="text-xs text-muted-foreground">SQL</Label>
                <textarea
                  value={sql}
                  onChange={(e) => setSql(e.target.value)}
                  rows={5}
                  className="mt-1 w-full rounded-md border border-input bg-background px-3 py-2 font-mono text-xs text-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                  placeholder={`SELECT * FROM "${active.tableName}" LIMIT 100`}
                />
              </div>
              <div className="flex justify-end">
                <Button
                  size="sm"
                  onClick={() => sql.trim() && queryMut.mutate(sql)}
                  disabled={!sql.trim() || queryMut.isPending}
                >
                  {queryMut.isPending ? (
                    <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
                  ) : (
                    <Play className="mr-1.5 h-3.5 w-3.5" />
                  )}
                  Run
                </Button>
              </div>
            </div>
          ) : (
            <div className="rounded-xl border border-dashed border-border p-10 text-center text-sm text-muted-foreground">
              Select a dataset on the left or import a new file.
            </div>
          )}

          {result && (
            <div className="rounded-xl border border-border bg-card p-3">
              <div className="mb-2 flex items-center justify-between text-xs text-muted-foreground">
                <span>
                  {result.rowCount} rows · {result.durationMs}ms
                  {result.truncated && ' · truncated'}
                </span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="border-b border-border">
                      {result.columns.map((c) => (
                        <th
                          key={c.name}
                          className="whitespace-nowrap px-2 py-1.5 text-left font-medium text-foreground"
                        >
                          {c.name}
                          <span className="ml-1 text-[10px] font-normal text-muted-foreground">
                            {c.type}
                          </span>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {result.rows.map((row, i) => (
                      <tr key={i} className="border-b border-border/50 last:border-0">
                        {row.map((cell, j) => (
                          <td
                            key={j}
                            className="max-w-[280px] truncate whitespace-nowrap px-2 py-1 font-mono text-muted-foreground"
                          >
                            {formatCell(cell)}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

function formatCell(v: unknown): string {
  if (v === null || v === undefined) return '—';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'bigint') return String(v);
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Camera, RotateCcw } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import {workspaceApi , toastApiError} from '@/lib/api';
import { formatDate } from '@/lib/format';

type WorkspacesResponse = {
  workspaces?: { id: string }[];
};

type Snapshot = {
  id: string;
  name: string;
  description?: string | null;
  createdAt: string;
};

export default function SnapshotsPage() {
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [restoreTarget, setRestoreTarget] = useState<Snapshot | null>(null);

  // We need a workspaceId. For now, get user's first workspace.
  const { data: wsData } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaceId = wsData?.workspaces?.[0]?.id;

  const { data: snapshots, isLoading } = useQuery({
    queryKey: ['snapshots', workspaceId],
    enabled: Boolean(workspaceId),
    queryFn: async () => {
      const res = await workspaceApi.get(`/workspaces/${workspaceId}/snapshots`);
      return (res.data as { snapshots: Snapshot[] }).snapshots;
    },
  });

  const createMutation = useMutation({
    mutationFn: async () => {
      await workspaceApi.post(`/workspaces/${workspaceId}/snapshots`, { name, description });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot created');
      setShowCreate(false);
      setName('');
      setDescription('');
    },
    onError: (e) => toastApiError(e, 'Failed to create snapshot'),
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.post(`/snapshots/${id}/restore`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot restored. A safety backup was created.');
      setRestoreTarget(null);
    },
    onError: (e) => toastApiError(e, 'Failed to restore'),
  });

  const items = snapshots || [];

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Snapshots</h2>
          <p className="text-sm text-muted-foreground">Backup and restore your workspace</p>
        </div>
        <Button size="sm" onClick={() => setShowCreate((v) => !v)} disabled={!workspaceId}>
          <Camera className="mr-1.5 h-3.5 w-3.5" />
          Create Snapshot
        </Button>
      </div>

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (name.trim()) createMutation.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-[1fr_1fr_auto] md:items-end"
        >
          <div className="space-y-1.5">
            <Label htmlFor="snap-name">Name</Label>
            <Input
              id="snap-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Before refactoring"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="snap-desc">Description (optional)</Label>
            <Input
              id="snap-desc"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Details about this state..."
            />
          </div>
          <Button type="submit" size="sm" disabled={!name.trim() || createMutation.isPending}>
            {createMutation.isPending ? 'Creating...' : 'Create'}
          </Button>
        </form>
      )}

      <div className="mt-6">
        {isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : items.length > 0 ? (
          <div className="space-y-3">
            {items.map((snap) => (
              <div
                key={snap.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
              >
                <div className="flex min-w-0 items-center gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                    <Camera className="h-5 w-5 text-primary" />
                  </div>
                  <div className="min-w-0">
                    <h3 className="font-medium text-foreground">{snap.name}</h3>
                    <p className="text-xs text-muted-foreground">
                      {snap.description || 'No description'} · {formatDate(snap.createdAt)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" variant="outline" onClick={() => setRestoreTarget(snap)}>
                    <RotateCcw className="mr-1 h-3.5 w-3.5" /> Restore
                  </Button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState
            icon={<Camera className="h-6 w-6" />}
            title="No snapshots yet"
            description="Create a snapshot to backup your current workspace state. You can restore it anytime."
            action={{
              label: 'Create first snapshot',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(restoreTarget)}
        onOpenChange={() => setRestoreTarget(null)}
        title="Restore snapshot"
        description={`This will overwrite your current workspace with "${restoreTarget?.name}". A safety backup will be created automatically before the restore begins. This cannot be undone.`}
        confirmLabel="Yes, restore"
        variant="destructive"
        onConfirm={async () => {
          if (restoreTarget) await restoreMutation.mutateAsync(restoreTarget.id);
        }}
      />
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  Clock3,
  History,
  Loader2,
  MoreHorizontal,
  Pause,
  Play,
  Plus,
  Trash2,
  Webhook,
  Zap,
} from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { EmptyState } from '@/components/ui/empty-state';
import { StatusBadge } from '@/components/ui/status-badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { agentApi, apiEndpoints, toastApiError} from '@/lib/api';
import { cn } from '@/lib/utils';
import { CreateAutomationDialog } from '@/components/automations/create-automation-dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

type Tab = 'active' | 'paused' | 'history';

type Automation = {
  id: string;
  title: string;
  enabled: boolean;
  scheduleType: 'manual' | 'hourly' | 'daily' | 'weekly' | 'cron';
  cronExpression?: string | null;
  prompt?: string | null;
  lastRunAt?: string | null;
  nextRunAt?: string | null;
  notificationMode?: string | null;
};

type AutomationRun = {
  id: string;
  status: 'queued' | 'running' | 'completed' | 'failed';
  trigger: string;
  startedAt: string | null;
  finishedAt: string | null;
  durationMs: string | null;
  error: string | null;
  output: string | null;
  createdAt: string;
};

const tabs: { id: Tab; label: string }[] = [
  { id: 'active', label: 'Active' },
  { id: 'paused', label: 'Paused' },
  { id: 'history', label: 'History' },
];

function formatRelative(value: string | null | undefined) {
  if (!value) return '—';
  const diff = new Date(value).getTime() - Date.now();
  const abs = Math.abs(diff);
  const min = Math.round(abs / 60_000);
  if (min < 1) return diff >= 0 ? 'in <1m' : 'just now';
  if (min < 60) return diff >= 0 ? `in ${min}m` : `${min}m ago`;
  const hr = Math.round(min / 60);
  if (hr < 24) return diff >= 0 ? `in ${hr}h` : `${hr}h ago`;
  const day = Math.round(hr / 24);
  return diff >= 0 ? `in ${day}d` : `${day}d ago`;
}

function describeSchedule(a: Automation) {
  if (a.scheduleType === 'cron' && a.cronExpression) return `cron · ${a.cronExpression}`;
  return a.scheduleType;
}

export default function AutomationsPage() {
  const [activeTab, setActiveTab] = useState<Tab>('active');
  const [historyId, setHistoryId] = useState<string | null>(null);
  const [createOpen, setCreateOpen] = useState(false);
  const queryClient = useQueryClient();

  const { data: automations, isLoading } = useQuery({
    queryKey: ['automations'],
    queryFn: async () => {
      const res = await agentApi.get('/automations');
      const payload = res.data as { automations: Automation[] } | Automation[];
      return Array.isArray(payload) ? payload : payload.automations;
    },
  });

  const toggleMutation = useMutation({
    mutationFn: async ({ id, enabled }: { id: string; enabled: boolean }) => {
      await agentApi.patch(`/automations/${id}`, { enabled });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation updated');
    },
    onError: (e) => toastApiError(e, 'Failed to update'),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.delete(`/automations/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation deleted');
    },
    onError: (e) => toastApiError(e, 'Failed to delete'),
  });

  const runMutation = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.post(`/automations/${id}/run`);
    },
    onSuccess: () => {
      toast.success('Automation triggered');
    },
    onError: (e) => toastApiError(e, 'Failed to run'),
  });

  const copyWebhookUrl = useMutation({
    mutationFn: async (id: string) => {
      const res = await agentApi.get(`/automations/${id}/trigger-token`);
      const { token } = res.data as { token: string };
      const url = `${apiEndpoints.agent}/automations/${id}/trigger?token=${token}`;
      await navigator.clipboard.writeText(url);
      return url;
    },
    onSuccess: () => toast.success('Webhook URL copied'),
    onError: (e) => toastApiError(e, 'Failed to fetch token'),
  });

  const all = automations || [];
  const filtered =
    activeTab === 'active'
      ? all.filter((a) => a.enabled)
      : activeTab === 'paused'
        ? all.filter((a) => !a.enabled)
        : all;

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Automations</h2>
          <p className="text-sm text-muted-foreground">Schedule AI tasks to run automatically</p>
        </div>
        <Button size="sm" onClick={() => setCreateOpen(true)}>
          <Plus className="mr-1.5 h-3.5 w-3.5" />
          Create Automation
        </Button>
      </div>

      <div className="mt-4 flex gap-1 border-b border-border">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            type="button"
            onClick={() => setActiveTab(tab.id)}
            className={cn(
              'border-b-2 px-4 py-2 text-sm font-medium transition-colors',
              activeTab === tab.id
                ? 'border-primary text-primary'
                : 'border-transparent text-muted-foreground hover:text-foreground',
            )}
          >
            {tab.label}
          </button>
        ))}
      </div>

      <div className="mt-6">
        {isLoading ? (
          <div className="flex justify-center py-12">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : filtered.length > 0 ? (
          <div className="space-y-3">
            {filtered.map((auto) => (
              <div
                key={auto.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
              >
                <div className="flex min-w-0 items-center gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                    <Zap className="h-5 w-5 text-primary" />
                  </div>
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <h3 className="truncate font-medium text-foreground">{auto.title}</h3>
                      <StatusBadge variant={auto.enabled ? 'success' : 'stopped'} dot>
                        {auto.enabled ? 'Active' : 'Paused'}
                      </StatusBadge>
                    </div>
                    <p className="truncate text-xs text-muted-foreground">
                      {describeSchedule(auto)}
                      {auto.prompt ? ` · ${auto.prompt.slice(0, 60)}…` : ''}
                    </p>
                    <div className="mt-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[11px] text-muted-foreground">
                      <span title={auto.nextRunAt ?? undefined}>
                        Next: <span className="text-foreground/80">{formatRelative(auto.nextRunAt)}</span>
                      </span>
                      <span title={auto.lastRunAt ?? undefined}>
                        Last: <span className="text-foreground/80">{formatRelative(auto.lastRunAt)}</span>
                      </span>
                      {auto.notificationMode && auto.notificationMode !== 'none' && (
                        <span>Notify: {auto.notificationMode}</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => runMutation.mutate(auto.id)}
                    disabled={runMutation.isPending}
                  >
                    <Play className="mr-1 h-3.5 w-3.5" /> Run
                  </Button>
                  <DropdownMenu>
                    <DropdownMenuTrigger
                      render={(props) => (
                        <Button {...props} size="sm" variant="ghost">
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      )}
                    />
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem onClick={() => setHistoryId(auto.id)}>
                        <History className="mr-2 h-4 w-4" /> View history
                      </DropdownMenuItem>
                      <DropdownMenuItem onClick={() => copyWebhookUrl.mutate(auto.id)}>
                        <Webhook className="mr-2 h-4 w-4" /> Copy webhook URL
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={() =>
                          toggleMutation.mutate({ id: auto.id, enabled: !auto.enabled })
                        }
                      >
                        {auto.enabled ? (
                          <>
                            <Pause className="mr-2 h-4 w-4" /> Pause
                          </>
                        ) : (
                          <>
                            <Play className="mr-2 h-4 w-4" /> Resume
                          </>
                        )}
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        className="text-destructive"
                        onClick={() => deleteMutation.mutate(auto.id)}
                      >
                        <Trash2 className="mr-2 h-4 w-4" /> Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState
            icon={<Clock3 className="h-6 w-6" />}
            title={`No ${activeTab} automations`}
            description="Create an automation to schedule AI tasks like file processing, reports, or backups."
            action={{
              label: 'Create automation',
              onClick: () => setCreateOpen(true),
            }}
          />
        )}
      </div>

      <CreateAutomationDialog open={createOpen} onOpenChange={setCreateOpen} />

      <RunHistoryDialog
        automationId={historyId}
        onOpenChange={(open) => !open && setHistoryId(null)}
      />
    </div>
  );
}

function RunHistoryDialog({
  automationId,
  onOpenChange,
}: {
  automationId: string | null;
  onOpenChange: (open: boolean) => void;
}) {
  const { data, isLoading } = useQuery({
    queryKey: ['automation-runs', automationId],
    queryFn: async () => {
      if (!automationId) return { runs: [] as AutomationRun[] };
      const res = await agentApi.get(`/automations/${automationId}/runs`);
      return res.data as { runs: AutomationRun[] };
    },
    enabled: !!automationId,
    refetchInterval: automationId ? 5_000 : false,
  });

  return (
    <Dialog open={!!automationId} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Run history</DialogTitle>
        </DialogHeader>
        <div className="max-h-[60vh] overflow-y-auto">
          {isLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
            </div>
          ) : data && data.runs.length > 0 ? (
            <div className="space-y-2">
              {data.runs.map((run) => {
                const variant: 'success' | 'error' | 'info' | 'stopped' =
                  run.status === 'completed'
                    ? 'success'
                    : run.status === 'failed'
                      ? 'error'
                      : run.status === 'running'
                        ? 'info'
                        : 'stopped';
                const duration = run.durationMs
                  ? `${(Number(run.durationMs) / 1000).toFixed(1)}s`
                  : '—';
                return (
                  <div
                    key={run.id}
                    className="rounded-lg border border-border bg-card p-3 text-xs"
                  >
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <StatusBadge variant={variant} dot>
                          {run.status}
                        </StatusBadge>
                        <span className="text-muted-foreground">{run.trigger}</span>
                      </div>
                      <span className="text-muted-foreground">
                        {new Date(run.createdAt).toLocaleString()}
                      </span>
                    </div>
                    <div className="mt-1 flex gap-3 text-[11px] text-muted-foreground">
                      <span>Duration: {duration}</span>
                    </div>
                    {run.error && (
                      <pre className="mt-2 max-h-32 overflow-auto rounded bg-destructive/10 p-2 text-[11px] text-destructive">
                        {run.error}
                      </pre>
                    )}
                    {run.output && (
                      <pre className="mt-2 max-h-32 overflow-auto rounded bg-muted/50 p-2 text-[11px] text-foreground/80">
                        {run.output}
                      </pre>
                    )}
                  </div>
                );
              })}
            </div>
          ) : (
            <p className="py-8 text-center text-sm text-muted-foreground">No runs yet.</p>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useEffect, useMemo, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { agentApi, workspaceApi , toastApiError} from '@/lib/api';
import { cn } from '@/lib/utils';

type ScheduleType = 'manual' | 'hourly' | 'daily' | 'weekly' | 'cron';
type NotificationMode = 'none' | 'in-app' | 'email-mock' | 'webhook';

type WorkspaceSummary = { id: string; name: string };

interface CreateAutomationDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function CreateAutomationDialog({ open, onOpenChange }: CreateAutomationDialogProps) {
  const queryClient = useQueryClient();
  const [title, setTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [workspaceId, setWorkspaceId] = useState<string>('');
  const [scheduleType, setScheduleType] = useState<ScheduleType>('manual');
  const [cronExpression, setCronExpression] = useState('');
  const [notificationMode, setNotificationMode] = useState<NotificationMode>('in-app');
  const [webhookUrl, setWebhookUrl] = useState('');

  const { data: workspacesData } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as { workspaces: WorkspaceSummary[] };
    },
    enabled: open,
  });
  const workspaces = useMemo(
    () => workspacesData?.workspaces ?? [],
    [workspacesData],
  );

  useEffect(() => {
    if (open && !workspaceId && workspaces.length > 0 && workspaces[0]) {
      // Default-select the first workspace when the dialog opens; the
      // selection is user-overridable so the cascading-render warning is
      // not applicable here.
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setWorkspaceId(workspaces[0].id);
    }
  }, [open, workspaces, workspaceId]);

  const reset = () => {
    setTitle('');
    setPrompt('');
    setScheduleType('manual');
    setCronExpression('');
    setNotificationMode('in-app');
    setWebhookUrl('');
  };

  const createMutation = useMutation({
    mutationFn: async () => {
      const body: Record<string, unknown> = {
        title: title.trim(),
        prompt: prompt.trim(),
        scheduleType,
        notificationMode,
        enabled: true,
      };
      if (workspaceId) body.workspaceId = workspaceId;
      if (scheduleType === 'cron') body.cronExpression = cronExpression.trim();
      if (notificationMode === 'webhook') body.webhookUrl = webhookUrl.trim();

      const res = await agentApi.post('/automations', body);
      return res.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation created');
      reset();
      onOpenChange(false);
    },
    onError: (e) => toastApiError(e, 'Failed to create automation'),
  });

  const valid =
    title.trim().length > 0 &&
    prompt.trim().length > 0 &&
    (scheduleType !== 'cron' || cronExpression.trim().length > 0) &&
    (notificationMode !== 'webhook' || /^https?:\/\//i.test(webhookUrl.trim()));

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Create automation</DialogTitle>
        </DialogHeader>

        <div className="space-y-3">
          <div className="space-y-1.5">
            <Label htmlFor="auto-title">Title</Label>
            <Input
              id="auto-title"
              placeholder="Daily standup summary"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              maxLength={200}
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="auto-prompt">Prompt</Label>
            <Textarea
              id="auto-prompt"
              placeholder="Summarize today's commits and post to /workspace/standup.md"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              rows={4}
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="auto-workspace">Workspace</Label>
            <NativeSelect
              id="auto-workspace"
              value={workspaceId}
              onChange={(e) => setWorkspaceId(e.target.value)}
            >
              <option value="">Select workspace…</option>
              {workspaces.map((w) => (
                <option key={w.id} value={w.id}>
                  {w.name}
                </option>
              ))}
            </NativeSelect>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <Label htmlFor="auto-schedule">Schedule</Label>
              <NativeSelect
                id="auto-schedule"
                value={scheduleType}
                onChange={(e) => setScheduleType(e.target.value as ScheduleType)}
              >
                <option value="manual">Manual / webhook only</option>
                <option value="hourly">Hourly (top of hour)</option>
                <option value="daily">Daily at 09:00 UTC</option>
                <option value="weekly">Weekly Mon 09:00 UTC</option>
                <option value="cron">Custom cron</option>
              </NativeSelect>
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="auto-notify">Notify</Label>
              <NativeSelect
                id="auto-notify"
                value={notificationMode}
                onChange={(e) => setNotificationMode(e.target.value as NotificationMode)}
              >
                <option value="none">None</option>
                <option value="in-app">In-app only</option>
                <option value="email-mock">Email (mock)</option>
                <option value="webhook">Webhook POST</option>
              </NativeSelect>
            </div>
          </div>

          {scheduleType === 'cron' && (
            <div className="space-y-1.5">
              <Label htmlFor="auto-cron">Cron expression</Label>
              <Input
                id="auto-cron"
                placeholder="*/15 * * * *"
                value={cronExpression}
                onChange={(e) => setCronExpression(e.target.value)}
                className="font-mono"
              />
              <p className="text-[11px] text-muted-foreground">
                Standard 5-field cron. Next-run estimate is hidden for custom cron schedules.
              </p>
            </div>
          )}

          {notificationMode === 'webhook' && (
            <div className="space-y-1.5">
              <Label htmlFor="auto-webhook">Webhook URL</Label>
              <Input
                id="auto-webhook"
                type="url"
                placeholder="https://example.com/hooks/automation"
                value={webhookUrl}
                onChange={(e) => setWebhookUrl(e.target.value)}
              />
              <p className="text-[11px] text-muted-foreground">
                Each run POSTs JSON with an <code className="font-mono">X-Pcp-Signature</code>{' '}
                header (HMAC SHA-256).
              </p>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="ghost" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            onClick={() => createMutation.mutate()}
            disabled={!valid || createMutation.isPending}
          >
            {createMutation.isPending && <Loader2 className="mr-2 h-3.5 w-3.5 animate-spin" />}
            Create
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function NativeSelect({
