        'focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring',
        'disabled:cursor-not-allowed disabled:opacity-50',
        className,
      )}
      {...props}
    />
  );
}

import { FastifyInstance, FastifyRequest } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { promises as fs } from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { pipeline } from 'node:stream/promises';
import { createWriteStream } from 'node:fs';
import {
  datasetResponseSchema,
  queryDatasetSchema,
  queryResultSchema,
  apiErrorCodeFromStatus,
  sendApiError,
} from '@pcp/shared';
import { DatasetsService } from '../datasets/service';
import { env } from '../env';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';

const SOURCE_TYPE_BY_EXT: Record<string, 'csv' | 'json' | 'parquet'> = {
  '.csv': 'csv',
  '.tsv': 'csv',
  '.json': 'json',
  '.ndjson': 'json',
  '.jsonl': 'json',
  '.parquet': 'parquet',
};

function toResponse(row: any) {
  return {
    id: row.id,
    name: row.name,
    tableName: row.tableName,
    sourceType: row.sourceType,
    sourceFilename: row.sourceFilename ?? null,
    columns: Array.isArray(row.columns) ? row.columns : [],
    rowCount: Number(row.rowCount ?? 0),
    sizeBytes: Number(row.sizeBytes ?? 0),
    version: Number(row.version ?? 1),
    createdAt: row.createdAt instanceof Date ? row.createdAt.toISOString() : row.createdAt,
    updatedAt: row.updatedAt instanceof Date ? row.updatedAt.toISOString() : row.updatedAt,
  };
}

export async function setupDatasetsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const datasetsService = new DatasetsService(fastify.log);

  async function authUser(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  server.get(
    '/datasets',
    {
      schema: {
        response: {
          200: z.object({ datasets: z.array(datasetResponseSchema) }),
        },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await datasetsService.list(userId);
      return { datasets: rows.map(toResponse) };
    },
  );

  server.delete(
    '/datasets/:id',
    {
      schema: { params: z.object({ id: z.string().uuid() }) },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await datasetsService.remove(userId, request.params.id);
        return { success: true };
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Internal error',
        );
      }
    },
  );

  server.post(
    '/datasets/:id/query',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const ds = await datasetsService.get(userId, request.params.id);
      if (!ds) return sendApiError(reply, 404, 'NOT_FOUND', 'Dataset not found');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.post(
    '/datasets/query',
    {
      schema: {
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.get(
    '/datasets/:id/preview',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        querystring: z.object({ limit: z.coerce.number().int().min(1).max(500).optional() }),
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.preview(userId, request.params.id, request.query.limit);
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Preview failed',
        );
      }
    },
  );

  // Multipart upload + import. Field name for the file part is "file"; an optional
  // text field "name" overrides the dataset display name.
  server.post('/datasets/import', async (request, reply) => {
    const userId = await authUser(request);
    if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

    if (!request.isMultipart()) {
      return sendApiError(reply, 400, 'BAD_REQUEST', 'Expected multipart/form-data');
    }

    let displayName: string | undefined;
    let savedPath: string | undefined;
    let originalFilename: string | undefined;
    let sourceType: 'csv' | 'json' | 'parquet' | undefined;

    try {
      const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'cloudmind-ds-'));
      const parts = request.parts();
      for await (const part of parts) {
        if (part.type === 'field' && part.fieldname === 'name') {
          displayName = String(part.value);
        } else if (part.type === 'file') {
          originalFilename = part.filename;
          const ext = path.extname(part.filename).toLowerCase();
          const detected = SOURCE_TYPE_BY_EXT[ext];
          if (!detected) {
            await part.file.resume();
            return sendApiError(
              reply,
              400,
              'BAD_REQUEST',
              `Unsupported file type "${ext}". Use .csv, .tsv, .json, .ndjson, or .parquet.`,
            );
          }
          sourceType = detected;
          savedPath = path.join(tmpDir, `upload${ext}`);
          await pipeline(part.file, createWriteStream(savedPath));
        }
      }

      if (!savedPath || !sourceType || !originalFilename) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'No file provided');
      }

      const finalName =
        (displayName?.trim() || path.basename(originalFilename, path.extname(originalFilename))) ||
        'dataset';

      const inserted = await datasetsService.importFile({
        userId,
        name: finalName,
        filePath: savedPath,
        sourceFilename: originalFilename,
        sourceType,
      });
      return reply.code(201).send(toResponse(inserted));
    } catch (err: any) {
      const status = err?.statusCode ?? 500;
      if (status === 500) fastify.log.error({ err }, 'dataset import failed');
      return sendApiError(
        reply,
        status,
        apiErrorCodeFromStatus(status),
        err?.message ?? 'Import failed',
      );
    } finally {
      if (savedPath) {
        await fs.rm(path.dirname(savedPath), { recursive: true, force: true }).catch(() => {});
      }
    }
  });
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { createSnapshotSchema, snapshotResponseSchema, sendApiError } from '@pcp/shared';
import { WorkspaceService } from '../service';
import { db } from '@pcp/db/src/client';
import { auditLogs } from '@pcp/db/src/schema';

async function emitAudit(
  fastify: FastifyInstance,
  userId: string | null,
  action: string,
  details: Record<string, unknown>,
): Promise<void> {
  try {
    await db.insert(auditLogs).values({ userId, action, details });
  } catch (e) {
    fastify.log.warn({ action, err: e }, 'audit_log emit failed');
  }
}

export async function setupSnapshotRoutes(
  fastify: FastifyInstance,
  workspaceService: WorkspaceService,
) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();

  server.post(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: createSnapshotSchema.omit({ workspaceId: true }),
        response: {
          201: snapshotResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshot = await workspaceService.createSnapshot(
        request.params.id,
        userId,
        request.body.name,
        request.body.description,
      );

      return reply.code(201).send(snapshot);
    },
  );

  server.get(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        response: {
          200: z.object({
            snapshots: z.array(snapshotResponseSchema),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshots = await workspaceService.getSnapshots(request.params.id, userId);
      return { snapshots };
    },
  );

  server.post(
    '/snapshots/:id/restore',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const result = await workspaceService.restoreSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_RESTORE', { snapshotId: request.params.id });
      return { success: true, ...result };
    },
  );

  server.delete(
    '/snapshots/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await workspaceService.deleteSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_DELETE', { snapshotId: request.params.id });
      return { success: true };
    },
  );
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { db } from '@pcp/db/src/client';
import { automations, automationRuns, workspaces } from '@pcp/db/src/schema';
import { validateSessionUserId } from '@pcp/db/src/session';
import { and, eq, desc, isNull } from 'drizzle-orm';
import { createAutomationSchema, updateAutomationSchema, sendApiError } from '@pcp/shared';
import { automationQueue } from '../automation/queue';
import { automationRepeatKey, computeNextRunAt, resolveSchedule } from '../automation/schedule';
import { automationTriggerToken, verifyAutomationTriggerToken } from '../automation/notify';
import { z } from 'zod';

export async function setupAutomationRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();

  async function getAuthenticatedUserId(sessionId: string | undefined): Promise<string | null> {
    return validateSessionUserId(sessionId);
  }

  async function assertWorkspaceOwned(workspaceId: string | undefined | null, userId: string) {
    if (!workspaceId) return true;
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });
    return Boolean(workspace);
  }

  server.get(
    '/automations',
    {
      schema: {
        querystring: z.object({ workspaceId: z.string().uuid().optional() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const { workspaceId } = request.query;

      if (!(await assertWorkspaceOwned(workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const items = await db.query.automations.findMany({
        where: workspaceId
          ? and(eq(automations.userId, userId), eq(automations.workspaceId, workspaceId))
          : eq(automations.userId, userId),
        orderBy: [desc(automations.createdAt)],
      });

      return { automations: items };
    },
  );

  server.post(
    '/automations',
    {
      schema: { body: createAutomationSchema },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const nextRunAt = computeNextRunAt(request.body);

      const [automation] = await db
        .insert(automations)
        .values({
          userId,
          ...request.body,
          nextRunAt,
        })
        .returning();
      if (!automation) throw new Error('Failed to create automation');

      const schedule = resolveSchedule(automation);
      if (automation.enabled && schedule.isRepeating && schedule.pattern) {
        await automationQueue.add(
          'scheduled-run',
          { automationId: automation.id },
          {
            repeat: {
              pattern: schedule.pattern,
              ...(schedule.timezone ? { tz: schedule.timezone } : {}),
            },
            jobId: automationRepeatKey(automation.id),
          },
        );
      }

      return reply.code(201).send({
        ...automation,
        triggerToken: automationTriggerToken(automation.id),
      });
    },
  );

  server.patch(
    '/automations/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateAutomationSchema,
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;

      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const nextRunAt = computeNextRunAt({
        scheduleType: request.body.scheduleType ?? 'manual',
        cronExpression: request.body.cronExpression ?? null,
        timezone: request.body.timezone ?? null,
      });

      const [updated] = await db
        .update(automations)
        .set({
          ...request.body,
          ...(request.body.scheduleType !== undefined ? { nextRunAt } : {}),
          updatedAt: new Date(),
        })
        .where(and(eq(automations.id, id), eq(automations.userId, userId)))
        .returning();

      if (!updated) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      // Re-register the repeat: always remove the existing key first; then add
      // a fresh repeat job if the automation is enabled and has a schedule.
      try {
        await automationQueue.removeRepeatableByKey(automationRepeatKey(id));
      } catch {
        // ignore — key may not exist
      }
      const schedule = resolveSchedule(updated);
      if (updated.enabled && schedule.isRepeating && schedule.pattern) {
        await automationQueue.add(
          'scheduled-run',
          { automationId: updated.id },
          {
            repeat: {
              pattern: schedule.pattern,
              ...(schedule.timezone ? { tz: schedule.timezone } : {}),
            },
            jobId: automationRepeatKey(updated.id),
          },
        );
      }

      return updated;
    },
  );

  server.delete(
    '/automations/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      await db
        .delete(automations)
        .where(and(eq(automations.id, id), eq(automations.userId, userId)));
      try {
        await automationQueue.removeRepeatableByKey(automationRepeatKey(id));
      } catch {
        // ignore
      }

      return { success: true };
    },
  );

  // Manual trigger
  server.post(
    '/automations/:id/run',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, id), eq(automations.userId, userId)),
      });

      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');
      if (!automation.workspaceId) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'Automation missing workspace');
      }
      if (!(await assertWorkspaceOwned(automation.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      // Create a run record
      const [run] = await db
        .insert(automationRuns)
        .values({
          automationId: automation.id,
          userId,
          trigger: 'manual',
          status: 'queued',
        })
        .returning();
      if (!run) throw new Error('Failed to create run');

      // Add to BullMQ
      await automationQueue.add('manual-run', {
        runId: run.id,
        automationId: automation.id,
        userId,
        workspaceId: automation.workspaceId,
        prompt: automation.prompt,
      });

      return run;
    },
  );

  // Get runs
  server.get(
    '/automations/:id/runs',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, id), eq(automations.userId, userId)),
      });
      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      const runs = await db.query.automationRuns.findMany({
        where: and(eq(automationRuns.automationId, id), eq(automationRuns.userId, userId)),
        orderBy: [desc(automationRuns.createdAt)],
      });

      return { runs };
    },
  );

  // Return the inbound webhook trigger token. Callers use this to construct a
  // public webhook URL that can fire a manual run without a session cookie.
  server.get(
    '/automations/:id/trigger-token',
    {
      schema: { params: z.object({ id: z.string().uuid() }) },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, request.params.id), eq(automations.userId, userId)),
      });
      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      return { token: automationTriggerToken(automation.id) };
    },
  );

  // Inbound public webhook trigger. Validated via constant-time HMAC token
  // (no session cookie required). Always enqueues a manual run.
  server.post(
    '/automations/:id/trigger',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        querystring: z.object({ token: z.string().min(8) }),
      },
    },
    async (request, reply) => {
      const { id } = request.params;
      const { token } = request.query;

      if (!verifyAutomationTriggerToken(id, token)) {
        return sendApiError(reply, 401, 'UNAUTHORIZED', 'Invalid trigger token');
      }

      const automation = await db.query.automations.findFirst({
        where: eq(automations.id, id),
      });
      if (!automation || !automation.enabled) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Automation not found or disabled');
      }
      if (!automation.workspaceId) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'Automation missing workspace');
      }
      if (!(await assertWorkspaceOwned(automation.workspaceId, automation.userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const [run] = await db
        .insert(automationRuns)
        .values({
          automationId: automation.id,
          userId: automation.userId,
          trigger: 'webhook',
          status: 'queued',
        })
        .returning();
      if (!run) throw new Error('Failed to create run');

      await automationQueue.add('webhook-run', {
        runId: run.id,
        automationId: automation.id,
        userId: automation.userId,
        workspaceId: automation.workspaceId,
        prompt: automation.prompt,
      });

      return reply.code(202).send({ runId: run.id });
    },
  );
}

