  const [workspaceId, setWorkspaceId] = useState('');
  const [deleteTarget, setDeleteTarget] = useState<string | null>(null);

  const workspacesQuery = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaces = useMemo(
    () => workspacesQuery.data?.workspaces ?? [],
    [workspacesQuery.data],
  );
  const defaultWorkspaceId = workspaceId || workspaces[0]?.id || '';

  const servicesQuery = useQuery({
    queryKey: ['hosted-services', defaultWorkspaceId],
    enabled: Boolean(user?.id && defaultWorkspaceId),
    retry: false,
    refetchInterval: 20_000,
    queryFn: async () => {
      const res = await publishApi.get('/hosted-services', {
        params: { workspaceId: defaultWorkspaceId },
      });
      return res.data as HostedService[];
    },
  });

  const services = servicesQuery.data ?? [];
  const hostingReady = Boolean(user?.id && !servicesQuery.isError);

  const workspaceNameById = useMemo(() => {
    return new Map(workspaces.map((w) => [w.id, w.name]));
  }, [workspaces]);

  const createService = useMutation({
    mutationFn: async () => {
      if (!user?.id) throw new Error('You must be signed in.');
      await publishApi.post('/hosted-services', {
        workspaceId: defaultWorkspaceId,
        name: name.trim(),
        slug: normalizeSlug(slug || name),
        kind,
        rootPath,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service created.');
      setShowCreate(false);
      setName('');
      setSlug('');
      setKind('static');
      setRootPath('/');
    },
    onError: (e) => toastApiError(e, 'Could not create service.'),
  });

  const startService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/start`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service starting...');
    },
    onError: (e) => toastApiError(e, 'Could not start service.'),
  });

  const stopService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/stop`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service stopped.');
    },
    onError: (e) => toastApiError(e, 'Could not stop service.'),
  });

  const restartService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/restart`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service restarting...');
    },
    onError: (e) => toastApiError(e, 'Could not restart service.'),
  });

  const updateAutoRestart = useMutation({
    mutationFn: async ({ id, autoRestart }: { id: string; autoRestart: boolean }) => {
      await publishApi.patch(`/hosted-services/${id}`, { autoRestart });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
    },
    onError: (e) => toastApiError(e, 'Could not update service.'),
  });

  const deleteService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.delete(`/hosted-services/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service deleted.');
      setDeleteTarget(null);
    },
    onError: (e) => toastApiError(e, 'Could not delete service.'),
  });

  const canCreate = hostingReady && Boolean(defaultWorkspaceId && name.trim());

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Hosting</h2>
          <p className="text-sm text-muted-foreground">Deploy workspace apps as hosted services</p>
        </div>
        <Button
          size="sm"
          onClick={() => setShowCreate((v) => !v)}
          disabled={!hostingReady || workspaces.length === 0}
        >
          <Rocket className="mr-1.5 h-3.5 w-3.5" />
          Create service
        </Button>
      </div>

      {servicesQuery.isError && (
        <div className="mt-4 rounded-lg border border-amber-500/30 bg-amber-500/5 p-3 text-sm text-amber-600 dark:text-amber-400">
          Publish service is not available. Hosting actions are disabled until it responds.
        </div>
      )}

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (canCreate) createService.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-2 lg:grid-cols-3"
        >
          <div className="space-y-1.5">
            <Label htmlFor="svc-name">Service name</Label>
            <Input
              id="svc-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My App"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-slug">Slug (subdomain)</Label>
            <Input
              id="svc-slug"
              value={slug}
              onChange={(e) => setSlug(e.target.value)}
              placeholder={normalizeSlug(name || 'my-app')}
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-kind">Kind</Label>
            <select
              id="svc-kind"
              value={kind}
              onChange={(e) => setKind(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              <option value="static">Static (HTML/CSS/JS)</option>
              <option value="vite">Vite App</option>
              <option value="node">Node.js API</option>
            </select>
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-root">Root path</Label>
            <Input
              id="svc-root"
              value={rootPath}
              onChange={(e) => setRootPath(e.target.value)}
              placeholder="/"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-workspace">Workspace</Label>
            <select
              id="svc-workspace"
              value={defaultWorkspaceId}
              onChange={(e) => setWorkspaceId(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              {workspaces.map((w) => (
                <option key={w.id} value={w.id}>
                  {w.name}
                </option>
              ))}
            </select>
          </div>
          <div className="flex items-end">
            <Button type="submit" size="sm" disabled={!canCreate || createService.isPending}>
              {createService.isPending ? 'Creating...' : 'Create'}
            </Button>
          </div>
        </form>
      )}

      <div className="mt-6">
        {servicesQuery.isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : services.length > 0 ? (
          <div className="space-y-3">
            {services.map((svc) => {
              const isRunning = svc.status === 'running';
              const isStarting = svc.status === 'starting';
              return (
                <div
                  key={svc.id}
                  className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
                >
                  <div className="flex min-w-0 items-center gap-3">
                    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                      <Server className="h-5 w-5 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium text-foreground">{svc.name}</h3>
                        <StatusBadge
                          variant={isRunning ? 'running' : isStarting ? 'pending' : 'stopped'}
                          dot
                        >
                          {svc.status}
                        </StatusBadge>
                        <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
                          {svc.kind}
                        </span>
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {svc.slug}.apps.localhost ·{' '}
                        {workspaceNameById.get(svc.workspaceId) || 'Workspace'} ·{' '}
                        {formatDate(svc.updatedAt)}
                      </p>
                      <div className="mt-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[11px] text-muted-foreground">
                        <span
                          className={
                            svc.lastHealthOk === false
                              ? 'text-destructive'
                              : svc.lastHealthOk
                                ? 'text-emerald-600 dark:text-emerald-400'
                                : ''
                          }
                          title={svc.lastHealthAt ?? undefined}
                        >
                          Health:{' '}
                          {svc.lastHealthOk === null || svc.lastHealthOk === undefined
                            ? '—'
                            : svc.lastHealthOk
                              ? 'OK'
                              : 'failing'}
                        </span>
                        <span>Crashes: {svc.crashCount ?? 0}</span>
                        <label className="flex cursor-pointer items-center gap-1">
                          <input
                            type="checkbox"
                            checked={svc.autoRestart ?? true}
                            onChange={(e) =>
                              updateAutoRestart.mutate({
                                id: svc.id,
                                autoRestart: e.target.checked,
                              })
                            }
                            className="h-3 w-3"
                          />
                          Auto-restart
                        </label>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {isRunning ? (
                      <>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => restartService.mutate(svc.id)}
                          disabled={restartService.isPending}
                          title="Restart"
                        >
                          <RefreshCw className="mr-1 h-3.5 w-3.5" /> Restart
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => stopService.mutate(svc.id)}
                          disabled={stopService.isPending}
                        >
                          <Square className="mr-1 h-3.5 w-3.5" /> Stop
                        </Button>
                      </>
                    ) : (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => startService.mutate(svc.id)}
                        disabled={startService.isPending || isStarting}
                      >
                        <Play className="mr-1 h-3.5 w-3.5" /> Start
                      </Button>
                    )}
                    {svc.publicUrl && (
                      <a href={svc.publicUrl} target="_blank" rel="noreferrer">
                        <Button size="sm" variant="outline">
                          Open <ExternalLink className="ml-1 h-3.5 w-3.5" />
                        </Button>
                      </a>
                    )}
                    <Button
                      size="sm"
                      variant="ghost"
                      className="text-destructive hover:text-destructive"
                      onClick={() => setDeleteTarget(svc.id)}
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <EmptyState
            icon={<Globe2 className="h-6 w-6" />}
            title="No services yet"
            description="Create a static site, Vite app, or Node.js service from an existing workspace."
            action={{
              label: 'Create service',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={() => setDeleteTarget(null)}
        title="Delete service"
        description="This will stop the running container and remove the service. This action cannot be undone."
        confirmLabel="Delete"
        variant="destructive"
        onConfirm={async () => {
          if (deleteTarget) await deleteService.mutateAsync(deleteTarget);
        }}
      />
    </div>
  );
}

function normalizeSlug(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

import { FastifyPluginAsyncZod } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { PublishService } from './service';
import {
  createApiErrorResponse,
  createHostedServiceSchema,
  apiErrorResponseSchema,
  updateHostedServiceSchema,
  hostedServiceResponseSchema,
} from '@pcp/shared';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';
import { FastifyReply, FastifyRequest } from 'fastify';

function sendUnauthorized(reply: FastifyReply) {
  return reply.code(401).send(createApiErrorResponse('UNAUTHORIZED', 'Unauthorized'));
}

export const publishRoutes: FastifyPluginAsyncZod = async (app) => {
  const publishService = new PublishService();

  async function getAuthenticatedUserId(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request);
  }

  app.post(
    '/hosted-services',
    {
      schema: {
        body: createHostedServiceSchema,
        response: {
          201: hostedServiceResponseSchema,
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const service = await publishService.createService({ ...request.body, userId });
      return reply.code(201).send(service);
    },
  );

  app.get(
    '/hosted-services',
    {
      schema: {
        querystring: z.object({
          workspaceId: z.string().uuid(),
        }),
        response: {
          200: z.array(hostedServiceResponseSchema),
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const services = await publishService.listServices(request.query.workspaceId, userId);
      return reply.code(200).send(services);
    },
  );

  app.patch(
    '/hosted-services/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateHostedServiceSchema,
        response: {
          200: hostedServiceResponseSchema,
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const service = await publishService.updateService(request.params.id, userId, request.body);
      return reply.code(200).send(service);
    },
  );

  app.delete(
    '/hosted-services/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      await publishService.deleteService(request.params.id, userId);
      return reply.code(204).send();
    },
  );

  app.post(
    '/hosted-services/:id/start',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const result = await publishService.startService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );

  app.post(
    '/hosted-services/:id/stop',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const result = await publishService.stopService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );

  app.post(
    '/hosted-services/:id/restart',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      await publishService.stopService(request.params.id, userId);
      const result = await publishService.startService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );
};

'use client';

import { useMemo, useState, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { ChevronDown, ChevronRight, File as FileIcon, Folder, FolderOpen, Pencil, Trash, Download } from 'lucide-react';
import { toast } from 'sonner';
import { workspaceApi, toastApiError} from '@/lib/api';
import { formatBytes, formatDate } from '@/lib/format';
import { cn } from '@/lib/utils';
import { useWorkspaceStore, WorkspaceFileMetadata } from '@/store/workspace';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from '@/components/ui/context-menu';

type FilesResponse = {
  files: WorkspaceFileMetadata[];
};

export default function FileTree({ workspaceId }: { workspaceId: string }) {
  const { selectedItem } = useWorkspaceStore();
  const queryClient = useQueryClient();
  const [isDragging, setIsDragging] = useState(false);

  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('path', `/${file.name}`);

      await workspaceApi.post(`/workspaces/${workspaceId}/upload`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('File uploaded successfully');
    },
    onError: (err) => {
      toastApiError(err, 'Failed to upload file');
    },
  });

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        Array.from(e.dataTransfer.files).forEach((file) => {
          uploadMutation.mutate(file);
        });
      }
    },
    [uploadMutation]
  );

  return (
    <div 
      className={cn(
        "flex h-full flex-col text-sm transition-colors",
        isDragging && "bg-primary/5 ring-1 ring-inset ring-primary"
      )}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <div className="flex h-10 items-center px-4 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
        Explorer
      </div>
      <div className="min-h-0 flex-1 overflow-auto py-1">
        {isDragging && (
          <div className="absolute inset-0 z-10 flex items-center justify-center bg-background/50 backdrop-blur-sm">
            <div className="rounded-xl border border-primary/20 bg-card p-4 text-center shadow-lg">
              <Download className="mx-auto mb-2 h-6 w-6 text-primary" />
              <p className="text-sm font-medium">Drop files to upload</p>
            </div>
          </div>
        )}
        <TreeBranch workspaceId={workspaceId} path="/" level={0} />
      </div>
      <div className="border-t border-border bg-card p-3">
        <p className="mb-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">Details</p>
        {selectedItem ? (
          <dl className="space-y-1.5 text-xs">
            <div>
              <dt className="text-muted-foreground">Name</dt>
              <dd className="truncate text-foreground">{selectedItem.name}</dd>
            </div>
            <div>
              <dt className="text-muted-foreground">Path</dt>
              <dd className="truncate text-foreground">{selectedItem.path}</dd>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <dt className="text-muted-foreground">Type</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? 'Folder' : selectedItem.mimeType || 'File'}</dd>
              </div>
              <div>
                <dt className="text-muted-foreground">Size</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? '-' : formatBytes(selectedItem.size)}</dd>
              </div>
            </div>
            <div>
              <dt className="text-muted-foreground">Updated</dt>
              <dd className="text-foreground">{formatDate(selectedItem.updatedAt)}</dd>
            </div>
          </dl>
        ) : (
          <p className="text-xs text-muted-foreground">Select a file or folder to inspect.</p>
        )}
      </div>
    </div>
  );
}

function TreeBranch({ workspaceId, path, level }: { workspaceId: string; path: string; level: number }) {
  const [expandedPaths, setExpandedPaths] = useState<Set<string>>(new Set());
  const { selectedItem, setSelectedFile, addOpenFile, setSelectedItem, removeOpenFile } = useWorkspaceStore();
  const queryClient = useQueryClient();

  const { data, isLoading, isError } = useQuery({
    queryKey: ['workspace-files', workspaceId, path],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces/' + workspaceId + '/files', { params: { path } });
      return res.data as FilesResponse;
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (filePath: string) => {
      await workspaceApi.delete(`/workspaces/${workspaceId}/files${filePath}`);
    },
    onSuccess: (_, filePath) => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('Deleted successfully');
      removeOpenFile(filePath);
      if (selectedItem?.path === filePath) {
        setSelectedItem(null);
      }
    },
    onError: (err) => {
      toastApiError(err, 'Failed to delete file');
    },
  });

  const files = useMemo(() => {
    return [...(data?.files ?? [])].sort((a, b) => {
      if (a.isDirectory !== b.isDirectory) return a.isDirectory ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  }, [data?.files]);

  const toggleDirectory = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setExpandedPaths((current) => {
      const next = new Set(current);
      if (next.has(file.path)) {
        next.delete(file.path);
      } else {
        next.add(file.path);
      }
      return next;
    });
  };

  const openFile = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setSelectedFile(file.path);
    addOpenFile(file.path);
  };

  if (isLoading) {
    return <div className={cn('py-1 pr-2 text-xs text-muted-foreground', indentClass(level))}>Loading...</div>;
  }

  if (isError) {
    return <div className={cn('py-1 pr-2 text-xs text-destructive', indentClass(level))}>Could not load files.</div>;
  }

  if (files.length === 0 && level === 0) {
    return <div className="px-4 py-2 text-xs text-muted-foreground">No files in this workspace.</div>;
  }

  return (
    <ul className="space-y-0.5 px-1.5">
      {files.map((file) => {
        const isExpanded = expandedPaths.has(file.path);
        const isSelected = selectedItem?.path === file.path;

        return (
          <ContextMenu key={file.path}>
            <ContextMenuTrigger>
              <li>
                <button
                  type="button"
                  className={cn(
                    'flex h-7 w-full items-center rounded-md pr-2 text-left text-sm transition-colors',
                    isSelected
                      ? 'bg-primary/10 text-primary'
                      : 'text-foreground/80 hover:bg-muted',
                    indentClass(level)
                  )}
                  onClick={() => (file.isDirectory ? toggleDirectory(file) : openFile(file))}
                >
                  {file.isDirectory ? (
                    <>
                      {isExpanded ? (
                        <ChevronDown className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      ) : (
                        <ChevronRight className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      )}
                      {isExpanded ? (
                        <FolderOpen className="mr-1.5 h-4 w-4 text-blue-500" />
                      ) : (
                        <Folder className="mr-1.5 h-4 w-4 text-blue-500" />
                      )}
                    </>
                  ) : (
                    <FileIcon className="ml-5 mr-1.5 h-4 w-4 text-muted-foreground" />
                  )}
                  <span className="truncate">{file.name}</span>
                </button>
                {file.isDirectory && isExpanded && <TreeBranch workspaceId={workspaceId} path={file.path} level={level + 1} />}
              </li>
            </ContextMenuTrigger>
            <ContextMenuContent className="w-48">
              {!file.isDirectory && (
                <ContextMenuItem onClick={() => openFile(file)}>
                  <Pencil className="mr-2 h-4 w-4" /> Edit
                </ContextMenuItem>
              )}
              {/* Note: Rename and move functionality to be fully implemented via modals */}
              <ContextMenuItem disabled>
                <Pencil className="mr-2 h-4 w-4" /> Rename
              </ContextMenuItem>
              <ContextMenuSeparator />
              <ContextMenuItem
                className="text-destructive focus:bg-destructive focus:text-destructive-foreground"
                onClick={() => {
                  if (confirm(`Are you sure you want to delete ${file.name}?`)) {
                    deleteMutation.mutate(file.path);
                  }
                }}
              >
                <Trash className="mr-2 h-4 w-4" /> Delete
              </ContextMenuItem>
            </ContextMenuContent>
          </ContextMenu>
        );
      })}
    </ul>
  );
}

