    mutationFn: async () => {
      const res = await browserApi.post('/browser/sessions');
      return res.data as Session;
    },
    onSuccess: (s) => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
      setActiveId(s.id);
      toast.success('Session started.');
    },
    onError: (e) => toastApiError(e, 'Could not start session.'),
  });

  const close = useMutation({
    mutationFn: async (id: string) => {
      await browserApi.delete(`/browser/sessions/${id}`);
    },
    onSuccess: (_, id) => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
      if (activeId === id) {
        setActiveId(null);
        setExtract(null);
        setShotSrc(null);
      }
    },
    onError: (e) => toastApiError(e, 'Could not close session.'),
  });

  const navigate = useMutation({
    mutationFn: async ({ id, url }: { id: string; url: string }) => {
      const res = await browserApi.post(`/browser/sessions/${id}/navigate`, { url });
      return res.data as Session;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
    },
    onError: (e) => toastApiError(e, 'Navigate failed.'),
  });

  const doExtract = useMutation({
    mutationFn: async (id: string) => {
      const res = await browserApi.get(`/browser/sessions/${id}/extract`);
      return res.data as ExtractResult;
    },
    onSuccess: (r) => setExtract(r),
    onError: (e) => toastApiError(e, 'Extract failed.'),
  });

  const doShot = useMutation({
    mutationFn: async (id: string) => {
      const res = await browserApi.get(`/browser/sessions/${id}/screenshot`);
      return (res.data as { pngBase64: string }).pngBase64;
    },
    onSuccess: (b64) => setShotSrc(`data:image/png;base64,${b64}`),
    onError: (e) => toastApiError(e, 'Screenshot failed.'),
  });

  return (
    <div className="mx-auto flex max-w-6xl flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Globe className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Cloud Browser</h2>
          <p className="text-sm text-muted-foreground">
            Headless Playwright sessions with persistent per-user profiles. Navigate, extract page
            content, or take screenshots.
          </p>
        </div>
        <Button onClick={() => create.mutate()} disabled={create.isPending}>
          {create.isPending ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Plus className="mr-1.5 h-3.5 w-3.5" />
          )}
          New session
        </Button>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-[260px_1fr]">
        <aside className="rounded-xl border border-border bg-card p-3">
          <h3 className="mb-2 px-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Sessions
          </h3>
          {isLoading ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">Loading...</p>
          ) : sessions.length === 0 ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">
              No active sessions. Start one to begin.
            </p>
          ) : (
            <ul className="space-y-1">
              {sessions.map((s) => (
                <li key={s.id}>
                  <button
                    type="button"
                    onClick={() => {
                      setActiveId(s.id);
                      setNavUrl(s.url === 'about:blank' ? 'https://example.com' : s.url);
                      setExtract(null);
                      setShotSrc(null);
                    }}
                    className={`group flex w-full items-start justify-between gap-2 rounded-lg px-2 py-2 text-left text-sm transition-colors hover:bg-muted ${
                      activeId === s.id ? 'bg-muted' : ''
                    }`}
                  >
                    <div className="min-w-0 flex-1">
                      <div className="truncate font-medium text-foreground">
                        {s.title || s.url || 'Blank tab'}
                      </div>
                      <div className="truncate text-[11px] text-muted-foreground">{s.url}</div>
                    </div>
                    <span
                      role="button"
                      tabIndex={0}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (confirm('Close this session?')) close.mutate(s.id);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          if (confirm('Close this session?')) close.mutate(s.id);
                        }
                      }}
                      className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <main className="space-y-4">
          {activeId ? (
            <>
              <div className="rounded-xl border border-border bg-card p-4">
                <form
                  onSubmit={(e) => {
                    e.preventDefault();
                    if (!navUrl.trim()) return;
                    navigate.mutate({ id: activeId, url: navUrl.trim() });
                  }}
                  className="flex gap-2"
                >
                  <Input
                    value={navUrl}
                    onChange={(e) => setNavUrl(e.target.value)}
                    placeholder="https://example.com"
                    className="flex-1 font-mono text-xs"
                  />
                  <Button type="submit" size="sm" disabled={navigate.isPending}>
                    {navigate.isPending ? (
                      <Loader2 className="h-3.5 w-3.5 animate-spin" />
                    ) : (
                      <ArrowRight className="h-3.5 w-3.5" />
                    )}
                  </Button>
                </form>
                <div className="mt-3 flex gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => doExtract.mutate(activeId)}
                    disabled={doExtract.isPending}
                  >
                    <FileText className="mr-1.5 h-3.5 w-3.5" />
                    Extract
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => doShot.mutate(activeId)}
                    disabled={doShot.isPending}
                  >
                    <ImageDown className="mr-1.5 h-3.5 w-3.5" />
                    Screenshot
                  </Button>
                </div>
              </div>

              {shotSrc && (
                <div className="rounded-xl border border-border bg-card p-3">
                  <p className="mb-2 text-xs text-muted-foreground">Latest screenshot</p>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={shotSrc}
                    alt="screenshot"
                    className="max-h-[600px] w-full rounded-md border border-border object-contain"
                  />
                </div>
              )}

              {extract && (
                <div className="rounded-xl border border-border bg-card p-3">
                  <h4 className="mb-1 truncate font-medium text-foreground">{extract.title}</h4>
                  <p className="mb-2 truncate text-[11px] text-muted-foreground">{extract.url}</p>
                  <pre className="max-h-[400px] overflow-auto whitespace-pre-wrap rounded-md bg-muted p-3 text-xs text-foreground">
                    {extract.text}
                  </pre>
                  {extract.links.length > 0 && (
                    <details className="mt-3">
                      <summary className="cursor-pointer text-xs text-muted-foreground">
                        {extract.links.length} links
                      </summary>
                      <ul className="mt-2 max-h-[200px] space-y-0.5 overflow-auto text-xs">
                        {extract.links.slice(0, 50).map((l, i) => (
                          <li key={i} className="truncate">
                            <a
                              href={l.href}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="text-primary hover:underline"
                            >
                              {l.text || l.href}
                            </a>
                          </li>
                        ))}
                      </ul>
                    </details>
                  )}
                </div>
              )}
            </>
          ) : (
            <div className="rounded-xl border border-dashed border-border p-10 text-center text-sm text-muted-foreground">
              Select or start a session to begin.
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

'use client';

import { useCallback, useEffect, useRef, useState } from 'react';
import { ChatComposer } from '@/components/app-shell/chat-composer';
import { DottedBackground } from '@/components/app-shell/dotted-background';
import { StatusToast } from '@/components/app-shell/status-toast';
import { ToolApproval } from '@/components/app-shell/tool-approval-card';
import { agentApi, getApiErrorMessage } from '@/lib/api';

export function ChatHome() {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<
    Array<{ id: string; role: 'user' | 'assistant'; content: string }>
  >([]);
  const [isThinking, setIsThinking] = useState(false);
  const [toolApproval, setToolApproval] = useState<ToolApproval | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const abortRef = useRef<AbortController | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const stopGeneration = useCallback(() => {
    abortRef.current?.abort();
    abortRef.current = null;
    if (intervalRef.current) {
      clearInterval(intervalRef.current);
      intervalRef.current = null;
    }
    setIsThinking(false);
  }, []);

  const startNewChat = useCallback(() => {
    stopGeneration();
    setMessages([]);
    setInput('');
    setToolApproval(null);
  }, [stopGeneration]);

  const openUpload = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  useEffect(() => {
    const handleNewChat = () => startNewChat();
    const handleUpload = () => openUpload();
    window.addEventListener('app:new-chat', handleNewChat);
    window.addEventListener('app:open-file-upload', handleUpload);
    return () => {
      window.removeEventListener('app:new-chat', handleNewChat);
      window.removeEventListener('app:open-file-upload', handleUpload);
    };
  }, [openUpload, startNewChat]);

  useEffect(() => {
    const handleEscape = (event: KeyboardEvent) => {
      if (event.key === 'Escape' && isThinking) {
        stopGeneration();
      }
    };
    window.addEventListener('keydown', handleEscape);
    return () => window.removeEventListener('keydown', handleEscape);
  }, [isThinking, stopGeneration]);

  useEffect(() => {
    return () => stopGeneration();
  }, [stopGeneration]);

  const submit = async () => {
    const prompt = input.trim();
    if (!prompt || isThinking) return;

    setMessages((current) => [
      ...current,
      { id: crypto.randomUUID(), role: 'user', content: prompt },
    ]);
    setInput('');
    setIsThinking(true);
    setToolApproval(null);

    const needsTool = /\b(file|deploy|publish|terminal|workspace|host)\b/i.test(prompt);
    if (needsTool) {
      setTimeout(() => {
        setToolApproval({
          toolName: prompt.match(/\bdeploy|publish|host\b/i)
            ? 'prepare_deployment'
            : 'workspace_inspector',
          description: 'Review workspace context before taking action.',
        });
      }, 450);
    }

    const assistantId = crypto.randomUUID();
    setMessages((current) => [...current, { id: assistantId, role: 'assistant', content: '' }]);

    const controller = new AbortController();
    abortRef.current = controller;

    try {
      const response = await agentApi.post(
        '/agent/chat',
        { input: prompt },
        { signal: controller.signal },
      );
      const content =
        (response.data as { content?: string }).content ||
        'I did not receive a response from the model.';

      setMessages((current) =>
        current.map((message) => (message.id === assistantId ? { ...message, content } : message)),
      );
    } catch (error) {
      const content = controller.signal.aborted
        ? 'Generation stopped.'
        : getApiErrorMessage(error, 'The MiniMax agent service is not available.');

      setMessages((current) =>
        current.map((message) => (message.id === assistantId ? { ...message, content } : message)),
      );
    } finally {
      if (abortRef.current === controller) {
        abortRef.current = null;
      }
      setIsThinking(false);
    }
  };

  return (
    <div className="relative flex min-h-full flex-col overflow-hidden bg-[linear-gradient(180deg,#1D1E21_0%,#18191C_100%)] px-4 pb-4 pt-8 text-[#F0F0F0] sm:px-8 lg:px-12">
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -left-40 -top-56 h-[900px] w-[900px] rounded-full bg-[radial-gradient(circle,#3FB6E0_0%,transparent_68%)] opacity-[0.10] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -right-48 -top-72 h-[1000px] w-[1000px] rounded-full bg-[radial-gradient(circle,#B85CFF_0%,transparent_68%)] opacity-[0.12] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute bottom-[-280px] left-[22%] h-[560px] w-[820px] rounded-full bg-[radial-gradient(circle,#F5A524_0%,transparent_70%)] opacity-[0.09] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -bottom-52 -left-48 h-[600px] w-[760px] rounded-full bg-[radial-gradient(circle,#7CD992_0%,transparent_70%)] opacity-[0.08] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute -left-32 -top-56 h-[1400px] w-96 -rotate-[22deg] rounded-full bg-[linear-gradient(90deg,transparent,#3FB6E0,transparent)] opacity-[0.07] blur-3xl"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-32 -top-72 h-[1400px] w-80 rotate-[18deg] rounded-full bg-[linear-gradient(90deg,transparent,#B85CFF,transparent)] opacity-[0.06] blur-3xl"
      />
      <DottedBackground className="opacity-45" />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[13%] top-[10%] h-0.5 w-0.5 rounded-full bg-white shadow-[0_0_14px_4px_rgba(122,184,255,0.65)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[43%] top-[16%] h-1 w-1 rounded-full bg-[#FFE7B3] shadow-[0_0_18px_5px_rgba(245,165,36,0.55)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[22%] top-[11%] h-0.5 w-0.5 rounded-full bg-white shadow-[0_0_14px_4px_rgba(184,92,255,0.55)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[15%] bottom-[18%] h-1 w-1 rounded-full bg-[#FFE7B3] shadow-[0_0_16px_4px_rgba(245,165,36,0.5)]"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute left-[2%] top-[25%] h-px w-40 rotate-[12deg] bg-gradient-to-r from-transparent to-[#A8E0FF] opacity-45"
      />
      <div
        aria-hidden="true"
        className="pointer-events-none absolute right-[12%] bottom-[28%] h-px w-44 rotate-[14deg] bg-gradient-to-r from-transparent to-[#E0BCFF] opacity-45"
      />
      <input ref={fileInputRef} type="file" multiple className="hidden" aria-label="Upload files" />
      <div className="relative z-10 mx-auto flex w-[calc(100vw-3rem)] min-w-0 max-w-full flex-1 flex-col justify-center pb-20 pt-8 sm:w-full sm:max-w-[700px] lg:justify-start lg:pt-[27vh]">
        <StatusToast isThinking={isThinking} onStop={stopGeneration} />
        {messages.length > 0 && (
          <div className="mb-5 max-h-[32vh] space-y-3 overflow-auto rounded-xl border border-zinc-800 bg-zinc-950/35 p-4">
            {messages.map((message) => (
              <div
                key={message.id}
                className={message.role === 'user' ? 'text-right' : 'text-left'}
              >
                <div
                  className={`inline-block max-w-[84%] rounded-xl px-4 py-2 text-sm leading-6 ${
                    message.role === 'user'
                      ? 'bg-blue-500/15 text-blue-100 ring-1 ring-blue-400/20'
                      : 'bg-zinc-900 text-zinc-200 ring-1 ring-zinc-800'
                  }`}
                >
                  {message.content || '...'}
                </div>
              </div>
            ))}
          </div>
        )}
        <ChatComposer
          value={input}
          onChange={setInput}
          onSubmit={submit}
          onUpload={openUpload}
          isThinking={isThinking}
          toolApproval={toolApproval}
          onApproveTool={() => setToolApproval(null)}
          onRejectTool={() => setToolApproval(null)}
        />
        <div className="mt-5 text-[10px] leading-tight text-[#777C85]">
          <div className="font-extrabold text-[#B1B3B9]">Rewards</div>
          <div>Earn $10 / user</div>
        </div>
      </div>
      <div className="relative z-10 mx-auto flex w-full max-w-[520px] flex-wrap items-center justify-center gap-x-5 gap-y-2 pb-1 text-xs text-[#A8A8A8]/80">
        <span>kafkasder.zo.computer</span>
        <span>kafkasder.zo.space</span>
        <span>kafkasder@zo.computer</span>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useMemo, useRef } from 'react';
import type React from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Send, Bot, Loader2, CheckCircle2, XCircle, Paperclip, X } from 'lucide-react';
import { toast } from 'sonner';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { agentApi, workspaceApi, toastApiError} from '@/lib/api';
import { usePersonaStore } from '@/store/persona';
import { useActiveSkillsStore } from '@/store/skills';

type ToolCall = {
  name: string;
  args: unknown;
};

type Message = {
  id: string;
  taskId: string;
  taskStatus: string;
  conversationId: string;
  role: string;
  content: string;
  toolCalls?: ToolCall[];
  createdAt: string;
};

type Conversation = {
  id: string;
  title: string | null;
};

export default function WorkspaceChat({ workspaceId }: { workspaceId: string }) {
  const [input, setInput] = useState('');
  const [attachments, setAttachments] = useState<{ path: string; name: string }[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const queryClient = useQueryClient();

  // Fetch conversations
  const { data: convosData } = useQuery({
    queryKey: ['agent-conversations'],
    queryFn: async () => {
      const res = await agentApi.get('/agent/conversations');
      return res.data.conversations as Conversation[];
    },
  });

  const activeConversationId = convosData?.[0]?.id;

  // Fetch messages
  const { data: messagesData, isLoading: isLoadingMessages } = useQuery({
    queryKey: ['agent-messages', activeConversationId],
    queryFn: async () => {
      if (!activeConversationId) return { messages: [] };
      const res = await agentApi.get(`/agent/conversations/${activeConversationId}/messages`);
      return res.data as { messages: Message[] };
    },
    enabled: !!activeConversationId,
    refetchInterval: (query) => {
      // Poll if any task is executing or waiting approval
      const isPending = query.state?.data?.messages.some((m: Message) =>
        ['pending', 'executing'].includes(m.taskStatus),
      );
      return isPending ? 2000 : false;
    },
  });

  const messages = useMemo(() => messagesData?.messages ?? [], [messagesData]);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMutation = useMutation({
    mutationFn: async (content: string) => {
      const personaId = usePersonaStore.getState().activePersonaId;
      const skillIds = useActiveSkillsStore.getState().activeSkillIds;
      const composed =
        attachments.length > 0
          ? `${content}\n\n${attachments.map((a) => `[Attached: ${a.path}]`).join('\n')}`
          : content;
      await agentApi.post('/agent/tasks', {
        workspaceId,
        input: composed,
        conversationId: activeConversationId,
        personaId: personaId ?? undefined,
        skillIds: skillIds.length > 0 ? skillIds : undefined,
      });
    },
    onSuccess: () => {
      // Invalidate queries so we fetch the new task and poll
      if (!activeConversationId) {
        queryClient.invalidateQueries({ queryKey: ['agent-conversations'] });
      } else {
        queryClient.invalidateQueries({ queryKey: ['agent-messages', activeConversationId] });
      }
      setAttachments([]);
    },
    onError: (error) => {
      toastApiError(error, 'Failed to send message');
    },
  });

  const approvalMutation = useMutation({
    mutationFn: async ({
      taskId,
      decision,
      reason,
    }: {
      taskId: string;
      decision: 'approve' | 'reject';
      reason?: string;
    }) => {
      await agentApi.post(`/agent/tasks/${taskId}/tool-approval`, { decision, reason });
    },
    onSuccess: (_, variables) => {
      toast.success(`Tool call ${variables.decision}d.`);
      queryClient.invalidateQueries({ queryKey: ['agent-messages', activeConversationId] });
    },
    onError: (error) => {
      toastApiError(error, 'Failed to submit approval');
    },
  });

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if ((!input.trim() && attachments.length === 0) || sendMutation.isPending) return;
    sendMutation.mutate(input);
    setInput('');
  };

  const handleFilePick = () => fileInputRef.current?.click();

  const handleFilesSelected = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files ?? []);
    e.target.value = '';
    if (files.length === 0) return;
    if (!workspaceId) {
      toast.error('Open a workspace before attaching files.');
      return;
    }
    setIsUploading(true);
    try {
      for (const file of files) {
        const form = new FormData();
        form.append('file', file);
        form.append('path', `/chat-uploads/${Date.now()}-${file.name}`);
        const res = await workspaceApi.post(`/workspaces/${workspaceId}/upload`, form, {
          headers: { 'Content-Type': 'multipart/form-data' },
        });
        const path = res.data?.path ?? `/chat-uploads/${file.name}`;
        setAttachments((prev) => [...prev, { path, name: file.name }]);
      }
      toast.success(`${files.length} file${files.length > 1 ? 's' : ''} attached.`);
    } catch (err) {
      toastApiError(err, 'Upload failed');
    } finally {
      setIsUploading(false);
    }
  };

  const removeAttachment = (idx: number) => {
    setAttachments((prev) => prev.filter((_, i) => i !== idx));
  };

  return (
    <div className="flex h-full flex-col bg-[#252526]">
      <div className="flex h-10 items-center justify-between border-b border-[#333333] px-4 font-semibold uppercase tracking-wider text-zinc-400">
        <span>Agent Chat</span>
        <Bot className="h-5 w-5 text-blue-400" />
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {isLoadingMessages && !messages.length ? (
          <div className="flex justify-center text-zinc-500 py-4 animate-in fade-in duration-200">
            <Loader2 className="animate-spin h-5 w-5" />
          </div>
        ) : messages.length === 0 ? (
          <div className="flex h-full flex-col items-center justify-center text-zinc-500 animate-in fade-in zoom-in-95 duration-300">
            <Bot className="mb-2 h-10 w-10 text-zinc-600" />
            <p>How can I help you today?</p>
          </div>
        ) : null}

        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex flex-col max-w-[85%] animate-in fade-in slide-in-from-bottom-2 duration-300 ${
              msg.role === 'user' ? 'ml-auto items-end' : 'mr-auto items-start'
            }`}
          >
            <div
