import { z } from 'zod';

export const createTaskSchema = z.object({
  workspaceId: z.string().uuid(),
  conversationId: z.string().uuid().optional(),
  input: z.string().min(1),
  personaId: z.string().uuid().nullable().optional(),
  skillIds: z.array(z.string().uuid()).max(5).optional(),
});

export const taskResponseSchema = z.object({
  id: z.string().uuid(),
  workspaceId: z.string().uuid(),
  status: z.string(),
  input: z.string(),
  output: z.string().nullable(),
  createdAt: z.date(),
  updatedAt: z.date(),
});

export const taskStepSchema = z.object({
  id: z.string().uuid(),
  taskId: z.string().uuid(),
  stepNumber: z.number(),
  type: z.string(),
  content: z.string().nullable(),
  toolName: z.string().nullable(),
  toolInput: z.any().nullable(),
  toolOutput: z.string().nullable(),
  createdAt: z.date(),
});

export const toolDefinitionSchema = z.object({
  name: z.string(),
  description: z.string(),
  parameters: z.record(z.any()),
});

export const conversationResponseSchema = z.object({
  id: z.string().uuid(),
  workspaceId: z.string().uuid().nullable(),
  title: z.string().nullable(),
  provider: z.string(),
  createdAt: z.date(),
  updatedAt: z.date(),
});

export const messageResponseSchema = z.object({
  id: z.string(),
  taskId: z.string().uuid(),
  taskStatus: z.string(),
  conversationId: z.string().uuid(),
  role: z.string(),
  content: z.string(),
  toolCalls: z.array(z.any()).optional(),
  createdAt: z.date(),
});

export const toolApprovalSchema = z.object({
  decision: z.enum(['approve', 'reject']),
  reason: z.string().optional(),
});

export const taskEventStreamQuerySchema = z.object({
  snapshot: z.coerce.boolean().optional(),
});

import { pgTable, timestamp, uuid, varchar, text, jsonb, index } from 'drizzle-orm/pg-core';
import { users } from './users';
import { workspaces } from './workspaces';

export const tasks = pgTable(
  'tasks',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id, { onDelete: 'cascade' }),
    workspaceId: uuid('workspace_id')
      .notNull()
      .references(() => workspaces.id, { onDelete: 'cascade' }),
    conversationId: uuid('conversation_id'), // FK enforced application-side to avoid circular import
    status: varchar('status', { length: 50 }).default('pending').notNull(), // pending, planning, executing, waiting_approval, completed, failed, cancelled
    input: text('input').notNull(),
    output: text('output'),
    metadata: jsonb('metadata'), // provider, model, tokens used, etc.
    createdAt: timestamp('created_at').defaultNow().notNull(),
    updatedAt: timestamp('updated_at').defaultNow().notNull(),
  },
  (t) => ({
    userIdx: index('tasks_user_idx').on(t.userId, t.status),
    conversationIdx: index('tasks_conversation_idx').on(t.conversationId),
  }),
);

import { useEffect, useRef, useState } from 'react';
import { Terminal } from '@xterm/xterm';
import { FitAddon } from '@xterm/addon-fit';
import { WebLinksAddon } from '@xterm/addon-web-links';
import '@xterm/xterm/css/xterm.css';

interface UseTerminalOptions {
  runtimeId: string;
  onCommandBlocked?: (command: string) => void;
}

export type TerminalConnectionState =
  | 'connecting'
  | 'connected'
  | 'reconnecting'
  | 'closed';

const MAX_RECONNECT_ATTEMPTS = 6;
const BASE_BACKOFF_MS = 500;
const MAX_BACKOFF_MS = 8_000;

/** Exponential backoff with light jitter, capped at MAX_BACKOFF_MS. */
function computeBackoff(attempt: number): number {
  const exp = Math.min(BASE_BACKOFF_MS * 2 ** attempt, MAX_BACKOFF_MS);
  const jitter = Math.random() * 0.3 * exp;
  return Math.round(exp + jitter);
}

export function useTerminal({ runtimeId, onCommandBlocked }: UseTerminalOptions) {
  const terminalRef = useRef<HTMLDivElement>(null);
  const xtermRef = useRef<Terminal | null>(null);
  const fitAddonRef = useRef<FitAddon | null>(null);
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const attemptsRef = useRef(0);
  const cancelledRef = useRef(false);

  const [connectionState, setConnectionState] = useState<TerminalConnectionState>('connecting');

  useEffect(() => {
    if (!terminalRef.current) return;

    cancelledRef.current = false;
    attemptsRef.current = 0;

    // Initialize xterm.js once; the Terminal instance is reused across reconnects.
    const term = new Terminal({
      cursorBlink: true,
      fontFamily: 'Menlo, Monaco, "Courier New", monospace',
      fontSize: 14,
      theme: {
        background: '#1e1e1e',
        foreground: '#cccccc',
      },
    });
    const fitAddon = new FitAddon();
    term.loadAddon(fitAddon);
    term.loadAddon(new WebLinksAddon());
    term.open(terminalRef.current);
    fitAddon.fit();
    xtermRef.current = term;
    fitAddonRef.current = fitAddon;

    // Buffered input for client-side command screening.
    let inputBuffer = '';

    term.onData((data) => {
      const ws = wsRef.current;
      if (!ws || ws.readyState !== WebSocket.OPEN) return;

      if (data === '\r') {
        const blockedPatterns = [/rm\s+-rf\s+\//, /^sudo\b/, /:\(\)\{\s*:\|:&\s*\};:/];
        const isBlocked = blockedPatterns.some((p) => p.test(inputBuffer.trim()));
        if (isBlocked) {
          term.writeln('\r\n\x1b[31mError: Command blocked by security policy.\x1b[0m');
          onCommandBlocked?.(inputBuffer.trim());
          inputBuffer = '';
          ws.send('\x03');
          return;
        }
        inputBuffer = '';
      } else if (data === '\x7f') {
        inputBuffer = inputBuffer.slice(0, -1);
      } else if (data === '\x03') {
        inputBuffer = '';
      } else {
        inputBuffer += data;
      }

      ws.send(data);
    });

    const handleResize = () => fitAddon.fit();
    window.addEventListener('resize', handleResize);

    const connect = () => {
      if (cancelledRef.current) return;
      const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
      const wsUrl = `${protocol}//${window.location.host}/api/runtimes/${runtimeId}/terminal`;
      const ws = new WebSocket(wsUrl);
      wsRef.current = ws;

      ws.onopen = () => {
        attemptsRef.current = 0;
        setConnectionState('connected');
        term.writeln('\r\n\x1b[32m--- Connected to CloudMind Terminal ---\x1b[0m\r\n');
      };

      ws.onmessage = (event) => {
        term.write(event.data);
      };

      ws.onerror = () => {
        term.writeln('\r\n\x1b[31m--- Connection Error ---\x1b[0m');
      };

      ws.onclose = (event) => {
        if (cancelledRef.current) {
          setConnectionState('closed');
          return;
        }
        // 1000 = normal closure; do not retry intentional closes.
        if (event.code === 1000) {
          setConnectionState('closed');
          term.writeln('\r\n\x1b[31m--- Connection Closed ---\x1b[0m\r\n');
          return;
        }

        const attempt = attemptsRef.current;
        if (attempt >= MAX_RECONNECT_ATTEMPTS) {
          setConnectionState('closed');
          term.writeln(
            '\r\n\x1b[31m--- Connection Lost (max reconnect attempts reached) ---\x1b[0m\r\n',
          );
          return;
        }

        const delay = computeBackoff(attempt);
        attemptsRef.current = attempt + 1;
        setConnectionState('reconnecting');
        term.writeln(
          `\r\n\x1b[33m--- Disconnected. Reconnecting in ${
            Math.round(delay / 100) / 10
          }s (attempt ${attempt + 1}/${MAX_RECONNECT_ATTEMPTS}) ---\x1b[0m`,
        );

        reconnectTimerRef.current = setTimeout(connect, delay);
      };
    };

    setConnectionState('connecting');
    connect();

    return () => {
      cancelledRef.current = true;
      window.removeEventListener('resize', handleResize);
      if (reconnectTimerRef.current) {
        clearTimeout(reconnectTimerRef.current);
        reconnectTimerRef.current = null;
      }
      const ws = wsRef.current;
      if (ws) {
        // Detach handlers before close so the close handler does not schedule a reconnect.
        ws.onopen = null;
        ws.onclose = null;
        ws.onerror = null;
        ws.onmessage = null;
        ws.close(1000, 'unmount');
      }
      wsRef.current = null;
      term.dispose();
      xtermRef.current = null;
      fitAddonRef.current = null;
    };
  }, [runtimeId, onCommandBlocked]);

  return {
    terminalRef,
    connectionState,
    isConnected: connectionState === 'connected',
  };
}

import type { NextConfig } from "next";
import path from "node:path";

const nextConfig: NextConfig = {
  turbopack: {
    root: path.resolve(__dirname, "../.."),
  },
};

export default nextConfig;

'use client';

import { useState } from 'react';
import { Plus, TerminalSquare, AlertTriangle, Loader2 } from 'lucide-react';
import { useMutation } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { runtimeApi, toastApiError} from '@/lib/api';
import { useTerminal } from '@/hooks/use-terminal';

function TerminalTab({ runtimeId, isActive, onBlocked }: { runtimeId: string; isActive: boolean; onBlocked: (cmd: string) => void }) {
  const { terminalRef, connectionState } = useTerminal({ runtimeId, onCommandBlocked: onBlocked });

  const badgeStyle =
    connectionState === 'connected'
      ? 'bg-emerald-500/20 text-emerald-300'
      : connectionState === 'connecting'
        ? 'bg-zinc-500/20 text-zinc-300'
        : connectionState === 'reconnecting'
          ? 'bg-amber-500/20 text-amber-300'
          : 'bg-red-500/20 text-red-300';

  return (
    <div className={`flex-1 p-2 bg-[#1e1e1e] relative ${isActive ? 'block' : 'hidden'}`}>
      <div
        className={`absolute top-2 right-3 z-10 rounded-full px-2 py-0.5 text-[10px] font-medium uppercase tracking-wide ${badgeStyle}`}
        role="status"
        aria-live="polite"
      >
        {connectionState}
      </div>
      {connectionState !== 'connected' && (
        <div className="absolute inset-0 flex items-center justify-center bg-[#1e1e1e]/80 z-10">
          <Loader2 className="animate-spin text-zinc-400 mr-2" />
          <span className="text-zinc-400">
            {connectionState === 'reconnecting' ? 'Reconnecting…' : 'Connecting…'}
          </span>
        </div>
      )}
      <div className="h-full w-full" ref={terminalRef} />
    </div>
  );
}

export default function WorkspaceTerminal({ workspaceId }: { workspaceId: string }) {
  const [tabs, setTabs] = useState<{ id: string; name: string }[]>([]);
  const [activeTabId, setActiveTabId] = useState<string | null>(null);
  const [blockedCommand, setBlockedCommand] = useState<string | null>(null);

  const createRuntimeMutation = useMutation({
    mutationFn: async () => {
      const res = await runtimeApi.post('/runtimes', {
        workspaceId,
        image: 'ubuntu:latest', // Default image
        options: {},
      });
      const runtime = res.data;
      // Start it automatically
      await runtimeApi.post(`/runtimes/${runtime.id}/start`);
      return runtime.id;
    },
    onSuccess: (runtimeId) => {
      const newTab = { id: runtimeId, name: `bash-${tabs.length + 1}` };
      setTabs((prev) => [...prev, newTab]);
      setActiveTabId(runtimeId);
    },
    onError: (error) => {
      toastApiError(error, 'Failed to start terminal');
    },
  });

  const handleBlocked = (cmd: string) => {
    setBlockedCommand(cmd);
  };

  return (
    <div className="flex h-full w-full flex-col relative">
      <div className="flex h-10 items-center bg-[#252526] border-b border-[#333333]">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTabId(tab.id)}
              className={`flex items-center px-4 h-full border-r border-[#333333] text-xs transition-colors ${
                activeTabId === tab.id ? 'bg-[#1e1e1e] text-blue-400 border-t-2 border-t-blue-500' : 'text-zinc-400 hover:bg-[#2d2d2d]'
              }`}
            >
              <TerminalSquare className="mr-2 h-3 w-3" />
              {tab.name}
            </button>
          ))}
        </div>
        <Button
          variant="ghost"
          size="icon"
          className="h-8 w-8 text-zinc-400 hover:text-white mr-2"
          onClick={() => createRuntimeMutation.mutate()}
          disabled={createRuntimeMutation.isPending}
          aria-label="New terminal session"
          title="New terminal session"
        >
          {createRuntimeMutation.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Plus className="h-4 w-4" />}
        </Button>
      </div>

      {tabs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center bg-[#1e1e1e] text-zinc-500">
          <TerminalSquare className="h-12 w-12 mb-4 opacity-50" />
          <p>No active terminal sessions.</p>
          <Button 
            className="mt-4 bg-blue-600 hover:bg-blue-500"
            onClick={() => createRuntimeMutation.mutate()}
            disabled={createRuntimeMutation.isPending}
          >
            {createRuntimeMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            Start Terminal Session
          </Button>
        </div>
      ) : (
        tabs.map((tab) => (
          <TerminalTab 
            key={tab.id} 
            runtimeId={tab.id} 
            isActive={activeTabId === tab.id} 
            onBlocked={handleBlocked}
          />
        ))
      )}

      <AlertDialog open={!!blockedCommand} onOpenChange={() => setBlockedCommand(null)}>
        <AlertDialogContent className="bg-[#2d2d2d] border-[#444] text-zinc-200">
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center text-red-400">
              <AlertTriangle className="mr-2 h-5 w-5" />
              Command Blocked
            </AlertDialogTitle>
            <AlertDialogDescription className="text-zinc-400">
              The command you attempted to run violates our security policy and has been blocked.
              <div className="mt-2 p-2 bg-black rounded font-mono text-sm text-red-300">
                {blockedCommand}
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogAction className="bg-blue-600 hover:bg-blue-500 text-white">I Understand</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

export interface SharedCorsOptions {
  origin: true | string[];
  credentials: true;
}

export function createCorsOptions(
  nodeEnv: string,
  allowedOrigins = process.env.CORS_ALLOWED_ORIGINS,
): SharedCorsOptions {
  if (nodeEnv !== 'production') {
    return { origin: true, credentials: true };
  }

  return {
    origin: parseAllowedCorsOrigins(allowedOrigins),
    credentials: true,
  };
}

export function parseAllowedCorsOrigins(value: string | undefined): string[] {
  const entries = value
    ?.split(',')
    .map((origin) => origin.trim())
    .filter(Boolean);

  if (!entries?.length) {
    throw new Error('CORS_ALLOWED_ORIGINS must be set in production');
  }

  return Array.from(new Set(entries.map(normalizeCorsOrigin)));
}

function normalizeCorsOrigin(origin: string): string {
  if (origin === '*') {
    throw new Error('CORS_ALLOWED_ORIGINS must not contain wildcard origins in production');
  }

  let parsed: URL;
  try {
    parsed = new URL(origin);
  } catch {
    throw new Error(`CORS_ALLOWED_ORIGINS contains an invalid URL: ${origin}`);
  }

  if (parsed.protocol !== 'https:' && parsed.protocol !== 'http:') {
    throw new Error(`CORS_ALLOWED_ORIGINS only supports http(s) origins: ${origin}`);
  }

  if (parsed.pathname !== '/' || parsed.search || parsed.hash || parsed.username || parsed.password) {
    throw new Error(
      `CORS_ALLOWED_ORIGINS entries must be origins only, without paths or credentials: ${origin}`,
    );
  }

  return parsed.origin;
}

