'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Bot, Plus, Pencil, Sparkles, Trash2, Download, Check, Library } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { agentApi, toastApiError} from '@/lib/api';

type Skill = {
  id: string;
  slug: string;
  name: string;
  description: string | null;
  bodyMarkdown: string | null;
  triggers: string[];
  enabled: boolean;
};

type FormState = {
  id?: string;
  slug: string;
  name: string;
  description: string;
  bodyMarkdown: string;
  triggers: string;
  enabled: boolean;
};

const empty: FormState = {
  slug: '',
  name: '',
  description: '',
  bodyMarkdown: '',
  triggers: '',
  enabled: true,
};

export default function SkillsPage() {
  const qc = useQueryClient();
  const [editor, setEditor] = useState<FormState | null>(null);
  const [showCatalog, setShowCatalog] = useState(false);

  const { data, isLoading } = useQuery({
    queryKey: ['skills'],
    queryFn: async () => {
      const res = await agentApi.get('/skills');
      return (res.data?.skills ?? []) as Skill[];
    },
    retry: false,
  });
  const skills = data ?? [];

  const { data: catalogData, isLoading: catalogLoading } = useQuery({
    queryKey: ['skills-catalog'],
    queryFn: async () => {
      const res = await agentApi.get('/skills/catalog');
      return (res.data?.skills ?? []) as Array<{
        slug: string;
        name: string;
        description: string;
        category: string;
        triggers: string[];
        bodyMarkdown: string;
        installed: boolean;
      }>;
    },
    enabled: showCatalog,
    retry: false,
  });

  const installPreset = useMutation({
    mutationFn: async (slug: string) => {
      await agentApi.post('/skills/install', { slug });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['skills'] });
      qc.invalidateQueries({ queryKey: ['skills-catalog'] });
      toast.success('Skill installed.');
    },
    onError: (e) => toastApiError(e, 'Could not install skill.'),
  });

  const save = useMutation({
    mutationFn: async (form: FormState) => {
      const triggers = form.triggers
        .split(',')
        .map((t) => t.trim())
        .filter(Boolean);
      if (form.id) {
        await agentApi.patch(`/skills/${form.id}`, {
          name: form.name,
          description: form.description || null,
          bodyMarkdown: form.bodyMarkdown || null,
          triggers,
          enabled: form.enabled,
        });
      } else {
        await agentApi.post('/skills', {
          slug: form.slug,
          name: form.name,
          description: form.description || null,
          bodyMarkdown: form.bodyMarkdown || null,
          triggers,
          enabled: form.enabled,
        });
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['skills'] });
      toast.success(editor?.id ? 'Skill updated.' : 'Skill created.');
      setEditor(null);
    },
    onError: (e) => toastApiError(e, 'Could not save skill.'),
  });

  const remove = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.delete(`/skills/${id}`);
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['skills'] });
      toast.success('Skill deleted.');
    },
    onError: (e) => toastApiError(e, 'Could not delete skill.'),
  });

  const enabledCount = skills.filter((s) => s.enabled).length;

  return (
    <div className="flex-1 overflow-auto p-6 lg:p-8">
      <header className="mb-6 flex items-start justify-between gap-3">
        <div className="flex items-start gap-3">
          <div className="flex h-11 w-11 items-center justify-center rounded-lg bg-primary/10 text-primary">
            <Sparkles className="h-6 w-6" />
          </div>
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold tracking-tight">Skills</h1>
              {!isLoading && (
                <span className="rounded-full bg-muted px-2.5 py-0.5 text-xs font-medium text-muted-foreground">
                  {enabledCount}/{skills.length} enabled
                </span>
              )}
            </div>
            <p className="mt-1 text-sm text-muted-foreground">
              Reusable SKILL.md instructions the agent loads when triggered keywords match.
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Button size="sm" variant="outline" onClick={() => setShowCatalog((v) => !v)}>
            <Library className="mr-1.5 h-3.5 w-3.5" />
            {showCatalog ? 'Hide catalog' : 'Browse catalog'}
          </Button>
          <Button size="sm" onClick={() => setEditor({ ...empty })}>
            <Plus className="mr-1.5 h-3.5 w-3.5" /> New skill
          </Button>
        </div>
      </header>
      <div className="mx-auto max-w-4xl">

      {showCatalog && (
        <section className="mb-6 animate-in fade-in slide-in-from-top-2 duration-200">
          <div className="mb-3 flex items-center gap-2">
            <Library className="h-4 w-4 text-primary" />
            <h2 className="text-sm font-semibold uppercase tracking-wider text-muted-foreground">
              Skill catalog
            </h2>
            <span className="rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
              {catalogData?.length ?? 0} presets
            </span>
          </div>
          {catalogLoading ? (
            <p className="text-sm text-muted-foreground">Loading catalog...</p>
          ) : (
            <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
              {(catalogData ?? []).map((c) => (
                <div
                  key={c.slug}
                  className="flex flex-col gap-2 rounded-xl border border-border bg-card p-4 transition-colors hover:border-primary/40"
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium text-foreground">{c.name}</h3>
                        <span className="rounded bg-primary/10 px-1.5 py-0.5 text-[10px] font-medium text-primary">
                          {c.category}
                        </span>
                      </div>
                      <p className="mt-1 text-xs text-muted-foreground line-clamp-2">
                        {c.description}
                      </p>
                    </div>
                    <Button
                      size="sm"
                      variant={c.installed ? 'outline' : 'default'}
                      disabled={c.installed || installPreset.isPending}
                      onClick={() => installPreset.mutate(c.slug)}
                      className="shrink-0"
                    >
                      {c.installed ? (
                        <>
                          <Check className="mr-1 h-3.5 w-3.5" /> Installed
                        </>
                      ) : (
                        <>
                          <Download className="mr-1 h-3.5 w-3.5" /> Install
                        </>
                      )}
                    </Button>
                  </div>
                  {c.triggers.length > 0 && (
                    <p className="text-[11px] text-muted-foreground">
                      Triggers: {c.triggers.slice(0, 4).join(', ')}
                      {c.triggers.length > 4 && '…'}
                    </p>
                  )}
                </div>
              ))}
            </div>
          )}
        </section>
      )}

      {editor && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (!editor.name.trim() || !editor.slug.trim()) return;
            save.mutate(editor);
          }}
          className="mt-4 space-y-3 rounded-xl border border-border bg-card p-4"
        >
          <div className="grid grid-cols-1 gap-3 md:grid-cols-2">
            <div className="space-y-1.5">
              <Label htmlFor="sk-slug">Slug</Label>
              <Input
                id="sk-slug"
                value={editor.slug}
                disabled={Boolean(editor.id)}
                onChange={(e) => setEditor({ ...editor, slug: e.target.value })}
                placeholder="research-topic"
              />
            </div>
            <div className="space-y-1.5">
              <Label htmlFor="sk-name">Name</Label>
              <Input
                id="sk-name"
                value={editor.name}
                onChange={(e) => setEditor({ ...editor, name: e.target.value })}
                placeholder="Research Topic"
              />
            </div>
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="sk-desc">Description</Label>
            <Input
              id="sk-desc"
              value={editor.description}
              onChange={(e) => setEditor({ ...editor, description: e.target.value })}
              placeholder="One-line summary"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="sk-trig">
              Triggers (comma-separated keywords; substring match on user input)
            </Label>
            <Input
              id="sk-trig"
              value={editor.triggers}
              onChange={(e) => setEditor({ ...editor, triggers: e.target.value })}
              placeholder="research, summarize, report"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="sk-body">SKILL.md body</Label>
            <textarea
              id="sk-body"
              value={editor.bodyMarkdown}
              onChange={(e) => setEditor({ ...editor, bodyMarkdown: e.target.value })}
              rows={10}
              className="w-full rounded-lg border border-border bg-card p-3 text-sm font-mono"
              placeholder="# Skill instructions...\n\nWhen invoked, the agent should..."
            />
          </div>
          <label className="flex items-center gap-2 text-sm">
            <input
              type="checkbox"
              checked={editor.enabled}
              onChange={(e) => setEditor({ ...editor, enabled: e.target.checked })}
            />
            Enabled
          </label>
          <div className="flex justify-end gap-2">
            <Button size="sm" variant="outline" type="button" onClick={() => setEditor(null)}>
              Cancel
            </Button>
            <Button size="sm" type="submit" disabled={save.isPending}>
              {save.isPending ? 'Saving...' : 'Save'}
            </Button>
          </div>
        </form>
      )}

      <div className="mt-6 space-y-3">
        {isLoading ? (
          <p className="text-sm text-muted-foreground">Loading...</p>
        ) : skills.length === 0 ? (
          <div className="rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">
            No skills yet. Create one to give the agent reusable instructions.
          </div>
        ) : (
          skills.map((s) => (
            <div
              key={s.id}
              className="flex items-start justify-between rounded-xl border border-border bg-card p-4"
            >
              <div className="flex min-w-0 gap-3">
                <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                  <Bot className="h-5 w-5 text-primary" />
                </div>
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <h3 className="font-medium text-foreground">{s.name}</h3>
                    <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono text-muted-foreground">
                      {s.slug}
                    </span>
                    {!s.enabled && (
                      <span className="rounded bg-amber-500/10 px-1.5 py-0.5 text-[10px] font-medium text-amber-600 dark:text-amber-400">
                        Disabled
                      </span>
                    )}
                  </div>
                  {s.description && (
                    <p className="mt-1 text-xs text-muted-foreground">{s.description}</p>
                  )}
                  {s.triggers.length > 0 && (
                    <p className="mt-1 text-[11px] text-muted-foreground">
                      Triggers: {s.triggers.join(', ')}
                    </p>
                  )}
                </div>
              </div>
              <div className="flex gap-1">
                <Button
                  size="sm"
                  variant="ghost"
                  onClick={() =>
                    setEditor({
                      id: s.id,
                      slug: s.slug,
                      name: s.name,
                      description: s.description ?? '',
                      bodyMarkdown: s.bodyMarkdown ?? '',
                      triggers: s.triggers.join(', '),
                      enabled: s.enabled,
                    })
                  }
                >
                  <Pencil className="h-3.5 w-3.5" />
                </Button>
                <Button
                  size="sm"
                  variant="ghost"
                  className="text-destructive hover:text-destructive"
                  onClick={() => {
                    if (confirm(`Delete skill "${s.name}"?`)) remove.mutate(s.id);
                  }}
                >
                  <Trash2 className="h-3.5 w-3.5" />
                </Button>
              </div>
            </div>
          ))
        )}
      </div>
      </div>
    </div>
  );
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import {
  createSkillSchema,
  skillResponseSchema,
  updateSkillSchema,
  apiErrorCodeFromStatus,
  sendApiError,
} from '@pcp/shared';
import { SkillsService } from '../skills/service';
import { SKILL_CATALOG } from '../skills/catalog';
import { AgentOrchestrator } from '../orchestrator';
import { env } from '../env';

export async function setupSkillsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const service = new SkillsService();
  const orchestrator = new AgentOrchestrator(fastify.log);

  async function getUserId(sessionId: string | undefined): Promise<string | null> {
    if (env.AUTH_BYPASS) return 'local-dev-user';
    if (!sessionId) return null;
    return orchestrator.validateUserFromCookie(sessionId);
  }

  server.get(
    '/skills',
    { schema: { response: { 200: z.object({ skills: z.array(skillResponseSchema) }) } } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await service.list(userId);
      return { skills: rows };
    },
  );

  server.post(
    '/skills',
    { schema: { body: createSkillSchema, response: { 201: skillResponseSchema } } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const row = await service.create(userId, request.body);
        return reply.code(201).send(row);
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to create skill',
        );
      }
    },
  );

  server.patch(
    '/skills/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateSkillSchema,
        response: { 200: skillResponseSchema },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const row = await service.update(request.params.id, userId, request.body);
        return row;
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to update skill',
        );
      }
    },
  );

  server.delete(
    '/skills/:id',
    { schema: { params: z.object({ id: z.string().uuid() }) } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await service.remove(request.params.id, userId);
        return { success: true };
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to delete skill',
        );
      }
    },
  );

  // Built-in catalog of preset skills the user can one-click install.
  server.get(
    '/skills/catalog',
    {
      schema: {
        response: {
          200: z.object({
            skills: z.array(
              z.object({
                slug: z.string(),
                name: z.string(),
                description: z.string(),
                category: z.string(),
                triggers: z.array(z.string()),
                bodyMarkdown: z.string(),
                installed: z.boolean(),
              }),
            ),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const installed = await service.list(userId);
      const installedSlugs = new Set(installed.map((s) => s.slug));
      return {
        skills: SKILL_CATALOG.map((s) => ({ ...s, installed: installedSlugs.has(s.slug) })),
      };
    },
  );

  // Install a preset skill into the user's library by slug.
  server.post(
    '/skills/install',
    {
      schema: {
        body: z.object({ slug: z.string().min(1).max(120) }),
        response: { 201: skillResponseSchema },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const preset = SKILL_CATALOG.find((s) => s.slug === request.body.slug);
      if (!preset) return sendApiError(reply, 404, 'NOT_FOUND', 'Catalog skill not found');
      try {
        const row = await service.create(userId, {
          slug: preset.slug,
          name: preset.name,
          description: preset.description,
          bodyMarkdown: preset.bodyMarkdown,
          triggers: preset.triggers,
          enabled: true,
        });
        return reply.code(201).send(row);
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to install skill',
        );
      }
    },
  );

  server.post(
    '/skills/match',
    {
      schema: {
        body: z.object({ input: z.string().min(1).max(20000) }),
        response: { 200: z.object({ skills: z.array(skillResponseSchema) }) },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const matched = await service.matchTriggers(userId, request.body.input);
      return { skills: matched };
    },
  );
}

import { z } from 'zod';

export const skillResponseSchema = z.object({
  id: z.string().uuid(),
  workspaceId: z.string().uuid().nullable(),
  slug: z.string(),
  name: z.string(),
  description: z.string().nullable(),
  bodyMarkdown: z.string().nullable(),
  sourcePath: z.string().nullable(),
  triggers: z.array(z.string()),
  enabled: z.boolean(),
  metadata: z.record(z.unknown()).nullable().optional(),
  createdAt: z.date(),
  updatedAt: z.date(),
});

export const createSkillSchema = z.object({
  workspaceId: z.string().uuid().nullable().optional(),
  slug: z
    .string()
    .min(1)
    .max(120)
    .regex(/^[a-z0-9][a-z0-9-_]*$/, 'slug must be lowercase alphanumeric/dash/underscore'),
  name: z.string().min(1).max(200),
  description: z.string().max(2000).nullable().optional(),
  bodyMarkdown: z.string().max(100000).nullable().optional(),
  sourcePath: z.string().max(1024).nullable().optional(),
  triggers: z.array(z.string().min(1).max(200)).max(20).optional(),
  enabled: z.boolean().optional(),
});

export const updateSkillSchema = z.object({
  name: z.string().min(1).max(200).optional(),
  description: z.string().max(2000).nullable().optional(),
  bodyMarkdown: z.string().max(100000).nullable().optional(),
  triggers: z.array(z.string().min(1).max(200)).max(20).optional(),
  enabled: z.boolean().optional(),
});

export type SkillResponse = z.infer<typeof skillResponseSchema>;
export type CreateSkillDto = z.infer<typeof createSkillSchema>;
export type UpdateSkillDto = z.infer<typeof updateSkillSchema>;
